-- Poems batch 139
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e709125b-d11e-479a-83d0-e39025ecc72e','贈法傳','李洪','宋','宋诗','song-poetry','','[]','栴檀林下老支郎，偶汎溪邊般若航。',64,'全唐诗/poet.song.145000.json','["栴檀林下老支郎，偶汎溪邊般若航。", "齋鉢分摶香積飯，午窗對卧凈名牀。", "雲山宴坐千春木，塵境難留三宿桑。", "欲結他年蓮社友，空門氣味覺優長。"]'),
('5eb80250-2612-4a76-ba42-5e159c8c6a87','宿天寧示𢜬老','李洪','宋','宋诗','song-poetry','','[]','又扶殘醉渡溪橋，飲散南園夜寂寥。',64,'全唐诗/poet.song.145000.json','["又扶殘醉渡溪橋，飲散南園夜寂寥。", "炬火照山疑犯斗，松風動地欲平潮。", "觀河自嘆塵容老，就日那能鬢雪消。", "煨芋擁鑪談妙道，階梯佛祖直須超。"]'),
('50748654-0323-48f0-b710-63ca65c7a8ae','和子召見寄','李洪','宋','宋诗','song-poetry','','[]','獨泛滄浪一釣舟，未償尋壑與經邱。',64,'全唐诗/poet.song.145000.json','["獨泛滄浪一釣舟，未償尋壑與經邱。", "霜清叵怯吳江冷，酒賤難從越女留。", "遊鹿臺荒人既往，採香逕遠宿須投。", "客遊空羨齊雲勝，辜負韋黄詩酒州。"]'),
('1e553d79-3f82-4782-a60b-b7c3dcf60046','和尚善韻','李洪','宋','宋诗','song-poetry','','[]','出郭尋幽興自長，叢林梅子未全黄。',64,'全唐诗/poet.song.145000.json','["出郭尋幽興自長，叢林梅子未全黄。", "問禪欲契風幡話，宴坐聊參知見香。", "觸念未通成繫橛，安心無法是還鄉。", "却憐石岊送迎處，潮落潮生有底忙。"]'),
('3dab16e2-537e-4829-8666-7ee88d6d1eb1','再用韻','李洪','宋','宋诗','song-poetry','','[]','風罥遊絲百尺長，蜂房釀蜜露微黄。',64,'全唐诗/poet.song.145000.json','["風罥遊絲百尺長，蜂房釀蜜露微黄。", "翠榕一半委陳葉，紫柰十分留暗香。", "盧橘带酸歸老圃，側生未熟去閩鄉。", "浮雲出岫初無戀，靜看卷舒何太忙。"]'),
('cf2e1271-edae-4794-a2a8-813a573ceb81','和仲信留別韻','李洪','宋','宋诗','song-poetry','','[]','歲首相逢四序遷，風饕雪虐忽凋年。',64,'全唐诗/poet.song.145000.json','["歲首相逢四序遷，風饕雪虐忽凋年。", "少而慕藺心何壯，老矣依劉誰復憐。", "邂逅難陪十日飲，分携却上五湖船。", "雪梅可折還相送，目斷離雲思黯然。"]'),
('e596a6a8-f84f-4659-9c8b-e03991255f1b','送趙德莊右司江東漕二首  其一','李洪','宋','宋诗','song-poetry','','[]','帝胄英英秀本支，名駒千里衆難睎。',64,'全唐诗/poet.song.145000.json','["帝胄英英秀本支，名駒千里衆難睎。", "馳聲小選衣冠地，振職中臺政事機。", "禮樂光華持節寵，綸恩獻納賜環歸。", "朝廷俊傑如公少，準擬重來伴紫微。"]'),
('b84eae64-8dfb-4d8a-b1e8-c2d0bec9e4fc','送趙德莊右司江東漕二首  其二','李洪','宋','宋诗','song-poetry','','[]','宰士雍容望最優，便期簪筆侍凝旒。',64,'全唐诗/poet.song.145000.json','["宰士雍容望最優，便期簪筆侍凝旒。", "暫勞省戶彌綸手，稍緩關中饋餉憂。", "寓直文謨高內閣，褰帷仁政被南州。", "龍蟠虎踞登臨勝，天險防邊得細籌。"]'),
('bc9af5d2-ace4-467a-8a65-5490bd5de2c4','伯封書中敘去歲七夕之樂因寄','李洪','宋','宋诗','song-poetry','','[]','去年此夜對芳樽，今日栖栖歎失羣。',64,'全唐诗/poet.song.145000.json','["去年此夜對芳樽，今日栖栖歎失羣。", "茅屋只餘燈伴我，酒爐應有月尋君。", "愁將從事青州去，風共禪師白足分。", "料想紫梅溪上客，也應回首一看雲。"]'),
('1e76c34d-7389-4f0b-9679-b1bb55d65fed','送仲彌性赴蘄水','李洪','宋','宋诗','song-poetry','','[]','中興岳牧任詞人，分虎初班楚澤春。',64,'全唐诗/poet.song.145000.json','["中興岳牧任詞人，分虎初班楚澤春。", "四紀才名文價重，一麾江海璽書新。", "眷深丹扆虛前席，祖意黄梅試問津。", "報政寧需外庸訖，遄歸清禁掌絲綸。"]'),
('0f901ff4-2e63-4c64-a654-01cba7c41912','午日寓圓果院苦河魚以詩紀節','李洪','宋','宋诗','song-poetry','','[]','老來百事與心違，節物殊非少壯時。',64,'全唐诗/poet.song.145000.json','["老來百事與心違，節物殊非少壯時。", "細葛宮中曾被賜，楊梅粽裏未容窺。", "浪求醫國三年艾，空弔沉湘五色絲。", "蕭寺更同摩詰病，玉堂帖子要新詩。"]'),
('d466588c-a24b-4f4a-b39c-987143df7a6d','送滕彥道赴浙東參議','李洪','宋','宋诗','song-poetry','','[]','輟自鵷行第一流，笑譚幕府卧青油。',64,'全唐诗/poet.song.145000.json','["輟自鵷行第一流，笑譚幕府卧青油。", "蘭亭陳迹猶堪賦，禹穴奇書尚可求。", "丞相開藩多暇日，省郎爲介借前籌。", "獨憐無用溝中斷，深羨千巖萬壑遊。"]'),
('2a7c80c5-83d4-4ef2-a6db-16f11a321bbe','陳丞相誕日  其一','李洪','宋','宋诗','song-poetry','','[]','鳳紀千齡遇聖君，扶持宗社不無人。',64,'全唐诗/poet.song.145000.json','["鳳紀千齡遇聖君，扶持宗社不無人。", "欣聞東魯真儒相，本是中興舊學臣。", "玉燕投懷文冠世，天麟呈瑞壽嘉辰。", "中書更倍汾陽考，宰枋重歸轉大鈞。"]'),
('3814edaf-99c9-439e-8656-f514b4bab2a2','陳丞相誕日  其二','李洪','宋','宋诗','song-poetry','','[]','壺山和氣儷神崧，間世鍾賢應尹躬。',64,'全唐诗/poet.song.145000.json','["壺山和氣儷神崧，間世鍾賢應尹躬。", "小試經綸安鼎鼐，更恢韜畧靖華戎。", "力陳致主千秋鑑，夢協遐年八十公。", "不用安期覓瓜棗，蓬萊清淺照方瞳。"]'),
('f30966f5-9c5f-4455-8b24-e00595738ec4','陳丞相誕日  其三','李洪','宋','宋诗','song-poetry','','[]','蟬冕金貂侍帝廷，格天勳業不譚兵。',64,'全唐诗/poet.song.145000.json','["蟬冕金貂侍帝廷，格天勳業不譚兵。", "曾聞楊綰無榮利，果見周公致太平。", "晝錦歸來安綠野，宣麻重起繫蒼生。", "民歌有衮巖瞻切，要使輿圖復兩京。"]'),
('b6be5b71-9ff0-483d-a5f7-35e4423a9be6','陳丞相誕日  其四','李洪','宋','宋诗','song-poetry','','[]','兩兩台符逼斗魁，就盈彌月早春回。',64,'全唐诗/poet.song.145000.json','["兩兩台符逼斗魁，就盈彌月早春回。", "細斟靜治曹參酒，重放和羹傅說梅。", "山立時行錫難老，鸞停鵠峙喜多才。", "千鍾未足爲公壽，盡挹滄江入壽杯。"]'),
('26d32493-a625-410c-b837-0e813c1be82d','陳丞相誕日  其五','李洪','宋','宋诗','song-poetry','','[]','衮繡于蕃鎮九僊，香凝森戟靄非煙。',64,'全唐诗/poet.song.145000.json','["衮繡于蕃鎮九僊，香凝森戟靄非煙。", "願同吉甫傾申伯，請繼東坡壽樂全。", "銅狄摩挲五百歲，蟠桃花實一千年。", "蚤窺東閣觀奇士，再入陶鎔豈偶然。"]'),
('2194a765-7625-4d88-aca3-f0ca679e0db1','送子南兄參選','李洪','宋','宋诗','song-poetry','','[]','我李柯條世有人，如兄器業自超倫。',64,'全唐诗/poet.song.145000.json','["我李柯條世有人，如兄器業自超倫。", "豈容被褐常懷寶，好上煙霄早致身。", "天氣未佳欲寒食，朝廷有道政青春。", "觀光勿作遲遲去，桂玉何勞嘆楚薪。"]'),
('c286c00c-dda5-4259-b7be-54b528ac5f5d','雨寒','李洪','宋','宋诗','song-poetry','','[]','昏昏海氣助朝寒，風雨蕭蕭盡日間。',64,'全唐诗/poet.song.145000.json','["昏昏海氣助朝寒，風雨蕭蕭盡日間。", "室似陳蕃塵不掃，門如陶令晝常關。", "惟憑茗盌消磨睡，更把詩筒斷送閒。", "悄悄絕無車馬至，方知顔巷似深山。"]'),
('9dfb6866-7fc6-4e1f-8d92-bd339478ae1c','至東林謁回仙人像','李洪','宋','宋诗','song-poetry','','[]','罨畫溪山杳靄中，爲尋遺事訪禪宮。',64,'全唐诗/poet.song.145000.json','["罨畫溪山杳靄中，爲尋遺事訪禪宮。", "回嵓故迹依然在，渭水非熊恍似空。", "綠薜侵衣餘手澤，遺榴輝壁想仙風。", "溪邊東老家何處，尚有孫礽話乃翁。"]'),
('d3e9c914-3f6e-4ee4-8f81-0b333e06591b','次韻曾仲躬初入鴈蕩','李洪','宋','宋诗','song-poetry','','[]','阡陌經行早布春，承明天語耳親聞。',64,'全唐诗/poet.song.145000.json','["阡陌經行早布春，承明天語耳親聞。", "詩情本自凌康樂，墨妙何勞法右軍。", "雪後西岑山競秀，潮來孤嶼浪中分。", "蘐堂扁榜名仁壽，鴈序娛親羨使君。"]'),
('5ef1e1de-9005-429c-9d74-7cea22271cbf','池水久涸雨後生蓮偶作','李洪','宋','宋诗','song-poetry','','[]','遶郭荷花泛畫船，枯池忽見葉田田。',64,'全唐诗/poet.song.145000.json','["遶郭荷花泛畫船，枯池忽見葉田田。", "艱生頗似石間柏，罕喻真成陸地蓮。", "要看露香明菡萏，不辭汲水弄漪漣。", "况逢小雨臨清曉，已見瓊珠碎又圓。"]'),
('ffbc92af-8980-457b-88ed-d7eca5118737','次韻林子長巖桂','李洪','宋','宋诗','song-poetry','','[]','凉入千巖趣更幽，廣寒月府恍神遊。',64,'全唐诗/poet.song.145000.json','["凉入千巖趣更幽，廣寒月府恍神遊。", "斷崖流水韻清古，冷雨凄風聲凜秋。", "要補離騷衙宋玉，豈期仙袂挹浮邱。", "却思勝集湖邊寺，搴取芳枝鎮日留。"]'),
('f31dc4ec-8af1-4ae7-a4d6-559717c375f0','賦丞廳連理木','李洪','宋','宋诗','song-poetry','','[]','老槐鉅竹儼牆陰，斯立詩情冠古今。',64,'全唐诗/poet.song.145000.json','["老槐鉅竹儼牆陰，斯立詩情冠古今。", "連理並柯真創見，澡身浴德信同心。", "蟬吟永夜傳清韻，鶴唳中宵和好音。", "不日除書下丹禁，瑞圖頻展錦窠深。"]'),
('d8cb4eed-5286-4b5f-b202-909d57a39714','赤目','李洪','宋','宋诗','song-poetry','','[]','元晏先生病久妨，經旬未省下禪床。',64,'全唐诗/poet.song.145000.json','["元晏先生病久妨，經旬未省下禪床。", "瞿曇善說空華喻，張湛新傳損讀方。", "對客不須分眼白，愛官寧復羨腰黄。", "會逢妙解金篦術，漸恐封疆限醉鄉。"]'),
('f8617968-1aa4-4337-8780-1443fa1d745c','再賦簡李尉','李洪','宋','宋诗','song-poetry','','[]','滿院秋英獨傲霜，恨無醇酒變春江。',64,'全唐诗/poet.song.145000.json','["滿院秋英獨傲霜，恨無醇酒變春江。", "門前催取麻姑榼，席上驚傾道士缸。", "學蹈丘軻難合俗，詩如曹鄶不成邦。", "埋藏自比豐城劒，射斗難占紫氣雙。"]'),
('2cc01ee4-436b-4642-96ba-8d4a1e373633','子都兄寄子濟兄詩借韻奉寄','李洪','宋','宋诗','song-poetry','','[]','緘題千里候寒暄，悵恨郊荆獨我班。',64,'全唐诗/poet.song.145000.json','["緘題千里候寒暄，悵恨郊荆獨我班。", "目斷檣烏五兩遠，書憑河鯉一雙還。", "金陵風月供吟嘯，鍾阜煙蘿想縱攀。", "盡把錦囊新詠句，小胥抄寄勿令慳。"]'),
('30ae4a02-c51b-48bb-8061-7e47160c67fc','子都錄示近作成白體一首奉寄','李洪','宋','宋诗','song-poetry','','[]','別日江梅半透春，梨花開後獨愁人。',64,'全唐诗/poet.song.145000.json','["別日江梅半透春，梨花開後獨愁人。", "欲將芳草萋萋恨，寄向滄江六六鱗。", "兩處吟當看雪夜，數篇抄值落花晨。", "未輸謝客池塘夢，千里賡酬句要新。"]'),
('6abe06b9-bf33-4329-8963-047256e203f3','寄沈時仲  其一','李洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','故人爲別又經年，幾度臨風思黯然。',64,'全唐诗/poet.song.145000.json','["故人爲別又經年，幾度臨風思黯然。", "赤縣暫陪珠履客，青衫空負小山篇。", "壯時之武無能用，老矣揚雄只守玄。", "何日西湖追舊約，淡煙踈雨泛湖船。"]'),
('fd8b49d0-d22f-43b2-a8b0-1e93af00fee6','寄沈時仲  其二','李洪','宋','宋诗','song-poetry','','[]','論交肺腑獨深知，手札勤渠慰我思。',64,'全唐诗/poet.song.145000.json','["論交肺腑獨深知，手札勤渠慰我思。", "郭泰墊巾頻念舊，休文減带最能詩。", "常懷勝集無三友，坐想高談彼一時。", "明月扁舟過苕霅，蘋汀重理釣魚絲。"]'),
('7d163387-f7e8-4590-b995-87dfd2eb8018','次韻子詠弟見寄','李洪','宋','宋诗','song-poetry','','[]','春殘逆旅賦歸歟，桂玉囊空欲趁虛。',64,'全唐诗/poet.song.145000.json','["春殘逆旅賦歸歟，桂玉囊空欲趁虛。", "懶效梁鴻五噫曲，未逢黄石一編書。", "刺漫屢簉門行馬，志拙寧堪鼎拄車。", "數𤱔荒田臨霅水，好披龍具去携鋤。"]'),
('1fd9fe20-34e0-46a0-8e52-d654a7686290','次韻陸元量見寄','李洪','宋','宋诗','song-poetry','','[]','醉別壺中太乙天，寥寥雲海已經年。',64,'全唐诗/poet.song.145000.json','["醉別壺中太乙天，寥寥雲海已經年。", "倦游復索長安米，壯志寧求負郭田。", "一歲九遷看布武，千巖萬壑莫留連。", "同時僚舊重相遇，幸有蓬瀛列二僊。"]'),
('c93085e5-5169-4284-886e-62cf4525f3ba','奉寄子濟兄','李洪','宋','宋诗','song-poetry','','[]','一紙平安附驛筒，打門三印啟斜封。',64,'全唐诗/poet.song.145000.json','["一紙平安附驛筒，打門三印啟斜封。", "讒言勿辯萋兮菲，舊隠猶存菊與松。", "豈有文章傳李漢，當今人物少南容。", "扁舟遠踐龍池約，共聽潺湲遶碧峯。"]'),
('4d1febf4-5763-45ac-86d2-477a1e63aa05','次韻子都兄見寄  其一','李洪','宋','宋诗','song-poetry','','[]','栖栖異縣歎飄蓬，暫釋牢愁頌酒功。',64,'全唐诗/poet.song.145000.json','["栖栖異縣歎飄蓬，暫釋牢愁頌酒功。", "失馬忽悲居塞上，卧龍有待起隆中。", "匪躬直道寧憂辱，巧舌如簧固易窮。", "况有知音居鼎鉉，豈隨笠澤著書叢。"]'),
('6b2f8b08-d28e-498c-8ed3-d669481b3cc7','次韻子都兄見寄  其二','李洪','宋','宋诗','song-poetry','','[]','五色徒誇補衮工，百年癡作蠹書蟲。',64,'全唐诗/poet.song.145000.json','["五色徒誇補衮工，百年癡作蠹書蟲。", "塵纓黧貌慙衰相，窾木號風逼歲窮。", "酌酒漫爲蛇畫足，覆蕉今悟鹿成空。", "江村且索梅花笑，獨有幽人影伴紅。"]'),
('7c3bae7b-939f-44d5-8102-4365f9980a74','冬至前','李洪','宋','宋诗','song-poetry','','[]','隠居慵出人嫌癖，樂靜安閒祇自憐。',64,'全唐诗/poet.song.145000.json','["隠居慵出人嫌癖，樂靜安閒祇自憐。", "窗眼白駒催短晷，案頭黄卷遣長年。", "南枝春信應先透，北陸寒凝勢更堅。", "地下一陽何日復，千林枯木已欣然。"]'),
('bb76353e-e0bc-4e01-90ce-bcde51c81b37','至後二日至東禪','李洪','宋','宋诗','song-poetry','','[]','至後陽和已發生，野梅官柳動詩情。',64,'全唐诗/poet.song.145000.json','["至後陽和已發生，野梅官柳動詩情。", "偶爲尋壑經邱計，故作穿雲渡水行。", "近郭好山皆可隠，隔林踈磬有餘清。", "他時粗免微官縛，歸去深謀谷口耕。"]'),
('f4df4bab-9de1-4eea-a390-21670c75a133','醫僧慧昌小軒','李洪','宋','宋诗','song-poetry','','[]','小池綠浄數游魚，高柳蟬嘶暑氣虛。',64,'全唐诗/poet.song.145000.json','["小池綠浄數游魚，高柳蟬嘶暑氣虛。", "露臉清真雙菡萏，風標閒雅一舂鋤。", "囊中時曬君臣藥，肘後新抄和扁書。", "只此便爲安穩處，何須林下與山居。"]'),
('253d3b95-b923-4cfe-9f1a-7bbb8176c070','余寓王園適當春殘尚有小桃臨水追想昔時繁麗無復存者借仲信桃花韻','李洪','宋','宋诗','song-poetry','','[]','兔葵摇曳雨濛濛，尚有夭桃出舊叢。',64,'全唐诗/poet.song.145000.json','["兔葵摇曳雨濛濛，尚有夭桃出舊叢。", "輕簿不禁三月浪，飄零常恨五更風。", "燕泥亂啄粘香蕊，漁艇猶疑趁落紅。", "惆悵眼前興廢事，靈雲今已悟真空。"]'),
('baaa81b1-8569-44f1-9296-002dbc9bd419','送客乘騾足跛口占示同行','李洪','宋','宋诗','song-poetry','','[]','欲趁江頭送客風，蹇騾難强逐驕驄。',64,'全唐诗/poet.song.145000.json','["欲趁江頭送客風，蹇騾難强逐驕驄。", "漫誇歷塊過燕市，自笑乘船似越儂。", "從此上車慙著作，肯令折臂老新豐。", "釣車魚具平生樂，得失真宜付塞翁。"]'),
('17ea740c-bbb0-40ab-a14a-c26fc9085303','子清弟冒暑見過','李洪','宋','宋诗','song-poetry','','[]','瓢飲今希陋巷顔，忽聞佳客款柴關。',64,'全唐诗/poet.song.145000.json','["瓢飲今希陋巷顔，忽聞佳客款柴關。", "風生荷芰青蘋末，詩寄煙波疊翠間。", "伏櫪常懷千里志，在原相望幾人閒。", "新篘紅友明朝熟，肯放扁舟取次還。"]'),
('f5b9fdba-3682-4b4c-839f-d12250dbe517','劉子履見懷小橋竹籬屢入夢寐因寄','李洪','宋','宋诗','song-poetry','','[]','寂寞荒郊野水濱，竹籬茅舍舊比鄰。',65,'全唐诗/poet.song.145000.json','["寂寞荒郊野水濱，竹籬茅舍舊比鄰。", "誰知綉斧文章伯，尚念漁蓑潦倒人。", "采菊佩萸思共賞，落霞孤鶩興尤新。", "關中小試酇磬侯績，却掌絲綸侍帝宸。"]'),
('0afaa349-b16c-4542-8a7a-30c48142fe2b','九日奉懷子濟兄','李洪','宋','宋诗','song-poetry','','[]','霜天寥落鴈行孤，九日還能行樂無。',64,'全唐诗/poet.song.145000.json','["霜天寥落鴈行孤，九日還能行樂無。", "料想山風吹醉帽，也應溪女解携壺。", "賞心樂事今難偶，弟勸兄酬歎莫俱。", "籬下黄花應笑我，獨哦短韻看茱萸。"]'),
('8bde653c-381d-4151-b205-40d5c1426f6f','寄子都兄兼呈上饒使君趙有翼','李洪','宋','宋诗','song-poetry','','[]','十驛征塗雪塞川，玉溪乍到意醒然。',64,'全唐诗/poet.song.145000.json','["十驛征塗雪塞川，玉溪乍到意醒然。", "家聲盍繼舍人樣，臺治遥分刺史天。", "感慨壯遊詞絢錦，笑談登最地流錢。", "邦侯儻記論交舊，應有新詩寄日邊。"]'),
('85a5f4ae-e553-4b36-a4e0-afc4e05668a0','橘','李洪','宋','宋诗','song-poetry','','[]','皇樹擅芳傳楚頌，厥包錫貢紀荆揚。',64,'全唐诗/poet.song.145000.json','["皇樹擅芳傳楚頌，厥包錫貢紀荆揚。", "踰淮易質從爲枳，書尾重題未降霜。", "四老何須隠商嶺，千奴誰爲種龍陽。", "遥憐陸績懷嘉實，歸奉慈顔滿袖香。"]'),
('0d910fe1-fdd0-436d-8ff9-93b0732857a6','次韻子都兄鮑庵芍藥  其一','李洪','宋','宋诗','song-poetry','','[]','春歸鶑老禁無音，天爲紅芳著意深。',64,'全唐诗/poet.song.145000.json','["春歸鶑老禁無音，天爲紅芳著意深。", "姝色自應傾一國，多情向惜費千金。", "如迎如舞緣風拆，不淡不深愁雨侵。", "宜與花王爲輔佐，欲傳彩筆繼高吟。"]'),
('f1e9a6a9-6bbf-4a53-8eaf-1f163d4e39ad','次韻子都兄鮑庵芍藥  其二','李洪','宋','宋诗','song-poetry','','[]','國香淪落在天涯，常畏人知使護遮。',64,'全唐诗/poet.song.145000.json','["國香淪落在天涯，常畏人知使護遮。", "雅韻曾翻西掖砌，佳名宜亞子亭花。", "野僧好事勤栽植，北客思鄉倍歎嗟。", "安得花前還醉倒，可憐不屬五侯家。"]'),
('c5e78599-7181-4f41-8867-7dc1fa1258cc','中春二十七日車駕躬請太上皇帝出郊獲觀盛事次大監叔韻','李洪','宋','宋诗','song-poetry','','[]','禁籞芳菲歲又新，兩宮行樂及良辰。',64,'全唐诗/poet.song.145000.json','["禁籞芳菲歲又新，兩宮行樂及良辰。", "雙瞻黄繖天回笑，並御花驄雨灑塵。", "漢殿捧巵稱萬壽，葛天張樂和千人。", "歡聲試採康衢詠，帝力熙熙物自春。"]'),
('cde19656-ef7a-4b1f-b698-a3ad83387412','擬和御製郊祀詩  其一','李洪','宋','宋诗','song-poetry','','[]','郊禋饗帝就圜丘，誠格蒼穹靈既留。',64,'全唐诗/poet.song.145000.json','["郊禋饗帝就圜丘，誠格蒼穹靈既留。", "夜陟紫壇飈馭下，天臨黄道矞雲浮。", "槐林雙闕恩方渙，禾黍三登歲有秋。", "幸覩賡歌千載遇，慙無銀筆贊洪猷。"]'),
('d7df0c6d-d1c9-482d-b238-fc397f48a98c','擬和御製郊祀詩  其二','李洪','宋','宋诗','song-poetry','','[]','聖代彌文考九丘，寅威郊見故遲留。',64,'全唐诗/poet.song.145000.json','["聖代彌文考九丘，寅威郊見故遲留。", "黄琮蒼玉神娭燕，月璧星珠瑞應浮。", "禮洽漢山呼萬歲，事殊唐鑑獻千秋。", "侍臣誰薦揚雄賦，豈使甘泉播令猷。"]'),
('393bad99-cfc5-47df-938a-66700b52dd56','六龍駐蹕溫州先公職列西掖扈從至此手澤具載一時之事三十三年嗣子洪守官於此因成感事詩','李洪','宋','宋诗','song-poetry','','[]','從龍浴日仰光輝，萬里鯨濤扈六飛。',64,'全唐诗/poet.song.145000.json','["從龍浴日仰光輝，萬里鯨濤扈六飛。", "晉國曾聞四蛇宇，周家親覩一戎衣。", "東巡王氣隨天仗，西狩麟經在紫微。", "江海孤臣孝忠志，大恩未報重歔欷。"]'),
('a0d86b4a-c262-4e8a-9613-3798b6759fc6','雨中過幽居寺','李洪','宋','宋诗','song-poetry','','[]','柳眼青葱桃萼紅，東皇試手放春功。',64,'全唐诗/poet.song.145000.json','["柳眼青葱桃萼紅，東皇試手放春功。", "峰巒矗矗孤雲聳，澗壑涓涓細水通。", "出谷抗塵身已去，登高能賦思無窮。", "驅車更過幽居寺，暫聽猿吟杳靄中。"]'),
('c2562782-2294-4280-9abe-e8890efda7ca','次韻施少路春日','李洪','宋','宋诗','song-poetry','','[]','拂面和風喜及辰，宮幡未賜岸烏巾。',64,'全唐诗/poet.song.145000.json','["拂面和風喜及辰，宮幡未賜岸烏巾。", "冰消水濼簫韶韻，雪過湖漘茝若春。", "詩律自憐心尚在，宦情難與世趨新。", "從茲排比尋芳計，况是湖山舊主人。"]'),
('aad84898-9db5-455a-a976-a7ce77b49e43','萬壽觀重萼梅','李洪','宋','宋诗','song-poetry','','[]','天街倦踏軟紅塵，喜見宮梅漏泄春。',64,'全唐诗/poet.song.145000.json','["天街倦踏軟紅塵，喜見宮梅漏泄春。", "千葉剪瓊多態度，九英照日倍精神。", "香清暗馥維摩榻，韻勝全疑姑射人。", "好是孤山臨水看，廣平能與賦清新。"]'),
('cc812a0a-16a4-47bb-8541-70c3268a7d02','會稽偶作二首  其一','李洪','宋','宋诗','song-poetry','','[]','去年行遍浙東山，越絕重來豈偶然。',64,'全唐诗/poet.song.145000.json','["去年行遍浙東山，越絕重來豈偶然。", "秦望雲深縈客恨，鏡湖月白結詩緣。", "鷓鴣處處啼篁竹，舴艋家家泛釣船。", "行役自應多感慨，故山如許好風煙。"]'),
('d3a05516-f71b-4508-a8bc-182578464e47','會稽偶作二首  其二','李洪','宋','宋诗','song-poetry','','[]','西陵渡口望吳山，獨策羸驂興惘然。',64,'全唐诗/poet.song.145000.json','["西陵渡口望吳山，獨策羸驂興惘然。", "竹樹幽深皆可老，江山信美祇隨緣。", "知章得請千秋觀，太白狂歌一酒船。", "更擬遲留探禹穴，梅梁風雨暗雲煙。"]'),
('bb92ef6e-bdf0-4fd5-b845-ef4a69a42d4d','垂虹亭','李洪','宋','宋诗','song-poetry','','[]','十年滄海慣騎𬳮，秋入垂虹豁眼明。',64,'全唐诗/poet.song.145000.json','["十年滄海慣騎𬳮，秋入垂虹豁眼明。", "雲氣蓬萊底難到，洞天林屋沒多程。", "漁歌三唱客愁破，鴈字一行秋影橫。", "他日若能追魯望，釣車魚具送餘生。"]'),
('9d9cadea-aac6-451d-a665-d989143dabd2','贈李守','李洪','宋','宋诗','song-poetry','','[]','宗衮英名壓搢紳，傳家濟美不無人。',64,'全唐诗/poet.song.145000.json','["宗衮英名壓搢紳，傳家濟美不無人。", "採詩于蒍承親擢，樂職中和著牧民。", "鳳入潁川宜卜相，梅開東閣趁班春。", "九重側席求奇士，尺一行頒覲紫宸。"]'),
('b9b32f46-62a8-4230-a8ac-8cf321e6a900','朱叔賜來自都城云梅已放因思每歲飲賞之樂','李洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曾酌孤山園裏梅，至今魂夢憶花開。',64,'全唐诗/poet.song.145000.json','["曾酌孤山園裏梅，至今魂夢憶花開。", "纖腰冷逼江煙瘦，素臉全疑曉雪催。", "南國相逢心恅愺，西湖遥想月徘徊。", "惜無妙語酬佳麗，頼有詩仙鳳闕來。"]'),
('540ee9de-dd18-4fa3-b2ee-d98f64510a94','尚善喜雨用元夕韻','李洪','宋','宋诗','song-poetry','','[]','軟紅塵土沒東華，未若爲農樂叵涯。',64,'全唐诗/poet.song.145000.json','["軟紅塵土沒東華，未若爲農樂叵涯。", "耕隴一犁欣已足，生春六夜喜非賒。", "頓回繭館柔桑綠，漸落峒山細麥花。", "惟覺空階聽更爽，齋居無睡轉河車。"]'),
('4669203d-d2e5-4fcd-99e3-d238de62aa55','喜雨用知宗韻呈陳丞相','李洪','宋','宋诗','song-poetry','','[]','旱意初憂病圃場，霈然甘澤起羸尪。',64,'全唐诗/poet.song.145000.json','["旱意初憂病圃場，霈然甘澤起羸尪。", "穹蒼既格由孚信，德教從來本抑强。", "再熟言觀競藨衮，千倉行見詠豐穰。", "帝虛左揆思良弼，霖雨重期澤萬方。"]'),
('6372cc9c-6f85-43b2-98f4-ffd96f356212','至日宿藍田驛感舊','李洪','宋','宋诗','song-poetry','','[]','至日天涯感慨同，曾陪鴛鷺大明宮。',64,'全唐诗/poet.song.145000.json','["至日天涯感慨同，曾陪鴛鷺大明宮。", "催班別殿春雷繞，駐輦蓬萊曉日紅。", "聳聽鳴鞘馳魏闕，歡傳放仗醉新豐。", "誰知獨木荒村裏，扇影爐煙入夢中。"]'),
('8969e8fb-eccf-421d-b50c-0af8229cd89c','奉簡潘師原澄江使君','李洪','宋','宋诗','song-poetry','','[]','話別都門歲再除，歸田猶復带經鋤。',64,'全唐诗/poet.song.145000.json','["話別都門歲再除，歸田猶復带經鋤。", "春朝結佩同迎駕，夜雪寒窗並直廬。", "東閣何堪薛宣吏，長安久絕子公書。", "故人江上新開府，一笑樽前氣少舒。"]'),
('cde1e466-9aeb-4fb0-af1a-ab8387841ad5','和王侍郎中春即事','李洪','宋','宋诗','song-poetry','','[]','溪頭飛絮白氈鋪，五馬班春計不踈。',64,'全唐诗/poet.song.145000.json','["溪頭飛絮白氈鋪，五馬班春計不踈。", "泛宅浮家行樂勝，浪花雲葉賦詩餘。", "競傳畫戟凝香什，莫望高軒織翠裾。", "碧落承明公厭直，水晶宮闕更誰如。"]'),
('5c0e4fbb-2948-4fc6-8ca5-bb18aed2e78f','清明自釋','李洪','宋','宋诗','song-poetry','','[]','異鄉節物又清明，懶復追遊年少行。',64,'全唐诗/poet.song.145000.json','["異鄉節物又清明，懶復追遊年少行。", "愁慘松楸十年淚，雨昏花絮數聲鶑。", "高紅遠綠俱無那，客恨春風兩不平。", "强課新詩作寒食，不堪重憶故園餳。"]'),
('5c3c3d96-8695-4244-87e8-abb9b724e327','望孤嶼','李洪','宋','宋诗','song-poetry','','[]','縹緲風煙島嶼孤，朱樓丹閣欲凌虛。',64,'全唐诗/poet.song.145000.json','["縹緲風煙島嶼孤，朱樓丹閣欲凌虛。", "浩然逸興成陳迹，康樂清吟足起予。", "鰲頂蓬萊無鴈塔，龍宮蠖濩擁宸居。", "平生李杜空遐想，我欲投竿學釣魚。"]'),
('33706efc-3c2c-41f3-ad2c-703281a33523','漫成','李洪','宋','宋诗','song-poetry','','[]','能安寂寞興何長，自覺無機稱坐忘。',64,'全唐诗/poet.song.145000.json','["能安寂寞興何長，自覺無機稱坐忘。", "一溉成功心尚在，五禽爲戲學無方。", "病來乍怯衣裳裌，秋至新嘗橘柚香。", "欲識道人真靜處，南華一卷是醫王。"]'),
