('a1fba554-4959-4fac-8340-9516569ff8d0','題華亭尉廳梅館  其二','李洪','宋','宋诗','song-poetry','','[]','掃徑開窗事事新，主人解組似行人。',32,'全唐诗/poet.song.145000.json','["掃徑開窗事事新，主人解組似行人。", "浮香弄影無因得，試促花神作小春。"]'),
('667384b0-2eed-41d8-8874-d02e48ebc66c','送范至能帥桂林','李洪','宋','宋诗','song-poetry','','[]','口伐奇謀讋可汗，歸來猶著侍臣冠。',64,'全唐诗/poet.song.145000.json','["口伐奇謀讋可汗，歸來猶著侍臣冠。", "燧林草色供詩思，鳳沼春波灧筆端。", "誰謂玉堂真學士，暫臨桂管小長安。", "元戎十乘無遄邁，上閣宣麻句已團。"]'),
('2b7d9e4d-0293-4434-8557-04ca4ff43fb9','送史志道帥建康','李洪','宋','宋诗','song-poetry','','[]','簪橐明光備武文，玉麟暫剖別堯雲。',64,'全唐诗/poet.song.145000.json','["簪橐明光備武文，玉麟暫剖別堯雲。", "朝中禮樂謀元帥，天下英雄有使君。", "陋矣齊丘當十萬，鄙哉諸葛眎三分。", "公歸豈作東征遠，彝鼎將書第一勳。"]'),
('e9c2fb6a-1697-486c-916d-70b24d4ab2c1','題甘將軍廟卷雪樓','李泳','宋','宋诗','song-poetry','','[]','卷雪樓前萬里江，亂峰卓列森旗槍。',64,'全唐诗/poet.song.145000.json','["卷雪樓前萬里江，亂峰卓列森旗槍。", "上有甘公古祠宇，節制洪流掌風雨。", "甘公一去踰千年，至今忠義猶凜然。", "我來再拜攬塵跡，斜陽白鳥橫蒼烟。"]'),
('9a8d5a8c-c0ba-4095-ad60-af78b671e0d5','新昌逢故人','李泳','宋','宋诗','song-poetry','','[]','草縣一相值，忽思傾蓋時。',48,'全唐诗/poet.song.145000.json','["草縣一相值，忽思傾蓋時。", "年來無限事，別後幾篇詩。", "石亂水流急，竹深煙散遲。", "兵戈方滿眼，我輩欲何之。"]'),
('ade74d8a-2a21-4491-b8a5-887556aafa40','西興','李泳','宋','宋诗','song-poetry','','[]','山擁千家邑，江涵萬頃天。',48,'全唐诗/poet.song.145000.json','["山擁千家邑，江涵萬頃天。", "洪濤舂落日，老樹秣荒煙。", "失路或搔首，夷途爭著鞭。", "勞生幾寒暑，半鬢已蒼然。"]'),
('2e9ade22-00d6-4802-b3d5-867b1fcaf173','華髮','李泳','宋','宋诗','song-poetry','','[]','華髮中年感，青陽萬物和。',48,'全唐诗/poet.song.145000.json','["華髮中年感，青陽萬物和。", "倦尋先友記，貧羨力田科。", "江遠千帆落，天空一雁過。", "還家得新歲，童稚想婆娑。"]'),
('10c4f238-fefa-4f69-8f97-2b96d4e7ed72','秋江打魚  其一','李泳','宋','宋诗','song-poetry','','[]','滄洲葉脫風有聲，漁舠兩兩從復橫。',32,'全唐诗/poet.song.145000.json','["滄洲葉脫風有聲，漁舠兩兩從復橫。", "菁江步口日欲沒，竹山潭邊潮欲生。"]'),
('b74b69d9-0120-4629-a757-b786a21ca1a3','秋江打魚  其二','李泳','宋','宋诗','song-poetry','','[]','鳴榔四合波圍蹙，掛網雪鱗穿翠束。',32,'全唐诗/poet.song.145000.json','["鳴榔四合波圍蹙，掛網雪鱗穿翠束。", "驚起沙頭白雁群，斜行書破秋天綠。"]'),
('9be50af6-d360-4790-8a3a-290679c678b4','擬古','李泳','宋','宋诗','song-poetry','','[]','鮮鮮歌者衣，扎扎機中練。',60,'全唐诗/poet.song.145000.json','["鮮鮮歌者衣，扎扎機中練。", "美人富千綺，寒女無一綫。", "古風日以遠，薄俗日以變。", "悲哉扊扅歌，女子羞自衒。", "男兒乖持操，蹙踖歎貧賤。"]'),
('3eac0455-1326-4e08-8df8-8d6ea13ebac0','普照院','李淛','宋','宋诗','song-poetry','','[]','青山繞屋藍光重，流水衝階碧蘚滋。',32,'全唐诗/poet.song.145000.json','["青山繞屋藍光重，流水衝階碧蘚滋。", "獨坐午窗誰晤語，鷓鴣聲裏竹陰移。"]'),
('c0f31931-e933-4984-8d17-317a49540d8b','普熏院','李淛','宋','宋诗','song-poetry','','[]','征鞍曉踏山頭月，客袂晝披松下風。',32,'全唐诗/poet.song.146000.json','["征鞍曉踏山頭月，客袂晝披松下風。", "況有禪堂供偃息，陶然一枕夢槐宮。"]'),
('e729577e-74e2-422f-84f3-7b53ef77520c','答朱元晦','石斗文','宋','宋诗','song-poetry','','[]','病枕經年卧沃洲，滿庭楓葉又吟秋。',64,'全唐诗/poet.song.146000.json','["病枕經年卧沃洲，滿庭楓葉又吟秋。", "書來如見舊人面，讀了還添塵世愁。", "憂國至今遺白髮，窮經空自愧前修。", "武夷休作相思夢，我已甘心老此丘。"]'),
('5eeda726-09ce-4d30-a753-4a63398e0b8a','遊大滌洞天','蓋經','宋','宋诗','song-poetry','','[]','暇日尋幽入洞霄，攀蘿捫石自忘勞。',64,'全唐诗/poet.song.146000.json','["暇日尋幽入洞霄，攀蘿捫石自忘勞。", "地環九鎖仙都閟，山倚一峯天柱高。", "夜靜仙人吹鳳笛，月明帝子下雪旄。", "佩環寂寂中庭曉，時有胎禽唳九皋。"]'),
('b6d7f68f-0749-4f8c-b889-8c940661ef87','句','趙雄','宋','宋诗','song-poetry','','[]','三十六峰如不到，青山還似不曾游。',16,'全唐诗/poet.song.146000.json','["三十六峰如不到，青山還似不曾游。"]'),
('4fcbb84b-163c-448a-956a-919daccb4289','高宗皇帝挽詞五首  其一','陳居仁','宋','宋诗','song-poetry','','[]','力拯艱難運，天開聖哲君。',48,'全唐诗/poet.song.146000.json','["力拯艱難運，天開聖哲君。", "赤符恢世祚，蒼籙炳人文。", "帝學窮淵奧，宸奎照典墳。", "三宗從著號，超軼未前聞。"]'),
('8cfa303d-6688-449e-9892-778cbc019223','高宗皇帝挽詞五首  其二','陳居仁','宋','宋诗','song-poetry','','[]','天步方寧只，民區復晏然。',48,'全唐诗/poet.song.146000.json','["天步方寧只，民區復晏然。", "心非堯位樂，子授舜躬賢。", "揖遜高千古，恬怡盛萬年。", "乘雲歸帝所，溥率淚成川。"]'),
('ecb10d2c-08c9-4d8a-bd5d-cfa140134514','高宗皇帝挽詞五首  其三','陳居仁','宋','宋诗','song-poetry','','[]','聖略如天大，仁心亙古無。',48,'全唐诗/poet.song.146000.json','["聖略如天大，仁心亙古無。", "神兵勝淝水，鳴劍罷伊吾。", "宵旰逾三紀，歌謠遍八區。", "耆龐聽遺誥，號絕更嗟呼。"]'),
('0a518901-6172-4ae1-820c-1ac20f64cb91','高宗皇帝挽詞五首  其四','陳居仁','宋','宋诗','song-poetry','','[]','漢日朝前殿，神堯宴大安。',48,'全唐诗/poet.song.146000.json','["漢日朝前殿，神堯宴大安。", "徒誇一時盛，誰似兩宮歡。", "謾採瀛洲藥，猶除荆鼎丹。", "傷心浙江畔，縞仗自回鑾。"]'),
('8e6dd00c-58aa-49d7-aa1f-2f0411eff802','高宗皇帝挽詞五首  其五','陳居仁','宋','宋诗','song-poetry','','[]','得壽尊慈扆，怡神久北宮。',48,'全唐诗/poet.song.146000.json','["得壽尊慈扆，怡神久北宮。", "綵衣頻侍燕，寶冊屢垂鴻。", "劍落橋山外，陵開禹穴東。", "從今壽文母，無復玉巵同。"]'),
('68bbbfe1-36dd-42b6-93b2-ddcfbafd28fc','西湖感舊','陳居仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','蘇公堤畔采蓮船，蘸碧樓臺動管弦。',32,'全唐诗/poet.song.146000.json','["蘇公堤畔采蓮船，蘸碧樓臺動管弦。", "山色湖光宛如昔，心情不似十年前。"]'),
('0f643221-6975-4906-8f5c-ec14f4845f3d','登龐公讀書堂','陳居仁','宋','宋诗','song-poetry','','[]','相君事業慕臯夔，被遇王家泰定時。',64,'全唐诗/poet.song.146000.json','["相君事業慕臯夔，被遇王家泰定時。", "曾向雲窗研漢簡，故應畫棟産靈芝。", "文鑱金石流芳在，像託丹青亙世垂。", "盛烈豐功難具述，爛然國史著猷爲。"]'),
('addab567-cfcb-425b-b35a-0b15640e4465','偶作','陳居仁','宋','宋诗','song-poetry','','[]','疏樹梢頭露曉星，薄寒侵榻睡初醒。',32,'全唐诗/poet.song.146000.json','["疏樹梢頭露曉星，薄寒侵榻睡初醒。", "沙鷗何處驚飛起，點破遥山一抹青。"]'),
('e44ac2a0-96c5-4de9-8871-b264a076c5ce','竹村居','陳居仁','宋','宋诗','song-poetry','','[]','霜筠萬箇繞龍孫，中有茅簷據小村。',32,'全唐诗/poet.song.146000.json','["霜筠萬箇繞龍孫，中有茅簷據小村。", "疏處只容猿鶴過，喜無俗客敢登門。"]'),
('cc0c24de-4770-4888-a772-6390d323110a','高宗皇帝挽詞  其一','留正','宋','宋诗','song-poetry','','[]','內禪堯咨舜，中興夏配天。',48,'全唐诗/poet.song.146000.json','["內禪堯咨舜，中興夏配天。", "鴻名光寶冊，奎畫動星躔。", "靜享仁人壽，書傳聖政編。", "永言天下養，胡不萬斯年。"]'),
('4e17bdbf-349a-4dea-b23c-518a7c1765e1','高宗皇帝挽詞  其二','留正','宋','宋诗','song-poetry','','[]','南北休兵久，仁恩及物深。',48,'全唐诗/poet.song.146000.json','["南北休兵久，仁恩及物深。", "九齡終帝夢，四海遏韶音。", "聖學高於古，衰衣始自今。", "一抔陵上土，他日卜嵩岑。"]'),
('52c4bb78-5090-4226-af43-eebeadc61e4d','羅浮天漢橋','留正','宋','宋诗','song-poetry','','[]','霏霏細雨濕芝田，短短桃花照水妍。',32,'全唐诗/poet.song.146000.json','["霏霏細雨濕芝田，短短桃花照水妍。", "可惜洞門關不盡，彩虹天外著飛泉。"]'),
('94be6eb7-4db6-4086-8231-0459646c6853','震山巖','曹訓','宋','宋诗','song-poetry','','[]','巖靜塵埃了不侵，公閑出郭喜登臨。',64,'全唐诗/poet.song.146000.json','["巖靜塵埃了不侵，公閑出郭喜登臨。", "雲山兀兀自朝暮，江水茫茫無古今。", "鷗鷺翩翩明遠目，漁樵歌唱動歸心。", "綠楊紅杏春風裏，誰與幽人共賞音。"]'),
('9c8f28de-2130-4fe4-bf2f-14d83831882b','送舉人','常禕','宋','宋诗','song-poetry','','[]','革去頹風靳選掄，翕然公論一時伸。',64,'全唐诗/poet.song.146000.json','["革去頹風靳選掄，翕然公論一時伸。", "棘圍共試三千士，海郡聯飛二十人。", "競說馬群空冀野，好看鯤化上雲津。", "從來自有湖平讖，由此公卿穩致身。"]'),
('504d6152-53ad-4cd0-909d-c15256c2f132','送舉人','曾汪','宋','宋诗','song-poetry','','[]','樂作疑遊太古庭，韓門今喜見諸生。',64,'全唐诗/poet.song.146000.json','["樂作疑遊太古庭，韓門今喜見諸生。", "千間厦敞攄雄思，萬里橋成助去程。", "玉醑杯深鄉意重，銀蟾宮近客身輕。", "前賢已有驚人舉，更聽臚傳第一聲。"]'),
('3d39dbdb-6925-402e-b403-930b54b82c97','宮亭廟','劉剛','宋','宋诗','song-poetry','','[]','回艫乘派水，舉棹逐分風。',60,'全唐诗/poet.song.146000.json','["回艫乘派水，舉棹逐分風。", "滉漾疑無際，飄揚似渡空。", "檣烏排鳥路，船影沒河宮。", "孤石滄浪裏，岸山古霧中。", "寄言千金子，安知萬里蓬。"]'),
('d25164a6-fa57-4c75-a662-9714d1ad3220','和劉右司淳于送牡丹病中賦','呂行中','宋','宋诗','song-poetry','','[]','天姿國艷燦芳柯，相亞紅黄詫綺羅。',64,'全唐诗/poet.song.146000.json','["天姿國艷燦芳柯，相亞紅黄詫綺羅。", "高擬營邱名冠絕，未饒伊洛品繁多。", "敢邀使座開青眼，爲歎英華墜綠莎。", "亭館主人芹意重，數枝折貢慶清和。"]'),
('12c87eda-a52d-4380-811c-95e17391990b','早秋遊靈巖','聞人滋','宋','宋诗','song-poetry','','[]','凭欄山翠濕濛濛，佛閣依然水殿風。',32,'全唐诗/poet.song.146000.json','["凭欄山翠濕濛濛，佛閣依然水殿風。", "欲採蓮花何處所，年年金井落梧桐。"]'),
('403574f9-5278-4b67-abbd-0706c8f93715','雲安監勸學詩','王日翬','宋','宋诗','song-poetry','','[]','雲安古湯谿，□□□□濱。',288,'全唐诗/poet.song.146000.json','["雲安古湯谿，□□□□濱。", "無室不鹽煙，無民不樵薪。", "士子獨希少，錐刀事艱辛。", "我因沿檄來，暇日聊咨詢。", "谿山秀且清，湛碧高嶙峋。", "衣冠杳不報，敢問夫何因。", "盛言漢廷尉，有語詒鄉鄰。", "三牛對馬嶺，有井無貴人。", "斯言既篤信，詩禮不復聞。", "我聞爲咨嗟，此語深非仁。", "儒風一旦掃，有甚遭燒焚。", "因言廷尉者，其生豈不神。", "既稟神靈姿，甯非賢聖倫。", "安得鄙俚語，千載愚斯民。", "斯民有幸氏，貴豈無足尊。", "唐皇上柱國，僞蜀掌絲綸。", "遺誥尚可考，苗裔亦詵詵。", "後生宜可畏，況逢堯舜辰。", "如何三百年，自棄甘煨塵。", "前賢不知慕，俚語常書紳。", "不知非格言，野老相因循。", "爲言聽我語，蜀氏初頑囂。", "文翁爲益州，化蜀與維新。", "英才出王馬，繼世揚子雲。"]'),
('ebc20e82-d47b-4c87-8139-a1f4900034e8','句','張湜','宋','宋诗','song-poetry','','[]','吳山空對越山明。',8,'全唐诗/poet.song.146000.json','["吳山空對越山明。"]'),
('8a28b91d-8342-44fc-9666-448889a87f6c','送張達道還山','趙璩','宋','宋诗','song-poetry','','[]','賸借紅塵一日閒，有勞妙語徹幽關。',64,'全唐诗/poet.song.146000.json','["賸借紅塵一日閒，有勞妙語徹幽關。", "豈知隠几如南郭，也愧移文向北山。", "有意清風憐我住，無心孤月伴君還。", "三茅若問今消息，爲報逍遥天地間。"]'),
('ea688d92-1680-4c87-9413-3d03f832536c','自新昌入天台','鄭伯英','宋','宋诗','song-poetry','','[]','升高無過胡孫擂，行險勝於老鼠梯。',32,'全唐诗/poet.song.146000.json','["升高無過胡孫擂，行險勝於老鼠梯。", "何事將身來試此，要參大士石橋西。"]'),
('1927d65c-6aee-4ba9-ab81-13445e7daab0','石橋煎茶','鄭伯英','宋','宋诗','song-poetry','','[]','白髮青衫故倦遊，何人能辦釣鼇鈎。',32,'全唐诗/poet.song.146000.json','["白髮青衫故倦遊，何人能辦釣鼇鈎。", "却逢大士開青眼，現出茶花五百甌。"]'),
('d8481fc2-7c84-4778-a5c2-7ef963c25ffd','放龜','鄭伯英','宋','宋诗','song-poetry','','[]','城中有四靈，麟鳳神龍龜。',168,'全唐诗/poet.song.146000.json','["城中有四靈，麟鳳神龍龜。", "鳳翔兮千仞，麟兮不可羈。", "天用莫如龍，在在風雲隨。", "拙哉老督郵，何時列於斯。", "浪言蓮上巢，甘作牀下支。", "牀支木爲辱，刳剔良可悲。", "陂塘溢春水，爬沙闖晴曦。", "漁師捨網罟，掇取如拾遺。", "解甲伏碪砆，哀鳴極嗚咿。", "卜師更安忍，鑽灼無完肌。", "有身不自靈，昔聞今見之。", "百金出敝楮，駢首還清漪。", "千歲善保汝，左顧非我期。", "願言貽日者，吉凶訪藂蓍。"]'),
('4b121121-3985-4b8c-a95f-6c052bcbb829','和清卿雪溪泛舟晚登華蓋亭','鄭伯英','宋','宋诗','song-poetry','','[]','滿江風雨釀清愁，坐嘯烟波一葉舟。',64,'全唐诗/poet.song.146000.json','["滿江風雨釀清愁，坐嘯烟波一葉舟。", "目送飛花千里去，身隨空碧一鷗浮。", "兜羅世界成游戲，欵乃聲中自唱酬。", "試問剡溪回棹客，可能乘興上南樓。"]'),
('6055d7f6-8e11-4a39-b9c7-295b497409ba','清明泛舟','鄭伯英','宋','宋诗','song-poetry','','[]','風雨連朝忽轉晴，天還著意作清明。',64,'全唐诗/poet.song.146000.json','["風雨連朝忽轉晴，天還著意作清明。", "簿書共了公家事，尊酒聊酬我輩情。", "花却餘寒紅尚瘦，柳融初日黛猶輕。", "一年春事纔如許，又作明朝祓禊行。"]'),
('125b393b-6a1c-4d86-a361-ad8d4e352d6f','江梅水仙同賦','項安世','宋','宋诗','song-poetry','','[]','蕭然兩高人，冠珮何楚楚。',72,'全唐诗/poet.song.146000.json','["蕭然兩高人，冠珮何楚楚。", "齊魯有大臣，可敬不可侮。", "東風吹百花，餘子不足數。", "同爲歲晚游，各不相媚嫵。", "君看冰雪姿，定肯學兒女。", "三肅庵中人，此客難爲主。"]'),
('b647553e-3756-4269-a4e0-17570509952a','次韻謝王𣓨秀才四首  其一','項安世','宋','宋诗','song-poetry','','[]','掩關飽黑甜，屏迹慕烏有。',48,'全唐诗/poet.song.146000.json','["掩關飽黑甜，屏迹慕烏有。", "何心望披拂，注意及衰朽。", "勞君崔魏徒，過我沮溺耦。", "拜手把瓜桃，捫胸愧箕斗。"]'),
('b2dfd3ef-7f4b-400b-a00a-2b3d31c8ed98','次韻謝王𣓨秀才四首  其二','項安世','宋','宋诗','song-poetry','','[]','春來無酒債，客至得詩材。',48,'全唐诗/poet.song.146000.json','["春來無酒債，客至得詩材。", "論文舌本壯，誦句鬚髯開。", "鮮芳曜楛朽，駿步驚駑駘。", "巍巍王謝家，衮衮世有才。"]'),
('88de6df9-5de3-4cfe-8995-3ad6c911ddb1','次韻謝王𣓨秀才四首  其三','項安世','宋','宋诗','song-poetry','','[]','書生無炎凉，市道有贏詘。',48,'全唐诗/poet.song.146000.json','["書生無炎凉，市道有贏詘。", "世方重陶猗，君獨師賈屈。", "反生自求良，背己方成黻。", "樂地名教中，金珠彼何物。"]'),
('ea1cf01e-00d6-43be-99e3-765b3d112819','次韻謝王𣓨秀才四首  其四','項安世','宋','宋诗','song-poetry','','[]','一萬里江天，供君作詩用。',48,'全唐诗/poet.song.146000.json','["一萬里江天，供君作詩用。", "靈均泛沅澧，子美去梁宋。", "兩公取不竭，留與我輩共。", "莫歌白雲詞，便作清廟頌。"]'),
('1c61e95d-bfd7-4b7a-a176-956e213935de','水圖詩壽王丞相','項安世','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','水於天地間，體物而不倚。',288,'全唐诗/poet.song.146000.json','["水於天地間，體物而不倚。", "其數爲天一，衆有之所始。", "其辰爲壬癸，重任之所揆。", "其德爲智端，非非而是是。", "其聲爲羽音，宇覆而物止。", "精爲九霄月，脈爲百川水。", "上爲雲千峯，下爲霧五里。", "春雨散膏腴，秋霜歛華靡。", "露滋夏畦活，雪喚冬麥起。", "五行雖異生，宰割由一軌。", "火蒸妃合巹，金鑄母生子。", "鑿土得亂泉，斲木出脂髓。", "瀑垂石山巔，汞出砂坑裏。", "盛德其神乎，有生皆具此。", "雖然此其源，萬變難比擬。", "盍往觀其流，庶幾有窮已。", "前稽夏書意，後考周雅旨。", "河爲中國經，江作南邦紀。", "濟溢陶邱陰，漢合武昌涘。", "桐柏濬靈源，鳥鼠導幽趾。", "弱水沈一毛，涇泥灌千埤。", "八水壯函秦，三川貫熊耳。", "汾潞表參墟，睢漳雄楚羋。", "洞庭汩南放，彭蠡浩東迤。"]'),
('feded889-c300-4717-93e3-1aaad319f21a','送李季章','項安世','宋','宋诗','song-poetry','','[]','聖靈昔回眷，霑沐仰清徽。',216,'全唐诗/poet.song.146000.json','["聖靈昔回眷，霑沐仰清徽。", "十載朝雲陛，賞心惟良知。", "索居易永久，衰疾忽在斯。", "常恐鷹隼擊，微命察如絲。", "末塗幸休明，成貸遂兼茲。", "且伸獨往意，追尋栖息時。", "心事俱已矣，星星白髮垂。", "惟開蔣生徑，想像崑山姿。", "歡娛寫懷抱，愛客不告疲。", "莫言相遇易，趣途遠有期。", "勿貽白首歎，祇足攪余思。", "伊余秉微尚，不爲歲寒欺。", "拙疾相倚薄，雲歸日西馳。", "養疴邱園中，意愜理無違。", "况值衆君子，文物共葳蕤。", "獻納雲臺表，心胸既云披。", "華屋非蓬居，工拙各有宜。", "明哲持經綸，試用此道推。"]'),
('fef96003-e65c-4aa0-8e5b-b9005a804e7c','得句','項安世','宋','宋诗','song-poetry','','[]','平生爲斯文，思極心欲破。',48,'全唐诗/poet.song.146000.json','["平生爲斯文，思極心欲破。", "得句如得官，歡喜不能奈。", "遶牀行百匝，如覺此身大。", "昔我得官時，悠然但高卧。"]'),
('99a1ccd7-878c-44bf-85f5-e131d106481b','答賀者','項安世','宋','宋诗','song-poetry','','[]','自聞諸賢興，便謂我當出。',120,'全唐诗/poet.song.146000.json','["自聞諸賢興，便謂我當出。", "親朋願其貴，賀者日盈室。", "雖感賀者情，奈此十年疾。", "平生萬事僞，獨有病是實。", "下床足攣圈，出戶膚憯慄。", "空懷魏牟心，未遇盧扁術。", "向來謂求己，那料見今日。", "幸逢世和平，吾願良已畢。", "諸賢致嘉靖，即與我身一。", "政恐我自爲，粗疎更難必。"]'),
('c60084a5-4362-4717-ae4f-ac069819faba','答張以道','項安世','宋','宋诗','song-poetry','','[]','君詩不可狀，似是秋蘭清。',48,'全唐诗/poet.song.146000.json','["君詩不可狀，似是秋蘭清。", "急著無近色，靜嗅有餘馨。", "饑來食杞菊，不願生鵝腥。", "長安三市裏，杳杳一鴻冥。"]'),
('5023d009-ec59-487c-aa90-5726376b5a16','謝查元吉借示傃軒今是齋巢室三書','項安世','宋','宋诗','song-poetry','','[]','堂堂傃軒翁，學古無不探。',264,'全唐诗/poet.song.146000.json','["堂堂傃軒翁，學古無不探。", "詁訓尊六經，文章妙瞿曇。", "大兒號今是，思若春波涵。", "最長作千百，時用經訓參。", "猶子號巢室，清甚寒泉甘。", "尤善賦五七，每于禪悅耽。", "各得一翁體，與翁名字三。", "我生在翁後，鶴化無留驂。", "今是亦已往，龍亡空故潭。", "猶能及巢室，朝暮聞其談。", "結交盡前輩，舊事多所諳。", "五斗驅我行，歸來哭空龕。", "故園但喬木，後生誰指南。", "今年四月尾，暑氣如焚惔。", "慇懃小巢室，浩蕩傾籝甔。", "併持三篋來，爲飽千里婪。", "倒海見珠瑇，連山閲楩楠。", "歛袵不知熱，醉心常自酣。", "門前日熇熇，門內風毿毿。", "清晨送書去，過午忽不堪。", "始悟歲方燠，雩祈遍精藍。", "誰能寫此書，長使雨我菴。"]'),
('bd4e870b-773b-4fe1-b65a-0b29f1b4c7de','輯陶句送胡仲方東歸四首  其一','項安世','宋','宋诗','song-poetry','','[]','凄凄風露交，落葉滿長陌。',60,'全唐诗/poet.song.146000.json','["凄凄風露交，落葉滿長陌。", "荆扉晝常閉，寂寂無行迹。", "東方有一士，素袍深可惜。", "時復墟曲中，載醪祛所惑。", "遥遥至南荆，此士再難得。"]'),
('8509483d-2300-4a7a-a33e-bb608ee8b294','輯陶句送胡仲方東歸四首  其二','項安世','宋','宋诗','song-poetry','','[]','相知何必早，一遇盡慇懃。',60,'全唐诗/poet.song.146000.json','["相知何必早，一遇盡慇懃。", "疑義相與析，立善常所欣。", "野外罕人事，思與爾爲隣。", "如何舍此去，興言在茲春。", "來雁有餘聲，念來存故人。"]'),
('728231a5-3ef5-432e-83eb-74f4ee2811f9','輯陶句送胡仲方東歸四首  其三','項安世','宋','宋诗','song-poetry','','[]','萬族各有託，吾亦愛吾廬。',60,'全唐诗/poet.song.146000.json','["萬族各有託，吾亦愛吾廬。", "誰言客舟遠，歸子念前途。", "晨夕看山川，相將還舊居。", "斗酒聚比隣，再喜見友于。", "念彼窮居士，門庭日荒蕪。"]'),
('e998f138-ec83-41e7-97c0-2cac1ea9c5b8','輯陶句送胡仲方東歸四首  其四','項安世','宋','宋诗','song-poetry','','[]','羈鳥戀舊林，我心固匪石。',60,'全唐诗/poet.song.146000.json','["羈鳥戀舊林，我心固匪石。", "君情定何如，政爾不能得。", "豫章抗高門，義風都未隔。", "及時當勉勵，步步尋往迹。", "見重我軒皇，事事悉如昔。"]'),
('e35f8959-6d6b-4d2a-a43d-53606e52f179','和王少清用昌黎送劉師服韵索近作','項安世','宋','宋诗','song-poetry','','[]','兒時學戇語，筆力思摩秋。',84,'全唐诗/poet.song.146000.json','["兒時學戇語，筆力思摩秋。", "年來頗解事，毀去不復留。", "荷君俎豆我，重意難爲酬。", "不逢吞舟鯨，十犗虛垂鈎。", "徒蒙萬金價，竟以瓦礫售。", "夫君自奇偉，下筆不肯休。", "須我合藥紙，欲兼砂扎收。"]'),
('8a8623d4-36d3-457f-8781-3e0378324fe3','江州陳待制送酒','項安世','宋','宋诗','song-poetry','','[]','誰謂淵明遠，我住栗里源。',48,'全唐诗/poet.song.146000.json','["誰謂淵明遠，我住栗里源。", "亦有好事人，送酒黄花前。", "舉酒對南湖，見之心悠然。", "相逢各無心，後世自稱賢。"]'),
('e24c7652-565a-443a-816b-dd6cbf2e1c60','送葉參議知蘄州','項安世','宋','宋诗','song-poetry','','[]','丈夫睫間珠，肯作兒女滴。',192,'全唐诗/poet.song.146000.json','["丈夫睫間珠，肯作兒女滴。", "曉與秘書辭，愴然欲霑臆。", "我家括山下，土俗號窮僻。", "自我來荆州，邦風更蕭瑟。", "流落三十年，魚蝦共眠食。", "出門無所往，入門長太息。", "自從祕書來，覺我好顔色。", "香霧浹衣巾，春風醉膚革。", "歛我氣馬浮，廣我心地窄。", "年來困侵暴，兩鬢愁欲白。", "家門危破碎，意氣向消釋。", "萬事不稱懷，獨此天下特。", "如何下江船，便掛北風席。", "吹君向南岸，留我著江北。", "向來窮未苦，今日窮始極。", "君行見張薛，爲道此愁寂。"]'),
('f79f19b2-f258-4a5a-bba0-44247ac49852','送范少約二首  其一','項安世','宋','宋诗','song-poetry','','[]','天地爲一家，萬人生其中。',84,'全唐诗/poet.song.146000.json','["天地爲一家，萬人生其中。", "父母甚愛之，産智牧其蒙。", "雖蒙亦吾子，一一關天胸。", "所以聖賢心，相傳極哀恫。", "晝夜當競競，明命敢不龔。", "此意一以忘，萬命爲牢饔。", "誰能指斯路，鄒魯兩衰公。"]'),
('ca4a2cda-2c2c-4879-8b07-321221882531','送范少約二首  其二','項安世','宋','宋诗','song-poetry','','[]','侃侃太史孫，風誼美於玉。',72,'全唐诗/poet.song.146000.json','["侃侃太史孫，風誼美於玉。", "生才天豈虛，此士世所屬。", "秦槌不敢贈，孔道以相告。", "一世須大輿，長途要堅轂。", "神天極虔恭，萬姓吾骨肉。", "念此心迹融，永以天下福。"]'),
('2d94e99c-b7aa-455a-881a-79143a093e45','次韵蕭復秀才','項安世','宋','宋诗','song-poetry','','[]','崇雲護南山，有士在其下。',48,'全唐诗/poet.song.146000.json','["崇雲護南山，有士在其下。", "俗駕日滔滔，誰爲問津者。", "美人兩世舊，獨許半席假。", "詩從墨中來，繁露清可把。"]'),
('b3bd61e1-55fd-45f0-8a43-b72f1fba0dc4','次韵襄陽常縣尉送行','項安世','宋','宋诗','song-poetry','','[]','別酒不可飲，別袂不可分。',120,'全唐诗/poet.song.146000.json','["別酒不可飲，別袂不可分。", "所嗟君勸我，已復又勸君。", "人生寧不老，值此相送頻。", "君家近天咫，我職在湘濆。", "山頭一揮手，從此斷知聞。", "甫昔年少日，著論准過秦。", "只今惟莫莫，於世不諄諄。", "何由東南去，復與吾子親。", "捧刺欲填字，食虀悲受辛。", "勉哉刷羽翰，往立要路津。"]'),
('e3c6696f-ab43-438d-aae3-e7709f0337ce','次韻當陽沈知縣送行','項安世','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','爾行欲何之，觸熱官裏去。',144,'全唐诗/poet.song.146000.json','["爾行欲何之，觸熱官裏去。", "官今有何急，須爾不得住。", "借問年幾何，四十倏已暮。", "前途更如此，所著真幾屨。", "明廷集夔襄，古樂徧韶頀。", "獨吹牛背笛，焉往不得牾。", "但聞湘山好，藏室鎖烟霧。", "平生獨往夢，恍惚至其處。", "胡張骨已冷，學者半新故。", "誰能用師說，九守立堅戍。", "閒持一青笠，往喚洞庭渡。", "飛上祝融峯，晴雲擘輕絮。"]'),
('92a58061-13fa-43bb-a67a-5135e43a958b','出安平山口自此無山矣作別山詩','項安世','宋','宋诗','song-poetry','','[]','自我出鄔郊，兩山翼我行。',96,'全唐诗/poet.song.146000.json','["自我出鄔郊，兩山翼我行。", "徘徊不忍去，爲雨阻我程。", "我程不可阻，前山當我橫。", "浰陽到斑竹，翳薈復崢嶸。", "中宵與之語，山鬼若見聽。", "衣上西山雲，頭上蒙泉纓。", "與君未始別，此別莫關情。", "明朝出山去，一笑漢江清。"]'),
('3a84b598-f3aa-4258-9e23-4ebc56225a6b','二十九日道中次韻酬寄羅鄂州','項安世','宋','宋诗','song-poetry','','[]','經世事日遠，獨往奈婆娑。',132,'全唐诗/poet.song.146000.json','["經世事日遠，獨往奈婆娑。", "兩途一未遂，痛飲復高歌。", "往者長已矣，黄山鬰嵯峨。", "在者聊復爾，後生誰錯摩。", "向來志士心，中夜如驚波。", "秋鷹錦韝鏇，天馬金盤陀。", "用士苦不早，歲月颯已過。", "剖符蠻觸間，使逐屈宋哦。", "珊珊青霞珮，粲粲紫玉珂。", "不嗔舞地小，但道暮山多。", "我意欲憐君，將如君笑何。"]'),
('d4f2cc32-ca23-4c2c-8cf7-672c22483700','次韻徐縣丞送行','項安世','宋','宋诗','song-poetry','','[]','用之索句苦，字字嚴以清。',96,'全唐诗/poet.song.146000.json','["用之索句苦，字字嚴以清。", "嚼之有永味，悠然寄深情。", "去年作一詩，如聽湘樂樂。", "聲翻楚客思，曲罷游魚覺。", "今年作一詩，如看湘水去。", "衝風結回波，澹靄凝遠暮。", "君詩靳不作，作則千夫開。", "情自屈賈出，聲自黄陳來。"]'),
('e9b70976-346b-4449-bcd3-4bf6b1384418','題蟬蝶畫扇','項安世','宋','宋诗','song-poetry','','[]','曉日兮花飛，晚風兮柳嘶。',25,'全唐诗/poet.song.146000.json','["曉日兮花飛，晚風兮柳嘶。", "異趣兮同樂，之二蟲兮何知。"]'),
('ed6cdc39-7383-4b98-9e55-600130399a6f','次韻謝姜自明秀才示卷詩','項安世','宋','宋诗','song-poetry','','[]','高人貴寡和，不顧世俗非。',84,'全唐诗/poet.song.146000.json','["高人貴寡和，不顧世俗非。", "君歌陽春曲，調與衆耳違。", "朱弦古時瑟，素積前朝衣。", "享我太羹饌，枯腸飫晨饑。", "贈我和氏璧，茅簷發霄暉。", "平生織流黄，忽受古錦機。", "愧非鍾子鑒，空枉伯牙徽。"]'),
('c84a46c1-f849-486d-af6e-1a14ee0f72b8','次東坡雪詩十六韻三首  其一','項安世','宋','宋诗','song-poetry','','[]','久從雲共商，稍與霰相和。',192,'全唐诗/poet.song.146000.json','["久從雲共商，稍與霰相和。", "初看稀可數，漸覺多難奈。", "如塵塞道起，似塊當空墮。", "練擣萬家砧，糠揚千廩簸。", "學舞勢僛僛，爭輝明瑳瑳。", "崑嶺玉成灰，閩溪茶出磨。", "瘠土總生腴，衡門亦堆貨。", "樵蘇带粉檐，芻稈如冰剉。", "朱轂化瑶車，華鞍變氈坐。", "兒看廢晨誦，犬走妨宵卧。", "漫天一遠近，蓋地均坎坷。", "改却松篁青，遮盡糞壤涴。", "獨有井成穿，惟餘江带破。", "處處作花衢，家家産鹽課。", "銀富不憂貧，米多寧患餓。", "比興豈無因，賤貧聊自賀。"]'),
('00827d20-1e99-4c16-b33d-8fec58a40bf6','次東坡雪詩十六韻三首  其二','項安世','宋','宋诗','song-poetry','','[]','雲來已三白，詩唱當再和。',192,'全唐诗/poet.song.146000.json','["雲來已三白，詩唱當再和。", "方無望其有，既有不可奈。", "方卑看成高，既高還易墮。", "婦言天雨米，安得箕可簸。", "兒言天雨玉，安得刀可瑳。", "粉厚婢思塗，麵粗僮欲磨。", "茗塵吾自啜，榆莢鄰俾貨。", "我馬玉山禾，饑甚睎可剉。", "我客金城氈，寒甚睎可坐。", "欲出無人蹤，且起復且卧。", "欲行無地皮，疑坎復疑坷。", "下鋪鵝肪璧，千里無點涴。", "上張狐腋裘，六合無罅破。", "仕者有遠謀，來年卜農課。", "貧者懷近憂，眼下不救餓。", "書生於其間，俯弔而仰賀。"]'),
('4ea407f7-0cfc-48d7-9b2e-402a9fe3fb67','次東坡雪詩十六韻三首  其三','項安世','宋','宋诗','song-poetry','','[]','高低互騰凌，先後更唱和。',192,'全唐诗/poet.song.146000.json','["高低互騰凌，先後更唱和。", "密密驕有餘，斜斜困無奈。", "翔空久未集，到地期不墮。", "雲惜暗遮圍，風欺惡掀簸。", "林光夜毰毸，瓦色晨玭瑳。", "犬喜吠若驚，兒顛走如磨。", "體虛君勿嫌，窖實更堪貨。", "飛逾絮毛弱，藏耐刀斧剉。", "三緘桃李蹊，十襲莓苔坐。", "填沼害魚游，封巢妨鶴卧。", "經厨忽渙汗，度井翻坎坷。", "入水恨先融，沾泥悲易涴。", "苦遭柔條翻，故壓堅竹破。", "已積深可量，方來密難課。", "宵明宿雀譁，晝合盤鴟餓。", "東日漏微光，窮人起相賀。"]'),
('9c2d4eb9-0855-4e4c-a531-34271a2962d0','次韻趙主簿雪詩十韻二首  其一','項安世','宋','宋诗','song-poetry','','[]','墮地白初形，當空黑如影。',120,'全唐诗/poet.song.146000.json','["墮地白初形，當空黑如影。", "喧豗復排拶，混沌方溟涬。", "惟餘塔可辨，始信江南迥。", "浩蕩海揚塵，糢糊山覆頂。", "梅肥頼香異，竹折傷秀挺。", "瞻烏已無色，認鶴猶有脛。", "簇簇歌處樓，栖栖畫中艇。", "端門想班賀，沙路爭駿騁。", "賦客夢游梁，逐臣悲去郢。", "沾鬢不能嫌，霜毛已垂領。"]'),
('53a60b93-f28c-49d4-bb76-30f0590bb9b6','次韻趙主簿雪詩十韻二首  其二','項安世','宋','宋诗','song-poetry','','[]','歷亂空中花，蹁躚水中影。',120,'全唐诗/poet.song.146000.json','["歷亂空中花，蹁躚水中影。", "屑屑復騷騷，凉凉何涬涬。", "風急陣形圓，雲深兵勢迥。", "簷鵲換緇衣，臯禽失丹頂。", "雁驚蘆箭射，魚畏冰叉挺。", "出印東郭跟，歸遮少陵脛。", "坐對孫康書，眠思子猷艇。", "夜氣忽崢嶸，冰天夢馳騁。", "齊珠擬誇梁，卞玉思獻郢。", "庇凍月千間，遺寒麑萬領。"]'),
('4d89568b-14ef-46cd-be31-b3b5f7f299fc','別周季隠東湖隠居','項安世','宋','宋诗','song-poetry','','[]','君不見東湖先生徐師川，雅歌清廟彈朱弦。',162,'全唐诗/poet.song.146000.json','["君不見東湖先生徐師川，雅歌清廟彈朱弦。", "又不見于湖居士張安國，健語龍蛇雜矛戟。", "佳人往矣不易致，見君使我心先醉。", "一聞東湖名，再讀于湖詩。", "恍然如見二大夫，使我真欲再拜之。", "君家玉带垂金魚，向來凜凜持鈞樞。", "丈夫不要五鼎食，自向湖邊築隠居。", "小園種花復種竹，數畝宜桑亦宜粟。", "人生如此復何求，把酒吟詩得自由。", "客來但與談風月，萬事如今只掉頭。"]'),
('337fe3c5-a844-4ae7-a470-2768456f7c72','次韻張通判遊釣隠園','項安世','宋','宋诗','song-poetry','','[]','大家有寶初不靳，戲把兼金擲虛牝。',160,'全唐诗/poet.song.146000.json','["大家有寶初不靳，戲把兼金擲虛牝。", "小家尺寸入校量，澀縮支撐惟恐盡。", "張侯胸中無不有，詩未落手人已信。", "偶然寫作釣隠圖，畫出芳洲橫小艇。", "水營何事去能忙，洲學誰禪眠許靜。", "東城車馬起埃塵，西嶺烟雲生瞥瞬。", "漁人正用一孤篷，傲兀其間俱戰勝。", "追隨魚鳥共飛浮，俯仰乾坤寄晨暝。", "我雖未是境中人，讀罷公詩遊已竟。", "從今剩覓千首詩，不用芒鞋踏幽境。"]'),
('7b853325-cf1d-4537-ad9e-3e59b3f33375','都下次韻酬松陽葉叔文','項安世','宋','宋诗','song-poetry','','[]','君不見崑岡烈焰燔蒼穹，中有一氣亙天如白虹。',396,'全唐诗/poet.song.146000.json','["君不見崑岡烈焰燔蒼穹，中有一氣亙天如白虹。", "又不見徂徠之山十丈雪，但見磊塊硉兀錯立于其中。", "從來人事看晚歲，不與兒童爭此世。", "五金流處要璠璵，萬木枯時待松桂。", "我家松源妙人物，水怪山奇古仙窟。", "山含水氣生萬嘉，水抱山形成百折。", "卯山先生山水郎，呼吸水怪含山光。", "栽梅不入積李候，植蕙自愛深林芳。", "筆端風月三千首，血指前頭甘袖手。", "腹中文字五千卷，白眼旁邊不開口。", "流泉百尺松風凉，玉琴一曲自琅琅。", "三間茅屋夜有光，直入斗牛何煌煌。", "萬鍾嵯峨劍頭米，九州幾何太倉粃。", "得錢嫁女吾事了，歸向空山教兒子。", "此時方帽一先生，野老相過無姓名。", "草間泥飲同一醉，醉裏小詩還自成。", "竹杖山邊行翠圍，松舟水上眠風漪。", "山行水宿似有道，或者疑是唐天師。", "古來藝達非道許，道在回愚與參魯。", "戰於蠻觸焉得剛，落盡皮毛吾甚武。", "復雷有象地中藏，豐屋無人天際翔。", "捨梧養樲師也賤，有芸無揠農之良。", "徐行周視故無遺，大道不勞私智窺。", "堂堂夏屋忍空曠，擾擾利場同縶維。"]'),
('b1bafb33-e0a7-47f0-9338-d95905c16db6','胡撫幹仲方','項安世','宋','宋诗','song-poetry','','[]','南郡佳人胡伯始，遼鶴重來藕花裏。',128,'全唐诗/poet.song.146000.json','["南郡佳人胡伯始，遼鶴重來藕花裏。", "皮冠翠被俯曾城，一一人民皆故里。", "罪人雖在四民外，亦是官家窮赤子。", "已將密蔭庇龜魚，更把閒情親鹿豕。", "東日舊德宛如新，他日榮觀皆倣此。", "年登八十豈其難，官至三師行復爾。", "都將厚福與之同，只有中庸渠未是。", "却須回向澹菴翁，此是君家真性理。"]'),
('fe3fb766-9128-4af0-82ee-ae868e9acfa2','送張安撫','項安世','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','蓬萊太守厭期會，歸結琳宮香火緣。',384,'全唐诗/poet.song.146000.json','["蓬萊太守厭期會，歸結琳宮香火緣。", "路旁送者誰最切，之子佩衿青可憐。", "子兮請自曩時說，芹館就荒三十年。", "邇來窮悴更堪說，舍下鞠草厨無烟。", "市門小兒有虛籍，校官弟子無鳴絃。", "向來一辱聲掃地，倒九江水誰爲湔。", "守家故是補天手，斷鰲四足承高圓。", "小却盛之鑑湖上，施設次第看後先。", "下車百廢未及舉，冕服釋菜供聖賢。", "願從博士聽講說，歛容就席毋敢專。", "邦人始識蠹簡重，士子稍作青灰然。", "迂生欲舉折洗事，衆膽傍碎公加鞭。", "合八縣士一戰霸，百川之水皆東沿。", "鵠袍如山聲不震，秦望却立回清妍。", "紫衣金带朱兩轓，牙旗戟纛來翩翩。", "魯侯色笑有深愛，南公歎息無前傳。", "翠裯已覺夏室清，棐几更與秋窗便。", "日輸月給輩相望，餼牽竭矣公愈堅。", "坐令學者飽虀飯，不待先生求酒錢。", "風聲汎汎鄒魯上，意向往往嬴劉前。", "子兮如此衿佩何，半渡欲濟收吾船。", "季鷹家人故難料，歸興忽動秋風邊。", "若人固自泰山雨，詎肯作我稽山泉。", "轅高轍駛不可駐，哦以七字成長篇。"]'),
('f3d83f1f-184e-4e21-831c-84692987155a','次韻答胡季履二首  其一','項安世','宋','宋诗','song-poetry','','["\u5929\u95e8\u5c71"]','吾易不師房與雄，吾筴不占方與功。',199,'全唐诗/poet.song.146000.json','["吾易不師房與雄，吾筴不占方與功。", "曰生一字有餘矣，萬有二千無隠爾。", "家人養火青楓前，過鼎一散成灰烟。", "泉亭長在麓之始，一止于山斯蹇矣。", "君不見坎離汲汲長相親，天淵混混無停雲。", "陳根已腐先復神，碩果未落心先人。", "心源翼翼城與缾，目光步步蘧而醒。", "得路至死行勿還，一簣自到天門山。", "不愁緝緝仍翻翻，偏我詐詐與姦姦。", "只愁衰惰忘躋攀，生意自斷它人難。", "公家此事最了了，萬仞峯頭看飛鳥。", "忽然憐我鸒鳩鷃雀之凡毛，傅以鵬翼何其高。"]'),
('6686a88a-5730-448f-8043-59305f79184f','次韻答胡季履二首  其二','項安世','宋','宋诗','song-poetry','','["\u8861\u5c71"]','君不見大胡公，春秋一筆誅群雄，要與排鴻驅象爭元功。',208,'全唐诗/poet.song.146000.json','["君不見大胡公，春秋一筆誅群雄，要與排鴻驅象爭元功。", "素王吾無間然矣，命世雖云無有爾。", "至今可望不可前，海山雲氣藍田烟。", "後無終極前無始，定以一元而已矣。", "又不見小胡公，沈潜探索要且親，傳心嫡派非礽雲。", "善根生聖聖生神，此理即元元即人。", "至今汲汲隨甖缾，涸者得濡狂者醒。", "濂溪已遠涪州還，此事往往歸衡山。", "大兒如祖洪濤翻，捎摋地怪麾天姦。", "小兒如父勤鑽攀，深觀博取爲其難。", "二公有藴行未了，可惜光陰如過鳥。", "二兒今日又霜毛，若要及人毋太高。"]'),
('51a9e7cd-17f8-4305-b427-234cbe627dbd','送張寺丞知常州','項安世','宋','宋诗','song-poetry','','[]','吾鄉人物鄭與張，堂堂介圭出琳琅。',144,'全唐诗/poet.song.146000.json','["吾鄉人物鄭與張，堂堂介圭出琳琅。", "論文合草北扉制，論經合講金華藝。", "兩途未遂如命何，四方爲君充撫摩。", "鄭公好義不肯住，張公好仁須少駐。", "吾聞天以民爲兒，又聞君以民爲支。", "爲天活兒天必享，爲君養支君必賞。", "天公享公壽千齡，天子賞公金萬鋌。", "能回五十萬人命，詎止封侯當得政。", "但令聖主民不饑，何必金華與北扉。"]'),
('cfbc9e39-8d80-42c8-a472-034d8deb7604','送李邕州','項安世','宋','宋诗','song-poetry','','[]','一官全似飛鴻翼，不在天南即天北。',167,'全唐诗/poet.song.146000.json','["一官全似飛鴻翼，不在天南即天北。", "朝辭白馬阿得脂，暮長蠻夷老夫國。", "不知廣源洞裏儂智高，何似仇池頂上楊難敵。", "傍人自歎吾自歌，靜處安身最長策。", "蝤蛑聞說背如黿，龍眼見來形似橘。", "桄榔之粉白于麵，椰子之泉甘勝蜜。", "婦能瀹餠兒啖果，翁自右浮還左執。", "天明坐衙將吏走，飯罷收廳烏鳥佚。", "人生如此亦何求，但媿君恩與民力。", "君不見江陵有叟白髭鬚，一榻十年穿兩膝。"]'),
('078bfe84-e30d-4344-8685-0b6786481ffd','上安撫高大卿五十韻','項安世','宋','宋诗','song-poetry','','[]','酆宮夜夢朱輪蹄，曉占熊虎嬉磻溪。',384,'全唐诗/poet.song.146000.json','["酆宮夜夢朱輪蹄，曉占熊虎嬉磻溪。", "魚竿沒浪豹韜出，金印斗大封全齊。", "百年梁柱出公族，外間國子中高徯。", "敬仲子孫盡鸞鵠，太岳廩廩卑凡黎。", "共惟太尉安國侯，龐眉繡黼游金閨。", "栽蘭種玉一千頃，芳潤衮衮生春畦。", "青齊百郡涴羶酪，無地可駟金狻猊。", "敖曹兄弟年正少，仰見赤日東方隮。", "丈夫江南雲水客，肯受蠛蠓幽缾醯。", "豹辭重霧氣吞虎，犀脫九淵光駭雞。", "于湖故是髯奴壘，蠅棘豈堪高鳳棲。", "群仙競乞紫霞佩，凡虎不斷青雲梯。", "清都太微覲玉座，綠章讀罷天爲低。", "英風爽氣動瑶闕，消得君王羹駃騠。", "壽州屬縣董生里，小却去偃邊城鞞。", "一州茆竹變桑苧，淮流不盡青玻璃。", "人言賜盡須一丈，不然尺二韓侯圭。", "誰知尚欠峽山夢，清江萬里隨鳬鷖。", "吏民莫作太守看，天子命我蘇旄倪。", "新詩恰要好山助，嫩肋不勞蕭斧批。", "丁寧縣令莫負弩，我有錦囊消一奚。", "烏絲欄置鐵鈎鎖，黄絹色摇金臼虀。", "姓名飛入玉宸殿，道山藏室煩吹藜。", "諸公著意疎賈誼，更欲盛我西山西。"]'),
('cfbff0bf-64db-4d22-86c6-17f84a991b21','常山縣','項安世','宋','宋诗','song-poetry','','[]','常山縣東足可惜，山光半紫溪全碧。',96,'全唐诗/poet.song.146000.json','["常山縣東足可惜，山光半紫溪全碧。", "柳嶼陰中軋軋車，桑疇徑裏青青麥。", "溪流終日伴人行，隔岸青山喚得譍。", "石季倫家新步障，李將軍畫小圍屏。", "多情小艇招賢渡，載我溪南看山去。", "黄昏我宿溪自行，只有青山伴人住。"]'),
('33d9a7b8-fbc7-4e79-939f-6d5c1b7f0102','建平縣道中','項安世','宋','宋诗','song-poetry','','[]','糖甖花開官路香，客子欲歸官路長。',80,'全唐诗/poet.song.146000.json','["糖甖花開官路香，客子欲歸官路長。", "稻田水足新秧黄，小麥吐秀南風凉。", "村村煮酒開官坊，家家禁忌障蠶房。", "門前健婦能招商，茗碗角餌邀人嘗。", "若無橫賦深剝牀，我欲問舍鷄林鄉。"]'),
('92869789-08dd-435c-b821-08aa27640c62','舟中閲親舊書','項安世','宋','宋诗','song-poetry','','[]','王稅官遺我一紙書，告我六十七灘名。',178,'全唐诗/poet.song.146000.json','["王稅官遺我一紙書，告我六十七灘名。", "舟人愛捷不愛穩，勸君勿盤官莫聽。", "曹先生遺我一紙書，四百餘字相丁寧。", "扶持世道貴深穩，切莫浪戰傾人城。", "兩書共作一書捲，一日十發手不停。", "口吟一字三太息，眼淚迸作黄流傾。", "我生三十有六歲，今年始別父母行。", "母兮恐我蹈天險，夢寐聽我盤灘聲。", "父兮恐我蹈人險，行坐勸我去寬平。", "二君此語誰告之，乃能得我父母情。", "從今座右置此紙，夜思晝讀當盤銘。"]'),
('22175945-1dbf-45ff-99ea-4658871d3e7b','送趙令赴江陵','項安世','宋','宋诗','song-poetry','','[]','平生所聞趙景明，太阿出匣百壬死。',128,'全唐诗/poet.song.146000.json','["平生所聞趙景明，太阿出匣百壬死。", "不令赤手□□□，亦合麻鞋見天子。", "霜風獵獵鬢毛斑，萬里水縣菰蒲間。", "妻兒稱屈大夫笑，閉閣正用蘇麻頑。", "邊頭有兵人要籍，邊頭有萊人要闢。", "名佳實惡君勿信，塞下吏民須蕩佚。", "檢民如葦身如弦，有時白眼對世賢。", "正爾忽憶諸梁篇，稍事細謹無流連。"]'),
('c5e9e7f8-dbad-44aa-ad33-652172b98a45','答陳江州和少游梅花韻見寄','項安世','宋','宋诗','song-poetry','','[]','葉似枯疎元不槁，枝似橫斜元不倒。',128,'全唐诗/poet.song.146000.json','["葉似枯疎元不槁，枝似橫斜元不倒。", "幾年花卉受渠欺，無限詩人被渠惱。", "冰霜冷淡妬人香，桃李衰遲嗔我早。", "露中梳洗怕添妝，雪裏埋藏畏稱好。", "隴頭村外忽相見，萬紫千紅遭一掃。", "却因計早遂成遲，桃杏開時吾已老。", "樓頭片片逐鳴笳，簷額紛紛墮芳草。", "頼憑金彈貯微酸，長爲天公轉芒昊。"]'),
('8d95f7c3-8277-4c88-bd6c-2d7e3b53b92b','送張升之四首  其一','項安世','宋','宋诗','song-poetry','','[]','升之升之子其歸，白雲鴻雁天邊飛。',44,'全唐诗/poet.song.146000.json','["升之升之子其歸，白雲鴻雁天邊飛。", "我嗟不能從子歸，煩子爲我尋松溪。", "松溪頭，萬株松樹平安不。"]'),
('f926aacb-a4ea-4cb6-98a3-ddc6ac8db86b','送張升之四首  其二','項安世','宋','宋诗','song-poetry','','[]','故人故人休相憶，君去江南我江北。',48,'全唐诗/poet.song.146000.json','["故人故人休相憶，君去江南我江北。", "江南江北天茫茫，相思各在天一方。", "天邊有雁江有魚，相思爲寄尺素書。"]'),
('8358a93f-9585-44fd-b0d3-d4c2ace492be','送張升之四首  其三','項安世','宋','宋诗','song-poetry','','[]','昔年常恨李白杜甫不相從，又見韓愈孟郊恨不如雲龍。',76,'全唐诗/poet.song.146000.json','["昔年常恨李白杜甫不相從，又見韓愈孟郊恨不如雲龍。", "我今與子別，正與二子同。", "我在大江北，君歸五湖東。", "我猶作楚客，君復爲吳儂。", "江湖吳楚休相憶，青雲有路各努力。"]'),
('71df639e-e4c2-4021-b97e-39d9b9d369f1','送張升之四首  其四','項安世','宋','宋诗','song-poetry','','[]','天公昨日爲我悲，陰雲慘慘風凄凄。',104,'全唐诗/poet.song.146000.json','["天公昨日爲我悲，陰雲慘慘風凄凄。", "天公今日爲我喜，朝陽晃晃融新泥。", "一悲復一喜，天意良有以。", "悲我東齋別心友，喜子還家奉甘旨。", "心友不可別，甘旨不可闕。", "人生安得兩如意，故人一別今千里。", "他時迎侍還東州，約君過我松溪頭。"]'),
('0f51cad5-4d3d-43db-b46b-3a6ef4e09a19','久旱得雨','項安世','宋','宋诗','song-poetry','','[]','不羨二十四考中書令，不羨萬八千戶冠軍侯，千羨萬羨朝來雨。',262,'全唐诗/poet.song.146000.json','["不羨二十四考中書令，不羨萬八千戶冠軍侯，千羨萬羨朝來雨。", "黄金白璧尚可求，去年大熟市無米。", "官船載使資他州，千艘萬艦日夜去。", "今年天旱始知憂，高田已逐黄埃化，湖田五月種未投。", "豈無飛車捲湖水，十日南風吹絕流。", "城郭村原百萬口，性命頃刻難爲留。", "如人奄奄氣欲斷，尚有微息出入三寸喉。", "天公亦有萬金藥，刀圭一試沉疴瘳。", "蔽藏赤日雲晻晻，呼吸凉氣風修修。", "雨聲未落人已快，便有生意還梧楸。", "夜深稍稍到竹屋，曉起涓涓行瓦溝。", "但看病草泫流血，想見羸秧新舉頭。", "兒童亦知一雨好，牽衣挽脛寬人愁。", "早禾已死不可救，晚禾未出猶堪收。", "天公有意憐赤子，願雨三日無少休。"]'),
('0149a617-01b8-4023-acdb-f3121292bc7b','大雨破塊而入書籍盡濕','項安世','宋','宋诗','song-poetry','','[]','容齋先生楚樓北，案上文書似山積。',208,'全唐诗/poet.song.146000.json','["容齋先生楚樓北，案上文書似山積。", "夜來醉卧不知曉，驪龍翻空作戲劇。", "巽二顛狂助叫號，吹下銀河八千尺。", "阿香寤起推雲車，鐵鼓金輪吼空壁。", "先生鼻息正雷鳴，萬狀千聲驚不得。", "興闌無奈此生何，噴入寒窗弄文墨。", "海神推浪上蓬萊，天漢回波浸圭璧。", "蘇卿引水灌西周，柱下老君翻藏室。", "子美多應是水仙，遺稿猶罹耒陽厄。", "初疑漢室濫觴餘，又如高鳳堂中麥。", "兒童見者各心驚，先生笑罷吟肩側。", "秦火雖焚道不焚，唐舟縱溺文難溺。", "摸索枯腸問雨師，奈我胸中真六籍。"]'),
('0c5f4e61-a216-41b6-b2f3-159f94445d65','陳攖寧既刊周左司太倉稊米集于阜陽趙使君復刊攖寧詩于荆門詩家皆美其師徒傳授之懿余亦次韻美之','項安世','宋','宋诗','song-poetry','','[]','鄉人長幼班以年，戚姻遠近合以連。',147,'全唐诗/poet.song.146000.json','["鄉人長幼班以年，戚姻遠近合以連。", "未如骨肉金石堅，祖孫父子其屬天。", "詩人一炷倉稊烟，玉川拜後攖寧前。", "如念爾祖思厥先，非真有聞胡傳焉。", "漢餘師法忌襲沿，譜系散落觀者眩。", "玉川摇首吾不然，持此薄命將誰妍。", "向來得法雙膝穿，老矣重任猶承肩。", "有能一鏃直我弦，兩手付汝□□□。", "君不見大書深刻開重元，徧四大海求其傳。"]'),
('fbc02062-94f7-40e9-a707-bdff4a384624','夔州永安宮詞','項安世','宋','宋诗','song-poetry','','[]','許昌門外驅霆靂，玉筯驚拋夜無迹。',192,'全唐诗/poet.song.146000.json','["許昌門外驅霆靂，玉筯驚拋夜無迹。", "五花驕馬雲作蹄，飛渡檀溪人未識。", "大隄八月陰風起，葉落花黄心欲死。", "山枯石裂見蒼龍，三十六鱗纔赴水。", "逢逢搥鼓上瞿塘，老瞞落筆三川忙。", "蓬萊一夜兩鼇死，血殷海水天無光。", "金戈鐵馬宮前道，龍旗未捲君王老。", "當時玉座醉春桃，今日銅駝泣秋草。", "從來兩髀彫鞍側，不爲兒曹營玉食。", "生將一死答將軍，死用一生酬相國。", "喬家小郎名賞音，玉房花貌空沉吟。", "吳娃解掩夫差面，難繫劉郎一寸心。"]'),
('9b827041-73f9-4a9e-8aa4-a1d44b480efd','次韻叔父從沈氏乞酒','項安世','宋','宋诗','song-poetry','','[]','雨後桃笙新睡足，經年一夢葡萄綠。',96,'全唐诗/poet.song.146000.json','["雨後桃笙新睡足，經年一夢葡萄綠。", "江南庾信萬斛愁，安得杯羹爲渠飫。", "南風日日送啼烏，東老好事今能無。", "督郵面目日可厭，青州網密音塵疎。", "誰能過我致十榼，奇字尚堪供問答。", "令人自憶平陽侯，日飲無何惟閉閤。"]'),
('b47c2567-17ba-4ce4-a3d5-bb4c0fd367a1','祁陽縣晚渡','項安世','宋','宋诗','song-poetry','','[]','郭外湘江清徹底，江頭石壁新如洗。',64,'全唐诗/poet.song.146000.json','["郭外湘江清徹底，江頭石壁新如洗。", "呼舟斜日度空明，脫帽中流照清泚。", "一聲欵乃忽心驚，曾與漁郎有舊盟。", "日暮征車猶未已，鬢毛如此欲何營。"]'),
('6edd22ef-b15f-48c1-84c5-371aa8bbe536','寒食道中','項安世','宋','宋诗','song-poetry','','[]','兒時只願春長早，老去始知春要老。',64,'全唐诗/poet.song.146000.json','["兒時只願春長早，老去始知春要老。", "人老高低事事諳，春深遠近家家好。", "鶑來燕去總關天，絮起萍浮俱合道。", "浪將開落惱閒心，却恨少年何草草。"]'),
('fc2ee1c3-c1db-45d1-96cf-9170e8065929','寒食輿病至城西再續去年之詠','項安世','宋','宋诗','song-poetry','','[]','冉冉飛來紅杏雨，又到去年花落處。',64,'全唐诗/poet.song.146000.json','["冉冉飛來紅杏雨，又到去年花落處。", "花今落慣已如常，莫怪春歸春不語。", "却思天女染春時，弄粉調朱傅綠枝。", "只見插花人似錦，誰知當日手如龜。"]'),
('0f2de764-2ab1-4705-8438-ec75599ddd75','以椰子香爐花瓶爲大人壽','項安世','宋','宋诗','song-poetry','','[]','石湖居士虞衡志，椰子之身本椶類。',224,'全唐诗/poet.song.146000.json','["石湖居士虞衡志，椰子之身本椶類。", "葉間各結三四子，大者能容五升器。", "初如青纈美少年，漸久漸黄堅且緻。", "有穰如玉汁如乳，味如春醪飲輒醉。", "番禺老工巧心數，能製瓶爐出新意。", "盡力揩摩發光彩，一月工夫成一技。", "二瓶可花爐可香，中有千鍾萬鍾味。", "牋封囊裹送大人，伴以銀奩古心字。", "四君俱自南天來，一老新霑北辰賜。", "金章紫綬照鄉閭，玉色冰神明聽視。", "天上煌煌列宿光，人間赫赫真郎貴。", "人言書自武昌來，知是吾兒壽詩至。", "兒供椰果勸椰杯，花露香風俱酒氣。", "慇懃更作椰子詩，甲子中間一年歲。"]'),
('1f476546-c84a-496f-af15-56210a9cd191','用韵爲席婿壽','項安世','宋','宋诗','song-poetry','','[]','仲呂欲轉蕤賓宮，巽位未放離風通。',192,'全唐诗/poet.song.146000.json','["仲呂欲轉蕤賓宮，巽位未放離風通。", "世有大族傳伊嵩，天與峻秀包邙熊。", "生申降甫何穹崇，赤昴太白來虛空。", "星光嶽氣煜以充，聖罇賢斚醒復中。", "援琴大叫蒼梧風，呵斗插向南雲東。", "向來兩手超逢蒙，連取三鶚摧其衷。", "南宮作賦羞雷同，坐見瓦釜欺玲瓏。", "老驓迥立雌群雄，大花晚折王衆叢。", "不妨吾事日以隆，小待造物觀其終。", "良金美玉無不公，陽春白雪無不聰。", "琅函氈字書春功，繡韉羢坐開曉幪。", "我時一醉衰顔紅，但願玉貴甘冰窮。"]'),
('e2d9e53c-dcac-48c9-a9e7-22c32863fa68','四伯父生朝集老杜句二十韵','項安世','宋','宋诗','song-poetry','','[]','三月三日天氣新，著處繁華矜是日。',315,'全唐诗/poet.song.146000.json','["三月三日天氣新，著處繁華矜是日。", "明日蕭條盡醉醒，碧窗宿霧濛濛濕。", "南極老人自有星，掛君高堂之素壁。", "仙人玉女回雲車，萬草千花動凝碧。", "奇祥異瑞爭來送，麟角鳳嘴世莫識。", "酒肉如山又一時，滿堂賓客皆嘆息。", "正是江南好風景，苑中萬物生顔色。", "遮莫鄰鷄下五更，且將款曲終今夕。", "獨慙投漢閣，出守吾家姪。", "懶慢無堪不出村，生無所成頭皓白。", "朋知來問腆我顔，汝伯何由髮如漆。", "紅顔白面花映肉，秋水爲神玉爲骨。", "元圃蒼洲莽空闊，神仙中人不易得。", "在於甫也何由羨，扶持自是神明力。", "君不見大兒聰明到，越羅蜀錦金粟尺。", "裁縫雲霧成御衣，朝廷記憶蒙祿秩。", "小兒心孔開，射策君門期第一。", "今春喜氣滿乾坤，朱紱即看隨畫鷁。", "丈夫生兒有如此，百年未見歡娛畢。", "南極老人應壽昌，人生歡會豈有極。"]'),
('af0b4da9-b471-4c94-967a-9454d446b635','春日即事二首  其一','項安世','宋','宋诗','song-poetry','','[]','拂拂水紋亂，陰陰花氣芳。',48,'全唐诗/poet.song.146000.json','["拂拂水紋亂，陰陰花氣芳。", "輕霏入平野，小雨渡橫塘。", "柳色未全綠，草根猶半黄。", "春容不可狀，欲說意還忘。"]'),
('808a3241-e7f3-451a-b41a-f44f5b2a36a7','春日即事二首  其二','項安世','宋','宋诗','song-poetry','','[]','好處難爲畫，閒中剩費吟。',48,'全唐诗/poet.song.146000.json','["好處難爲畫，閒中剩費吟。", "花開相次第，日出半晴陰。", "笑語人情樂，烟霏草色深。", "望中無可採，忽忽總關心。"]'),
('3a402582-693b-4146-9144-a28217816bca','睡起','項安世','宋','宋诗','song-poetry','','[]','夢破鷄啼午，心閒鵲噪晴。',48,'全唐诗/poet.song.146000.json','["夢破鷄啼午，心閒鵲噪晴。", "焚香槐日永，煮茗麥風清。", "掬水洗餘困，看雲生遠情。", "時時記花影，自遶曲欄行。"]'),
('10e159d6-8d50-4eda-9539-c1249b16b7aa','省中橋亭即事','項安世','宋','宋诗','song-poetry','','[]','虛閣跨芳沼，陰溪生綠苔。',48,'全唐诗/poet.song.146000.json','["虛閣跨芳沼，陰溪生綠苔。", "雨晴梅子長，春過芍花開。", "坐久談微縱，情深首重回。", "最憐清蔭裏，時有細香來。"]'),
('394d6529-d19e-4691-beef-c57143b4b9a8','同葉卿至龍井二首  其一','項安世','宋','宋诗','song-poetry','','[]','送客得茲遊，湖邊上小舟。',48,'全唐诗/poet.song.146000.json','["送客得茲遊，湖邊上小舟。", "水吞沙岸遠，雲綻日光浮。", "地轉風篁密，山藏野寺幽。", "飛泉如有意，夾路奏鳴球。"]'),
('349891cc-f433-4d77-920c-b0118163d9c2','同葉卿至龍井二首  其二','項安世','宋','宋诗','song-poetry','','[]','半世聞龍井，今年傍驛車。',48,'全唐诗/poet.song.146000.json','["半世聞龍井，今年傍驛車。", "山中無乳竇，世上有鳴渠。", "投石占陰洞，班荆飯野蔬。", "京塵紅一丈，無路到僧居。"]'),
('32ebc8cd-d874-43c9-be10-522ffe6a96d8','送客北關回赴省宿次韻和楊秘書','項安世','宋','宋诗','song-poetry','','[]','擾擾送征行，匆匆赴北城。',48,'全唐诗/poet.song.146000.json','["擾擾送征行，匆匆赴北城。", "隔關愁暝早，入直愛官清。", "夏屋連雲冷，冬宵徹曉明。", "不眠身百轉，無計决平生。"]'),
('6ca15a5f-a0ec-4f4b-a16a-4a0ab5019cd2','行香早起','項安世','宋','宋诗','song-poetry','','[]','露入襟裳冷，風傳带舄清。',48,'全唐诗/poet.song.146000.json','["露入襟裳冷，風傳带舄清。", "天街摇斷夢，原廟聽攢更。", "闕角升雲氣，簷牙鏤月明。", "未教陽彩動，應怕路塵生。"]'),
('69f28d0c-44b8-4c59-b774-84a825c96ebd','省中晚步讀宛陵詩  其一','項安世','宋','宋诗','song-poetry','','[]','午夢睡新足，西溪微暑侵。',48,'全唐诗/poet.song.146000.json','["午夢睡新足，西溪微暑侵。", "高堂通爽氣，綠樹愛繁陰。", "甃潤冷侵舄，簷虛風入襟。", "獨携梅老集，終日伴沉吟。"]'),
('8fc99dee-4f1a-4ee9-9203-b14699ff4337','省中晚步讀宛陵詩  其二','項安世','宋','宋诗','song-poetry','','[]','同僚歸去後，挾冊此婆娑。',48,'全唐诗/poet.song.146000.json','["同僚歸去後，挾冊此婆娑。", "樹密陽光薄，庭空鳥語多。", "靜中知有味，睡外更無何。", "彷彿滄洲興，悠然起細哦。"]'),
('b1b2c8a2-bc34-4698-a694-308f1982ee94','直舍窗前綠樹','項安世','宋','宋诗','song-poetry','','[]','綠樹幾年栽，窗應爲爾開。',48,'全唐诗/poet.song.146000.json','["綠樹幾年栽，窗應爲爾開。", "陰中無暑到，缺處有風來。", "長日宜佳寢，黄昏未忍回。", "今年緣底事，歸思忽難裁。"]'),
('aa3e84ca-191b-4d68-9326-92b485a30a16','有感三首  其一','項安世','宋','宋诗','song-poetry','','[]','八葉炎圖茂，千齡聖主昌。',48,'全唐诗/poet.song.146000.json','["八葉炎圖茂，千齡聖主昌。", "農桑開漢域，禮樂煥周庠。", "晏壑三登樂，謳吟七閏長。", "徽名辭鏤玉，盛舉冠前王。"]'),
('8d5ca890-9ec8-4321-bb2e-d27bb77a74fb','有感三首  其二','項安世','宋','宋诗','song-poetry','','[]','運屬宣和末，干戈變故仍。',48,'全唐诗/poet.song.146000.json','["運屬宣和末，干戈變故仍。", "倦勤修內禪，流澤啟中興。", "睢水千麾集，胡沙八駿騰。", "尺書傳諱日，寰宇淚如澠。"]'),
('7cf314f3-bb19-4b3a-950e-9d6e3f8b9da8','有感三首  其三','項安世','宋','宋诗','song-poetry','','[]','孝感柔强敵，和盟定一朝。',48,'全唐诗/poet.song.146000.json','["孝感柔强敵，和盟定一朝。", "龍輴來瀚海，鶴駕返神霄。", "歌吹仍祠禹，羹牆若見堯。", "稽山同峻極，從此百神朝。"]'),
('f4e45a55-9e18-4975-9599-ea687a454078','紹興次韻趙成卿閏七夕','項安世','宋','宋诗','song-poetry','','[]','乞得天孫網，人間巧已多。',48,'全唐诗/poet.song.146000.json','["乞得天孫網，人間巧已多。", "還逢閏重七，奈此衆兒何。", "耕織關民事，婚姻自俗訛。", "乾坤大務本，觀象莫蹉跎。"]'),
('dfae2be5-0611-4d2d-998c-af552a0244e7','中秋新昌道中有懷','項安世','宋','宋诗','song-poetry','','[]','今夜山陰月，家庭想共看。',48,'全唐诗/poet.song.146000.json','["今夜山陰月，家庭想共看。", "霜毛明壽鶴，霧鬢濕柔鸞。", "北望江湖迥，南瞻屺岵寒。", "頼憑雙去雁，早已報平安。"]'),
('e2fd988c-9e95-4d57-be9c-2ba3a1197ed4','紹興送妻弟任縣尉歸邵武二首  其一','項安世','宋','宋诗','song-poetry','','[]','珍重任公子，君行定幾時。',48,'全唐诗/poet.song.146000.json','["珍重任公子，君行定幾時。", "重來未有日，此別可無詩。", "带雨登閩嶠，因□想蜀碑。", "兩翁門戶在，努力慰相思。"]'),
('158235e2-3f16-4029-8980-208c9e0e04aa','紹興送妻弟任縣尉歸邵武二首  其二','項安世','宋','宋诗','song-poetry','','[]','場屋追兄弟，閨門託婦壬。',48,'全唐诗/poet.song.146000.json','["場屋追兄弟，閨門託婦壬。", "傳家深屬契，爲客細論心。", "何物尉乃勇，所居官不侵。", "相期愛蜩甲，突兀看穹林。"]'),
('ea0dfd2a-83b5-4da7-96d5-9794fcd42860','送周伯壽赴省二首  其一','項安世','宋','宋诗','song-poetry','','[]','子合居官久，今方得雋遲。',48,'全唐诗/poet.song.146000.json','["子合居官久，今方得雋遲。", "我儂非不早，老去亦何爲。", "冰玉相輝處，科名未是奇。", "草茅千萬慮，一一要扶持。"]'),
('3319207b-66fa-4ea6-94ac-6fe968012764','送周伯壽赴省二首  其二','項安世','宋','宋诗','song-poetry','','[]','陳薛非卿監，趙羅真吏兵。',48,'全唐诗/poet.song.146000.json','["陳薛非卿監，趙羅真吏兵。", "殿中尤給事，館下范先生。", "六士書難作，千懷子代傾。", "蒼生底時卿，切莫話歸耕。"]'),
('46ca75f3-03a5-4ce5-aa8a-1904a589dce3','冬至前簡陳正己李季允','項安世','宋','宋诗','song-poetry','','[]','節物吹葭近，鄉閭送篚頻。',48,'全唐诗/poet.song.146000.json','["節物吹葭近，鄉閭送篚頻。", "驩虞傾一市，憔悴獨三人。", "驛破風搜屋，船低月暗津。", "吾親于越外，日夜鬢毛新。"]'),
('a60deb1e-5446-4355-aa93-72eb39cb4394','雪中簡周子問','項安世','宋','宋诗','song-poetry','','[]','問訊東湖雪，今年幾尺深。',48,'全唐诗/poet.song.146000.json','["問訊東湖雪，今年幾尺深。", "擁門無過屐，折竹有驚禽。", "映帙兒童事，豐年老大心。", "待携筇杖去，梅下索清吟。"]'),
('e473eed8-8294-4ccf-9762-e6b53f64597a','次前韻督高秀才和詩','項安世','宋','宋诗','song-poetry','','[]','一雪來何暮，經年望已深。',48,'全唐诗/poet.song.146000.json','["一雪來何暮，經年望已深。", "狂於三月絮，清甚九臯禽。", "縱未扁舟興，能忘五字心。", "如何高處士，斷得此時吟。"]'),
('e495be04-46ef-4f6f-9500-e14a5d18b068','再次前韻督周子問雪中以疾辭詩','項安世','宋','宋诗','song-poetry','','[]','散花侵示疾，造物戲公深。',48,'全唐诗/poet.song.146000.json','["散花侵示疾，造物戲公深。", "毳飯添三白，熊經試一禽。", "從來詩愈瘧，枉去藥關心。", "無限山陰興，匡牀好越吟。"]'),
('1437405a-583b-4c40-a267-ae414a8606cc','寄韓丈兄弟  其一','項安世','宋','宋诗','song-poetry','','[]','兄弟真連璧，文章自一家。',48,'全唐诗/poet.song.146000.json','["兄弟真連璧，文章自一家。", "祠庭聊燕息，使節最光華。", "後會春應好，相思日又斜。", "遥知北堂上，把酒插梅花。"]'),
('1772f852-d1dc-4c4c-a6a9-f409c9c122c7','寄韓丈兄弟  其二','項安世','宋','宋诗','song-poetry','','[]','歲月驚遊子，江山隔故園。',48,'全唐诗/poet.song.146000.json','["歲月驚遊子，江山隔故園。", "感時雖有恨，適意自忘言。", "土銼晨炊飯，茅簷晝負暄。", "病來詩思減，東望想詞源。"]'),
('a59a9850-ecd0-4edd-998e-4a47b59b2089','寄胥直夫','項安世','宋','宋诗','song-poetry','','[]','江上歲云暮，風波無定時。',48,'全唐诗/poet.song.146000.json','["江上歲云暮，風波無定時。", "天寒歸鶴早，水闊到船遲。", "老去頗諳事，病來仍廢詩。", "願君逢驛使，寄贈小梅枝。"]'),
('6deaf5b1-19f5-4e22-a361-b0a5b1b56c17','次羅機宜韻  其一','項安世','宋','宋诗','song-poetry','','[]','篤道羅夫子，平生一展禽。',48,'全唐诗/poet.song.146000.json','["篤道羅夫子，平生一展禽。", "由由無失己，耿耿獨垂今。", "問舍家仍在，居家隠自深。", "祇今人不置，無處避朱金。"]'),
('ae9439bb-6a20-4cc5-ab6c-ec93a4b05e9b','次羅機宜韻  其二','項安世','宋','宋诗','song-poetry','','[]','不識田何易，空然愧項生。',48,'全唐诗/poet.song.146000.json','["不識田何易，空然愧項生。", "學文經子厚，評品得鍾嶸。", "內省無他技，誰欺有雋聲。", "後來資汲引，因見古人情。"]'),
('f526dc6f-46d5-409f-a40d-cd91843a0311','法輪道中大雨','項安世','宋','宋诗','song-poetry','','[]','淋浪翻一雨，拳局下層坡。',48,'全唐诗/poet.song.146000.json','["淋浪翻一雨，拳局下層坡。", "險盡平川出，村寬古屋多。", "風烟隨地闢，鷄犬覺聲和。", "田父正愁思，天陰難刈禾。"]'),
('a0fea6ae-b7f3-49c8-a05a-258f38798906','次韻王少清寒食感舊','項安世','宋','宋诗','song-poetry','','[]','愛酒王郎子，愁來日日中。',48,'全唐诗/poet.song.146000.json','["愛酒王郎子，愁來日日中。", "都門空舊觀，楚俗自鄉風。", "客裏寒無奈，年時事不同。", "新裁羅袖薄，還向寶臺烘。"]'),
('edc0a500-db9b-4bf7-9605-412f1eecab23','王少清歸蜀不成復下鄂渚詩','項安世','宋','宋诗','song-poetry','','[]','行止不可計，別離當奈何。',48,'全唐诗/poet.song.146000.json','["行止不可計，別離當奈何。", "賦歸重作客，欲泝竟沿波。", "湖上橘方熟，洲邊魚正多。", "西山舊相識，不厭屢經過。"]'),
('71bea207-ee15-4c4c-bd93-3ad61e9dc05f','次韻李校書賀張部門除寺簿詩','項安世','宋','宋诗','song-poetry','','[]','酷愛陶元亮，生憎庾子山。',48,'全唐诗/poet.song.146000.json','["酷愛陶元亮，生憎庾子山。", "盃中今兀兀，鏡裏昔斑斑。", "願子飛騰速，容予浩蕩閒。", "他時江海上，莫遣尺書慳。"]'),
('21c1a0e5-7854-4b77-9487-87e3e304b664','澹山岩遇雨二首  其一','項安世','宋','宋诗','song-poetry','','[]','水放沙痕出，雲將晚色昏。',48,'全唐诗/poet.song.146000.json','["水放沙痕出，雲將晚色昏。", "微茫上西渡，浩蕩出南門。", "欹側緣山罅，嵌空下石根。", "書崖無數墨，入寺兩山髠。"]'),
('b5a90abd-6cd1-4b79-83be-2843b13a4f03','澹山岩遇雨二首  其二','項安世','宋','宋诗','song-poetry','','[]','山神從狡獪，心賞莫蹉跎。',48,'全唐诗/poet.song.146000.json','["山神從狡獪，心賞莫蹉跎。", "况近茱萸節，懸知風雨多。", "不衝新潤去，將奈積陰何。", "相戒添裘褐，排雲入薜蘿。"]'),
('614aaf6e-8f5a-40af-9931-fac6c70cce5d','雨止','項安世','宋','宋诗','song-poetry','','[]','客子浪相驚，山靈自有情。',48,'全唐诗/poet.song.146000.json','["客子浪相驚，山靈自有情。", "雲深一夜雨，風急五更晴。", "餘潤翻宜暑，微乾不礙行。", "柘林秋色裏，時復一蟬聲。"]'),
('dd373ce3-6a09-43f7-8ec3-38c1dee887d5','分宜縣','項安世','宋','宋诗','song-poetry','','[]','郭內清溪響，溪南列岫光。',48,'全唐诗/poet.song.146000.json','["郭內清溪響，溪南列岫光。", "林花千樹白，嶼柳一川黄。", "野店明丹堊，郵籤列短長。", "先生心愛此，車過未須忙。"]'),
('3e2fa003-104a-45dd-9b7f-99da417d8514','次韻謝臨川梁知縣寄詩','項安世','宋','宋诗','song-poetry','','[]','友散萍分浪，師亡木拱阡。',48,'全唐诗/poet.song.146000.json','["友散萍分浪，師亡木拱阡。", "年深多棄井，道遠欠加鞭。", "不寐思同社，何時共一廛。", "瑟琴希舊曲，雲淡覓前川。"]'),
('0e5bcde9-32c0-451b-b597-c791a612d7c1','次韻答任貢父見寄三首  其一','項安世','宋','宋诗','song-poetry','','[]','千金懸蠆尾，一柱兀波心。',48,'全唐诗/poet.song.146000.json','["千金懸蠆尾，一柱兀波心。", "吾道今如此，微生力未禁。", "正須公等助，莫廢別來吟。", "拄杖當分付，相期化鄧林。"]'),
('fd366442-47fe-43c1-865b-e4f1329bc643','次韻答任貢父見寄三首  其二','項安世','宋','宋诗','song-poetry','','[]','有情方是物，無敬莫言誠。',48,'全唐诗/poet.song.146000.json','["有情方是物，無敬莫言誠。", "此事非俄測，由來只自成。", "箇中勤積累，熟處會分明。", "未厭拘攣隘，他時滿八瀛。"]'),
('a1a34f22-c9da-4796-b865-28e362e68fd6','次韻答任貢父見寄三首  其三','項安世','宋','宋诗','song-poetry','','[]','日者人間世，家傳洛下書。',48,'全唐诗/poet.song.146000.json','["日者人間世，家傳洛下書。", "誰能定真實，轉覺墮空虛。", "莫倚文無害，常懷行有餘。", "詞華非所欠，水溢自成渠。"]'),
('14b570bb-c235-4857-98c1-9101c0489971','晚步  其一','項安世','宋','宋诗','song-poetry','','[]','晚飯下前墀，徐行出短籬。',48,'全唐诗/poet.song.146000.json','["晚飯下前墀，徐行出短籬。", "輕風吹面處，斜日倚門時。", "靜見雲舒卷，閒知草盛衰。", "放懷無一事，隨意得新詩。"]'),
('a950a2f4-9e94-46b0-b04e-b2079b0d2dcf','晚步  其二','項安世','宋','宋诗','song-poetry','','[]','市隘初回暑，庭空得晚行。',48,'全唐诗/poet.song.146000.json','["市隘初回暑，庭空得晚行。", "薄雲天半露，凉月夜全明。", "露下葛巾重，風來紈扇輕。", "翛然疑物表，與世不相嬰。"]'),
('20367fb4-0d5b-41b1-b653-c868621dc162','山農','項安世','宋','宋诗','song-poetry','','[]','江上見山農，畬田用火攻。',48,'全唐诗/poet.song.146000.json','["江上見山農，畬田用火攻。", "鼓聲爲號令，竹援當畿封。", "生理猿猱似，年華豆粟供。", "無功隨薄祿，愧汝若爲容。"]'),
('38e063ea-9a67-415d-81e2-400d93fbc512','秋潦','項安世','宋','宋诗','song-poetry','','[]','秋潦乃逢社，天寒更積陰。',48,'全唐诗/poet.song.146000.json','["秋潦乃逢社，天寒更積陰。", "雨聲便睡美，風色喚杯深。", "穀穗泥生耳，田家痛切心。", "饑人來市少，城邑亦蕭森。"]'),
('759ad76d-d0eb-43f7-b329-fc153d97ba12','乘月入城','項安世','宋','宋诗','song-poetry','','[]','水落千原浄，天高七澤空。',48,'全唐诗/poet.song.146000.json','["水落千原浄，天高七澤空。", "征人秋色裏，騎馬月明中。", "故國山川在，承平氣象雄。", "西風多感慨，敲損玉玲瓏。"]'),
('6e55da4c-96c3-40dc-b07d-8e4e4d4bcb5e','送虞司理赴官辰州二首  其一','項安世','宋','宋诗','song-poetry','','[]','窈窈辰溪路，秦人此避秦。',48,'全唐诗/poet.song.146000.json','["窈窈辰溪路，秦人此避秦。", "子孫爲洞戶，世系本王民。", "問淑桑鴞變，言忠黍貊親。", "此心能勿捨，何地不歸仁。"]'),
('2d49c2eb-5b56-4117-b89b-54c7a6038d41','送虞司理赴官辰州二首  其二','項安世','宋','宋诗','song-poetry','','[]','當年有虞氏，初作理官名。',48,'全唐诗/poet.song.146000.json','["當年有虞氏，初作理官名。", "正以蠻兼寇，須煩允與明。", "雲孫今筮仕，溪子正稱兵。", "淑問端能繼，淮夷不足平。"]'),
('6e017515-a410-47d8-a5ae-faea4b29489e','次韻胡撫幹再雪詩每句寓再字仍用汝陰詩禁  其一','項安世','宋','宋诗','song-poetry','','[]','積疑茶井實，高恐劍峰平。',48,'全唐诗/poet.song.146000.json','["積疑茶井實，高恐劍峰平。", "星暗楚雙路，津迷洛兩生。", "隨風來不斷，洊水凍無聲。", "已覺一爲甚，更堪三後行。"]'),
('225a6d2a-3e0a-4804-988f-c9f9c1147439','次韻胡撫幹再雪詩每句寓再字仍用汝陰詩禁  其二','項安世','宋','宋诗','song-poetry','','[]','力減沙頭酒，情添漢浦神。',48,'全唐诗/poet.song.146000.json','["力減沙頭酒，情添漢浦神。", "有歧俱可可，無鬢不新新。", "淮蔡層城夜，元和二月春。", "遥瞻雙闕賀，難預合班人。"]'),
('9c2b5481-62ee-423c-8b53-162e5bb84826','三雪詩用前韻寓三字  其一','項安世','宋','宋诗','song-poetry','','[]','令月濃于耜，豐年兆太平。',48,'全唐诗/poet.song.146000.json','["令月濃于耜，豐年兆太平。", "片飛何粲者，磈落太麤生。", "薛鳳崩騰勢，巫猿寂寞聲。", "冰溪無豕渡，樵路有人行。"]'),
('e01d4fd7-a09d-419c-9c93-4a069ce2fdc2','三雪詩用前韻寓三字  其二','項安世','宋','宋诗','song-poetry','','[]','巴峽疑無路，蓬山似有神。',48,'全唐诗/poet.song.146000.json','["巴峽疑無路，蓬山似有神。", "極涵天地混，光助日星新。", "開拓大千界，鋪張九十春。", "閉門經幾日，饑殺咽螬人。"]'),
('5f7cf0a5-6458-4609-97e3-4b8aaed7cc55','四雪詩用前韻寓四字  其一','項安世','宋','宋诗','song-poetry','','[]','皓景連辛甲，寒歌遍仄平。',48,'全唐诗/poet.song.146000.json','["皓景連辛甲，寒歌遍仄平。", "會同符盛治，假合類浮生。", "境變西山色，詩翻郢曲新。", "且隨車角住，休趁馬蹄行。"]'),
('cf119f26-8a67-4c9f-8099-be844a045b51','四雪詩用前韻寓四字  其二','項安世','宋','宋诗','song-poetry','','[]','氣用乾陽壯，雲興初望神。',48,'全唐诗/poet.song.146000.json','["氣用乾陽壯，雲興初望神。", "瀆流連夜剪，澤草萬花新。", "暮夜翻疑曉，冬郊總是春。", "皇皇天一色，穆穆逕無人。"]'),
('d69926cf-7309-4393-bcc8-3559eca535fa','五雪詩用前韻寓五字  其一','項安世','宋','宋诗','song-poetry','','[]','偪塞天星近，紛綸世事平。',48,'全唐诗/poet.song.146000.json','["偪塞天星近，紛綸世事平。", "瘴消原穀長，蝗死嶽芝生。", "徑合迷車轍，宵明誤鼓聲。", "袴寒空數挽，屨綻莫深行。"]'),
('d1f87696-8d79-44cc-9fea-0c35fbb53d70','五雪詩用前韻寓五字  其二','項安世','宋','宋诗','song-poetry','','[]','眼看山城老，心經木有神。',48,'全唐诗/poet.song.146000.json','["眼看山城老，心經木有神。", "燕臺六月舊，粵嶺一冬新。", "色映康衢色，花沾綵服春。", "瑞多休更輯，禹甸有窮人。"]'),
('f24b34a1-452a-4eac-b308-6e83df7980a1','六雪詩用前韻寓六字  其一','項安世','宋','宋诗','song-poetry','','[]','點點多難賽，蚩蚩勢欲平。',48,'全唐诗/poet.song.146000.json','["點點多難賽，蚩蚩勢欲平。", "羣排風鷁退，深掩燭龍生。", "鄉混群庬吠，軍喧亂鶩聲。", "光陰乘歲暮，威令極施行。"]'),
('594e7134-1d1c-4ee2-afb6-f667a15f8941','六雪詩用前韻寓六字  其二','項安世','宋','宋诗','song-poetry','','[]','天宗興歲事，滕叟盛威神。',48,'全唐诗/poet.song.146000.json','["天宗興歲事，滕叟盛威神。", "樂羽朱成素，宮牆舊變新。", "周爻方用坎，燕律遽生春。", "花陣連天出，歡回合宇人。"]'),
('485c3e39-bc36-4df3-aa5a-487310d1d1f2','雪晴','項安世','宋','宋诗','song-poetry','','[]','煜煜陽光動，欣欣客意寬。',48,'全唐诗/poet.song.146000.json','["煜煜陽光動，欣欣客意寬。", "雪消田已潤，霜重露仍乾。", "半世長行脚，經年未解鞍。", "管晴兼管雨，何日得心安。"]'),
('13912b0f-87f5-4bce-847e-ae7537a77329','次韻歲暮對雪書懷','項安世','宋','宋诗','song-poetry','','[]','問寢荆江上，留家湘水濱。',48,'全唐诗/poet.song.146000.json','["問寢荆江上，留家湘水濱。", "心關兩處念，鬢改一年新。", "屑玉逢天富，鋪瑶蓋地貧。", "歸來見三白，因得賀鄉人。"]'),
('987945ba-302a-4562-84e7-f4c4374488ff','寄韓丈','項安世','宋','宋诗','song-poetry','','[]','送別扁舟上，相望一水間。',48,'全唐诗/poet.song.146000.json','["送別扁舟上，相望一水間。", "酒杯思共把，棋局定長閒。", "雅量容陂闊，私心豈石頑。", "夢隨漚鳥去，時過紫金山。"]'),
('14279229-4098-4097-89fa-ff9240334cb2','寄潘致虛','項安世','宋','宋诗','song-poetry','','[]','長憶潘居士，相望今幾州。',48,'全唐诗/poet.song.146000.json','["長憶潘居士，相望今幾州。", "生涯溫飽未，故舊往還不。", "問訊憑雙鯉，觀身渺一漚。", "湖南元好住，吾欲具扁舟。"]'),
('46aaffeb-346f-4639-a5bc-8ddd18f652e0','次韻答羅鄂州二首  其一','項安世','宋','宋诗','song-poetry','','[]','相望纔信宿，一出尚徘徊。',48,'全唐诗/poet.song.146000.json','["相望纔信宿，一出尚徘徊。", "誰謂堅高處，真成竭蹷來。", "人情傷蹭蹬，學力諱遲回。", "欲火焚林去，如何水一杯。"]'),
('79320111-1b95-4f19-b343-5cabd0103a46','次韻答羅鄂州二首  其二','項安世','宋','宋诗','song-poetry','','[]','任重心長在，年侵力未堪。',48,'全唐诗/poet.song.146000.json','["任重心長在，年侵力未堪。", "聖賢憎獨學，老宿幸同參。", "已信乾坤藴，無踰孔孟談。", "誰能中道廢，長使一生慚。"]'),
('4697e639-6013-4036-af00-976c80e9668b','送周明叔從陳運使東歸得能字','項安世','宋','宋诗','song-poetry','','[]','無分向師友，有誰知我能。',48,'全唐诗/poet.song.146000.json','["無分向師友，有誰知我能。", "只看他日說，謾道此時曾。", "酒莫從人强，身須更上層。", "明朝雙鬢髮，那更綠鬅鬙。"]'),
('b46f8f61-c55c-4c47-89d0-f4a59f519663','酬襄陽儲檢法','項安世','宋','宋诗','song-poetry','','[]','客子朝莫去，相過能幾回。',48,'全唐诗/poet.song.146000.json','["客子朝莫去，相過能幾回。", "少留貪快論，多病畏深盃。", "年少難量在，天姿信美哉。", "短檠三萬卷，莫待老相催。"]'),
('fb670d2f-c441-4afb-84ec-5de63976224a','次韻儲檢法帷字','項安世','宋','宋诗','song-poetry','','[]','歲月客中老，交遊天下奇。',48,'全唐诗/poet.song.146000.json','["歲月客中老，交遊天下奇。", "衰州訪人物，臺法妙天姿。", "年事真堪惜，人情莫浪隨。", "青春能幾許，綠葉看成帷。"]'),
('09eb94eb-d4c6-4eab-9c3c-939471be3ee1','次韻江陵張撫幹送行二首  其一','項安世','宋','宋诗','song-poetry','','[]','戍瓜違首夏，行李傍中秋。',48,'全唐诗/poet.song.146000.json','["戍瓜違首夏，行李傍中秋。", "此意元衰懶，吾生足滯留。", "竹枝看峽舞，月子聽吳謳。", "官况能多少，栖栖一世愁。"]'),
('aa002b39-0e4a-4bb7-938f-68855991304f','次韻江陵張撫幹送行二首  其二','項安世','宋','宋诗','song-poetry','','[]','蕭蕭青草岸，籊籊釣魚竿。',48,'全唐诗/poet.song.146000.json','["蕭蕭青草岸，籊籊釣魚竿。", "此地規逃世，傍人誤喚官。", "夏凉眠麓寺，春晚戲雩壇。", "却笑平生謬，崎嶇自作難。"]'),
('fa17ce95-6471-4bf0-befc-4a70435dc223','贈趙撫幹','項安世','宋','宋诗','song-poetry','','[]','龍種生來別，交情久更歡。',48,'全唐诗/poet.song.146000.json','["龍種生來別，交情久更歡。", "四年三入幕，一任兩同官。", "安定詩成軸，揚雲墨未乾。", "一聞磨衲句，如對畫圖看。"]'),
('1003a8ef-f631-45c9-adc0-5eea3dff0682','風雨望武昌岸','項安世','宋','宋诗','song-poetry','','[]','寒食今朝是，顛風半夜來。',48,'全唐诗/poet.song.146000.json','["寒食今朝是，顛風半夜來。", "自從天色暖，已遣客心猜。", "雨打洲容沐，烟籠水面灰。", "孫郎將漫叟，相送到浯臺。"]'),
('7e407ac3-9367-46f5-b567-80545d442709','夜泛湘江','項安世','宋','宋诗','song-poetry','','[]','窈窈崖頭黑，沉沉水面青。',48,'全唐诗/poet.song.146000.json','["窈窈崖頭黑，沉沉水面青。", "楓林嘯山鬼，竹月下湘靈。", "欵乃元郎曲，離騷屈子經。", "欲知當日意，須向此中聽。"]'),
('965bd513-41c2-45ba-a08c-59df128d8b5a','次韻吳少保雄楚樓','項安世','宋','宋诗','song-poetry','','[]','傑觀攙天出，懽聲動地遊。',48,'全唐诗/poet.song.146000.json','["傑觀攙天出，懽聲動地遊。", "簷開六千里，檻納九十洲。", "正以心期勝，居然眼法優。", "百年經幾牧，今日見斯樓。"]'),
('3c5aac6f-e91e-43d9-9f15-3b2a004572e3','又次韻少保雄楚樓席上','項安世','宋','宋诗','song-poetry','','[]','炷香秋色裏，落筆翠微間。',48,'全唐诗/poet.song.146000.json','["炷香秋色裏，落筆翠微間。", "八九開雲土，毫芒見峽山。", "水花光似拭，幽鳥語如蠻。", "不分荆州牧，全勝寓客閒。"]'),
('bc90ac9b-74d3-473e-bd18-a8d493250745','新月','項安世','宋','宋诗','song-poetry','','[]','臨風摇白羽，揖月問仙娥。',48,'全唐诗/poet.song.146000.json','["臨風摇白羽，揖月問仙娥。", "底事偏懷恨，于人故歛蛾。", "眉頭已如此，眼底奈渠何。", "料得中秋夜，動人應更多。"]'),
('508e71f1-013a-43b8-b5a0-747340d746fa','見雁','項安世','宋','宋诗','song-poetry','','[]','萬古胡沙雁，衡陽到即回。',48,'全唐诗/poet.song.146000.json','["萬古胡沙雁，衡陽到即回。", "如何九日至，故作永州來。", "節裏他鄉客，江邊獨夜桅。", "吾親應念我，煩汝到浯臺。"]'),
('c195fb9f-0222-4d2d-8a6b-9d084e264b15','遊延慶寺','項安世','宋','宋诗','song-poetry','','[]','急雨瀧危石，橫雲燾古碑。',48,'全唐诗/poet.song.146000.json','["急雨瀧危石，橫雲燾古碑。", "入山芒屨濕，歸路角巾欹。", "中濕連宵病，平生此段奇。", "只今酬妙句，猶自愛當時。"]'),
('d0e2aad4-acb5-4f2a-80b1-bd90a5d90b2d','約同行至浯溪作重九','項安世','宋','宋诗','song-poetry','','[]','九日明朝是，三浯自古高。',48,'全唐诗/poet.song.146000.json','["九日明朝是，三浯自古高。", "地能供此景，天亦念吾曹。", "溪上風宜帽，山中菊可醪。", "病夫雖不飲，短髮却堪搔。"]'),
('29778e4f-d0e2-4f70-b434-4aa43c0c6716','將至浯溪簡同行','項安世','宋','宋诗','song-poetry','','[]','地想浯溪近，舟逢怪石多。',48,'全唐诗/poet.song.146000.json','["地想浯溪近，舟逢怪石多。", "平生真到此，重九合如何。", "我解伊吾讀，君能欵乃歌。", "風從兩崖下，江水忽生波。"]'),
('db5d965b-c325-4cdc-a97d-57b5f48725b6','重陽','項安世','宋','宋诗','song-poetry','','[]','客裏逢重九，匆匆惜歲華。',48,'全唐诗/poet.song.146000.json','["客裏逢重九，匆匆惜歲華。", "籃輿上寒嵼，烏帽或欹斜。", "物態如相向，村醪幸免賒。", "山深不見菊，蕎麥正多花。"]'),
('ce49ddfc-1a88-4f27-bdad-f7769f3da804','自合州出陸所至例借宅宿食略無齟齬聞兩川皆然至利夔路則齗齗不可矣','項安世','宋','宋诗','song-poetry','','[]','此土有善俗，江湖人未知。',48,'全唐诗/poet.song.146000.json','["此土有善俗，江湖人未知。", "過門隨所謁，借宅總相宜。", "閴靜疑無主，餐眠遂及時。", "客賓俱自愛，不敢壞藩籬。"]'),
('e01a19fd-6c8d-4f70-b195-b02dd801ae37','茱萸茶','項安世','宋','宋诗','song-poetry','','[]','城郭千山隘，晨昏二氣并。',48,'全唐诗/poet.song.146000.json','["城郭千山隘，晨昏二氣并。", "乍如冰底宿，忽似甑中行。", "蚯蚓方雄長，茱萸可扞城。", "龍團寧小忍，異味且同傾。"]'),
('e5a8c19b-3c59-423a-9d88-15507eb76b4e','谷山照僧能詩事母孝','項安世','宋','宋诗','song-poetry','','[]','照公詩甚清，月淡更雲輕。',48,'全唐诗/poet.song.146000.json','["照公詩甚清，月淡更雲輕。", "拂拂晴絲卷，霏霏柳絮縈。", "我憎禪悖性，渠自孝鍾情。", "何似辭戎索，中原道上行。"]'),
('e80b307d-23f1-4b06-a02c-151309351daa','僧了仙携馬太守唱和求詩  其一','項安世','宋','宋诗','song-poetry','','[]','故國巴山裏，寒砧楚戶邊。',48,'全唐诗/poet.song.146000.json','["故國巴山裏，寒砧楚戶邊。", "上人名籍籍，刺史札翩翩。", "世有羞儒服，吾方厭俗緣。", "更須求愈輩，章句待磨研。"]'),
('d8b13f76-e4a8-4269-8e71-3f0571ff09ba','僧了仙携馬太守唱和求詩  其二','項安世','宋','宋诗','song-poetry','','[]','世態家鷄厭，人情外物牽。',48,'全唐诗/poet.song.146000.json','["世態家鷄厭，人情外物牽。", "僧來求我句，人去覓僧禪。", "語綺翻成業，談空未免筌。", "不須生許事，留眼看青天。"]'),
('4b9e9032-72da-4def-808f-ecea35d6ad6c','送劉坰登第赴調二首  其一','項安世','宋','宋诗','song-poetry','','[]','昔在中朝日，長懷隻影傷。',48,'全唐诗/poet.song.146000.json','["昔在中朝日，長懷隻影傷。", "逢人盡吳蜀，無伴說荆襄。", "千古卿材地，多年世論忘。", "因君到雲路，江漢不凄凉。"]'),
('18a764a8-86c0-48c5-b03d-ffe489d60b35','送劉坰登第赴調二首  其二','項安世','宋','宋诗','song-poetry','','[]','我老愚難改，年深病不瘳。',48,'全唐诗/poet.song.146000.json','["我老愚難改，年深病不瘳。", "鄉閭仗才雋，科甲慰窮愁。", "拾芥雖堪喜，看花且莫留。", "歸來修遠業，可以張吾州。"]'),
('ba121bf5-dad2-4f00-9d7b-17609701d0bb','呈羅機宜','項安世','宋','宋诗','song-poetry','','[]','抗己憂爲的，咸腓懼喪躬。',48,'全唐诗/poet.song.146000.json','["抗己憂爲的，咸腓懼喪躬。", "自從夫子學，始見古人風。", "有直終爲訐，能和乃不同。", "從今師下惠，一瓣敢忘公。"]'),
('4a4f58e0-a282-422c-a1ad-3d25aa6e5bf1','寒塘洑望黄羆嶺','項安世','宋','宋诗','song-poetry','','[]','憶上黄羆嶺，年時白汗傾。',48,'全唐诗/poet.song.146000.json','["憶上黄羆嶺，年時白汗傾。", "如今青箬底，卧看黑雲生。", "山骨穿江過，巖頭夾岸獰。", "似嗔舟楫駛，故作石灘鳴。"]'),
('2e279d18-6b96-4908-ba8a-bfb9e240fa5f','孱陵道中','項安世','宋','宋诗','song-poetry','','[]','草冷霜融晚，天寒日出遲。',48,'全唐诗/poet.song.146000.json','["草冷霜融晚，天寒日出遲。", "亂鴉鳴古柳，獨犬吠疎籬。", "歲暮方爲客，身閒豈有期。", "一生村疃裏，羨殺牧牛兒。"]'),
('ecd7a441-212b-4146-803a-690606269cb1','夜坐','項安世','宋','宋诗','song-poetry','','[]','天寒人倍爽，夜靜雨初喧。',48,'全唐诗/poet.song.146000.json','["天寒人倍爽，夜靜雨初喧。", "舊稿詩重定，新編手自繙。", "相親燈不厭，共坐意忘言。", "獨笑重城裏，千家正夢魂。"]'),
('dfa13e1b-ad15-439e-8e18-4404dd5cb05e','除夕宿武陵邸中','項安世','宋','宋诗','song-poetry','','[]','除夕仍爲客，今年脚不停。',48,'全唐诗/poet.song.146000.json','["除夕仍爲客，今年脚不停。", "分身三處夢，共影兩同行。", "諸子依潭橘，雙親滯楚萍。", "此時灰一寸，明日雪千莖。"]'),
('292a2ce1-71d2-41c3-bf08-d30beca2103d','古樟書堂','項安世','宋','宋诗','song-poetry','','[]','問訊書堂士，門前有古樟。',48,'全唐诗/poet.song.146000.json','["問訊書堂士，門前有古樟。", "植根深入地，盤勢闊連岡。", "霧合琴書潤，風來硯席凉。", "試賡雲下曲，餘韻遶琳琅。"]'),
('8f20f443-d705-491d-8b66-6bf940695234','南康軍寓居','項安世','宋','宋诗','song-poetry','','[]','檥岸逢重九，全家上淺山。',48,'全唐诗/poet.song.146000.json','["檥岸逢重九，全家上淺山。", "兒童爭險步，城郭有躋攀。", "采菊迷前路，開樽對近灣。", "年時吹帽處，不見雁書還。"]'),
('33020fb2-0246-4960-bf4c-56172439f96f','和揭尉冬至韻','項安世','宋','宋诗','song-poetry','','[]','自古珍斯日，留機與世窺。',48,'全唐诗/poet.song.146000.json','["自古珍斯日，留機與世窺。", "不因冬有至，誰識道之涯。", "一點陽初動，千山木未知。", "此時俄已復，端的更由誰。"]'),
('aca21c15-b357-49f3-ac8e-016ed76afa2f','都下呈叔表兄','項安世','宋','宋诗','song-poetry','','[]','相望五千里，話別十三年。',48,'全唐诗/poet.song.146000.json','["相望五千里，話別十三年。", "知我到江左，煩兄來日邊。", "朋遊俱健否，鬚髮已卷然。", "共說兒童事，分明在目前。"]'),
('10ef734c-793c-4ec6-8e45-39250c25536c','寒食風雨中過南湖','項安世','宋','宋诗','song-poetry','','[]','風雨春無緒，人家食併寒。',48,'全唐诗/poet.song.146000.json','["風雨春無緒，人家食併寒。", "一年佳節過，五字小詩難。", "開戶桃花笑，傾盃竹葉乾。", "聽人談異俗，爲爾慰愁端。"]'),
('d8a996d2-4fed-4327-a106-12cc3b0e8642','次韻沈告院問訊南湖','項安世','宋','宋诗','song-poetry','','[]','欲問南湖事，南湖事若何。',48,'全唐诗/poet.song.146000.json','["欲問南湖事，南湖事若何。", "主人新鳸正，風物舊漚波。", "綠髮深深柳，嬌鈿細細荷。", "檻虛宜鬭鴨，船過莫驚鵝。"]'),
('741e0c86-1a3a-4407-8672-62ff6a10460b','塘上遇雨','項安世','宋','宋诗','song-poetry','','[]','雨入湖心路，烟昏酒市樓。',48,'全唐诗/poet.song.146000.json','["雨入湖心路，烟昏酒市樓。", "驚飛花鴨閙，癡立白鵝愁。", "菰葉如相倚，楊枝不自由。", "猛思拋轎板，渾欲上漁舟。"]'),
('51d72767-b17d-4d31-9b45-37cc202ae456','石塘','項安世','宋','宋诗','song-poetry','','[]','市夾河漘好，橋當浦口雄。',48,'全唐诗/poet.song.146000.json','["市夾河漘好，橋當浦口雄。", "濕雲低障日，斜雨急收風。", "石岸蜿蜒去，松江杳靄中。", "知幾吾晚矣，慚汗過垂虹。"]'),
('47abfd83-0580-4064-ac45-1afdd70db6b2','重五聽談昨夢','項安世','宋','宋诗','song-poetry','','[]','節裏聽兒輩，杯行話日期。',48,'全唐诗/poet.song.146000.json','["節裏聽兒輩，杯行話日期。", "別來三剝粽，憶著四頒衣。", "久病忘前後，斯言果是非。", "只疑清夜夢，曾到九門歸。"]'),
('523e079b-9c35-4d13-b6e9-223e12d88fa1','八日丹陽相遇','項安世','宋','宋诗','song-poetry','','[]','舟楫庭闈近，衣裳步武輕。',48,'全唐诗/poet.song.146000.json','["舟楫庭闈近，衣裳步武輕。", "逆風猶作態，寒日爲開晴。", "獨客天邊住，全家水面行。", "今朝逢一笑，此樂冠生平。"]'),
('381db9d5-126a-4bfa-b318-c6035827771a','夏夜入城','項安世','宋','宋诗','song-poetry','','[]','巾櫛侵殘夜，衣裳謁上官。',48,'全唐诗/poet.song.146000.json','["巾櫛侵殘夜，衣裳謁上官。", "市心偏得熱，堤面自生寒。", "水闊江湖小，川平象緯寬。", "籃輿得佳夢，摇兀又驚殘。"]'),
('1e7b5cc9-5e69-42c7-825b-5b6873ed28ac','次前韻招鄭檢法','項安世','宋','宋诗','song-poetry','','[]','人健萸真好，尊開菊自知。',48,'全唐诗/poet.song.146000.json','["人健萸真好，尊開菊自知。", "無聊念前日，一笑及斯時。", "高處雲如帽，愁邊雨欲絲。", "能來紙窗底，相伴賦新詩。"]'),
('b2a9a10d-3638-47e9-a824-51186b683565','大人生朝代諸兒五首以春風花草香爲韻  其一','項安世','宋','宋诗','song-poetry','','[]','何物堪爲壽，南華有大椿。',48,'全唐诗/poet.song.146000.json','["何物堪爲壽，南華有大椿。", "根株天地遠，枝葉歲時新。", "十倍大彭國，百分清渭濱。", "周星八千度，纔是一番春。"]'),
('13ead929-87aa-40b7-90d1-5d934a3a2312','大人生朝代諸兒五首以春風花草香爲韻  其二','項安世','宋','宋诗','song-poetry','','[]','何物堪爲壽，巢龜碧玉筒。',48,'全唐诗/poet.song.146000.json','["何物堪爲壽，巢龜碧玉筒。", "龍洲多藕葉，上蔡足蕭叢。", "日月供呼吸，乾坤共始終。", "年年冰凍解，綠髮戲春風。"]'),
('37f4ea2c-7ce9-45b6-af17-a145f65677ca','大人生朝代諸兒五首以春風花草香爲韻  其三','項安世','宋','宋诗','song-poetry','','[]','何物堪爲壽，蟠桃照海涯。',48,'全唐诗/poet.song.146000.json','["何物堪爲壽，蟠桃照海涯。", "栽培煩阿母，護守倩神荼。", "夏果收蕡實，春林炫纈花。", "等閑開結裏，塵世幾河沙。"]'),
('b1de638a-8a64-4b34-a9c7-e735ca983917','大人生朝代諸兒五首以春風花草香爲韻  其四','項安世','宋','宋诗','song-poetry','','[]','何物堪爲壽，清宵桂花好。',48,'全唐诗/poet.song.146000.json','["何物堪爲壽，清宵桂花好。", "月殿轉香風，雲根長瑶草。", "金爲碧海波，玉作青天道。", "萬古鎮扶疎，不逐秋風老。"]'),
('c7fd75bf-f293-40ed-bab6-ad2000e99366','大人生朝代諸兒五首以春風花草香爲韻  其五','項安世','宋','宋诗','song-poetry','','[]','何物堪爲壽，春山鶴算長。',48,'全唐诗/poet.song.146000.json','["何物堪爲壽，春山鶴算長。", "雲邊風馭穩，松上露巢香。", "頂浴丹砂潤，翎梳白玉光。", "寶圖雙象轉，長在壽星傍。"]'),
('8a3900dd-2b1d-4b57-a5a6-2ca1880a1419','用韻爲十六弟壽','項安世','宋','宋诗','song-poetry','','[]','南極星中老，朱陵洞裏仙。',48,'全唐诗/poet.song.146000.json','["南極星中老，朱陵洞裏仙。", "相呼乘大夏，抱出送高賢。", "八莢蓂垂地，初弦桂拂天。", "它時南宛路，此日正開筵。"]'),
('a17fb1f2-aae7-4038-b529-6cd56b286f18','次韻謝唐先生惠得','項安世','宋','宋诗','song-poetry','','[]','後進魯諸生，斯文久服膺。',120,'全唐诗/poet.song.146000.json','["後進魯諸生，斯文久服膺。", "有心知映雪，何意望寒冰。", "粵嶠連屏秀，閩溪凈練澄。", "山川八州地，人物九霄鵬。", "樞坐鄰丹扆，魁星粲玉繩。", "風流方演迤，雲路好依乘。", "賦客遺孫在，詩壇老將登。", "踵門觀道德，命坐辱賓朋。", "貌古文相似，身貧道不曾。", "明珠一百顆，什襲永緘縢。"]'),
('f253ac07-e925-4e46-945f-19a3cfce212e','重午記俗八韻','項安世','宋','宋诗','song-poetry','','[]','菰飯沾花蜜，冰團裹蔗腴。',96,'全唐诗/poet.song.146000.json','["菰飯沾花蜜，冰團裹蔗腴。", "油淹枯茹滑，糟悶活鱗濡。", "餉篚爭門入，瘟船出市驅。", "屑蒲形武獸，編艾寫髯巫。", "朱揭橫楣牓，黄書闖戶符。", "辟邪釵篆蹙，解厄腕絲紆。", "惡月多憂畏，陰爻足備虞。", "更聞因屈子，冞動楚人吁。"]'),
('ad115e43-9104-45da-bbd1-057b387662c0','臘月一日詠雪二十韻簡潘都幹','項安世','宋','宋诗','song-poetry','','[]','忽見紛然墮，方驚甚矣衰。',240,'全唐诗/poet.song.146000.json','["忽見紛然墮，方驚甚矣衰。", "已拚蓬換鬢，其奈粟生肌。", "憶昔如黄犢，當軒塑白獅。", "踏模鞋透指，印貌面皴皮。", "衮作毬行地，團成燭照帷。", "簷冰充鐸振，盆凍當鉦搥。", "壯歲身仍健，邊城景又奇。", "高樓觀亂落，平野看橫吹。", "犬躍凌晨出，驄驕盡夜馳。", "三杯羞飲帳，百韻笑僵歧。", "往事今如夢，前歡竟是誰。", "非干爲客苦，不是罷官悲。", "溜響關門聽，階明映牖窺。", "探深時遣婢，嘬冷更防兒。", "喜婦添紅炭，娛親奉綠卮。", "不知戎幕出，何處蹇馿騎。", "上將分羔酒，諸軍擊鶩池。", "定須吟鐵甲，應不戀金絲。", "樵足鍾山頂，漁蓑淮水涯。", "金陵無限思，有底句來遲。"]'),
('dd9ef46e-46db-496a-9177-d30f0a77323d','再作','項安世','宋','宋诗','song-poetry','','[]','遇物無汙潔，經林失盛衰。',240,'全唐诗/poet.song.146000.json','["遇物無汙潔，經林失盛衰。", "坐令磚似玉，立見髮如肌。", "烏化瑶池鶴，騅成石闕獅。", "傾都陳鷺翿，連野獵麑皮。", "山裹青螺髻，城張白鳳帷。", "佛宮迷鐵塔，御路翳金槌。", "旟旆紛斜整，駕鵝雜正奇。", "四絃穠李抹，三弄落梅吹。", "舊積新仍壓，前驅後更馳。", "舞狂寧俟拍，行亂不遵歧。", "揚布疑非我，何郎竟指誰。", "孔淄應不涅，墨素遂無悲。", "勇勢將門塞，纖形探隙窺。", "欹傾愁屋壁，踴躍羨童兒。", "蓋垤危翻甕，填坑駭擲卮。", "屐深知夜過，蹄淺認朝騎。", "凍合將平海，冰堅已實池。", "羲和光奪色，鳥雀命懸絲。", "後陣多難測，陰機遠莫涯。", "看雲方浩浩，望霽故遲遲。"]'),
('667c8b61-fefc-473f-a901-57eb9aac1647','賦李季允校書悅齋','項安世','宋','宋诗','song-poetry','','[]','紛華戰罷凱歌旋，絃誦聲中一莞然。',64,'全唐诗/poet.song.146000.json','["紛華戰罷凱歌旋，絃誦聲中一莞然。", "理義足時心有味，友朋深處澤無邊。", "沂雩綠水春風裏，江漢清秋暠日前。", "千五百年時習趣，祝君無倦到華顛。"]'),
('9cb5c8ac-2407-4359-8dce-4803bf65fe67','題瀟湘霽雨圖','項安世','宋','宋诗','song-poetry','','[]','欲斂未斂雲溶溶，似見未見山矓矓。',64,'全唐诗/poet.song.146000.json','["欲斂未斂雲溶溶，似見未見山矓矓。", "人家遠近半衡宇，草樹高低深佛宮。", "西峰定有一罅日，東嶺豈無千丈虹。", "俗人不識莫與道，總在空濛蒼莽中。"]'),
('9b96aeb1-8c8b-42b9-a2c7-69252416cf76','次韻謝處州鄉人二首  其一','項安世','宋','宋诗','song-poetry','','[]','聽說江湖萬里身，十年流轉狎波神。',64,'全唐诗/poet.song.146000.json','["聽說江湖萬里身，十年流轉狎波神。", "鄉心只羨秋鷹急，世味如何臈蟻醇。", "耳識吳音疑故舊，眼看南士覺尖新。", "袖中詩句清如許，何啻他鄉見似人。"]'),
('19dc62f7-0ae6-4aad-ba7c-a7d3481bf117','次韻謝處州鄉人二首  其二','項安世','宋','宋诗','song-poetry','','[]','黄花和露作深秋，志士臨風惜壯猷。',64,'全唐诗/poet.song.146000.json','["黄花和露作深秋，志士臨風惜壯猷。", "靡靡道途空接淅，摇摇心事劇懸旒。", "兒時種木今盈抱，老去還家莫漫游。", "側耳鄉書上霄漢，聖朝賓貢似成周。"]'),
('0db87d4f-dea8-4c24-8551-aa2a5cfe6bfa','和陳待制江城畢工遇雪','項安世','宋','宋诗','song-poetry','','[]','魚釜鶉衣救叔寒，犧樽羊餼度姑山。',64,'全唐诗/poet.song.146000.json','["魚釜鶉衣救叔寒，犧樽羊餼度姑山。", "瑞花一夜圍青嶂，扶葉平明射白間。", "徧雨麥田知地瘠，怕冰戍土謝天慳。", "威稜迥出金湯外，十萬邊兵已北還。"]'),
('cdf6a2be-00ae-4182-bae8-ecba156c2546','阜陵復土詣重華奉慰遇雪不勝哀愴','項安世','宋','宋诗','song-poetry','','[]','龍胡九鍤閉玄扉，虎落千年護翠微。',64,'全唐诗/poet.song.146000.json','["龍胡九鍤閉玄扉，虎落千年護翠微。", "永阜凄凉成永夜，重華蕭瑟見重闈。", "雲迷八表俱愁思，雪滿千山盡素衣。", "更踏深泥南內去，紫宸殿下進名歸。"]'),
('f2647cb3-02d2-4a54-a224-8123371a3692','雪寒百司作暇獨入局觀雪簡張直閣','項安世','宋','宋诗','song-poetry','','[]','書生賦分合清愁，官與休辰不自休。',64,'全唐诗/poet.song.146000.json','["書生賦分合清愁，官與休辰不自休。", "特地忍寒開省署，誰家見雪似瀛洲。", "白銀殿閣雲中看，素李園林月下遊。", "說與南湖張秘閣，速來同直道山頭。"]'),
('f7a4b832-c070-4402-a936-190c1557ac63','周子問作蕎麥麵冷淘二首  其一','項安世','宋','宋诗','song-poetry','','[]','金魚玉带相公孫，不受膏粱貴氣吞。',64,'全唐诗/poet.song.146000.json','["金魚玉带相公孫，不受膏粱貴氣吞。", "忽喚寒儒共湯餠，翻疑晚飯過山村。", "舊聞鵝鴨高飛盡，却恐神仙大藥存。", "一夜夢魂秋坂裏，白花朱稈映柴門。"]'),
('9fc0abde-4f3d-4fec-965d-d2a84ed81f53','周子問作蕎麥麵冷淘二首  其二','項安世','宋','宋诗','song-poetry','','[]','調笑何郎莫漫嫌，一杯爲洗太官羶。',64,'全唐诗/poet.song.146000.json','["調笑何郎莫漫嫌，一杯爲洗太官羶。", "品題今自東湖始，湯沐新封羹頡邊。", "短制牙籌防易斷，半和麰粉借微堅。", "山鷄雋永堪司薦，豈是從來野性便。"]'),
('8268ab52-3a5a-4523-9fa2-c8b195eac9e2','題劉都幹所藏楊祕監詩卷','項安世','宋','宋诗','song-poetry','','[]','我雖未識誠齋面，道得誠齋句裏心。',64,'全唐诗/poet.song.146000.json','["我雖未識誠齋面，道得誠齋句裏心。", "醉語夢書辭總巧，生擒活捉力都任。", "雄吞詩界前無古，新創文機獨有今。", "肯爲小山題短紙，自家元愛晚唐吟。"]'),
('6023284e-4530-4a55-bfc5-1f2b6643d0ce','次韻高秀才借觀襄郢詩卷','項安世','宋','宋诗','song-poetry','','[]','先生鍊句本無奇，信筆閑題總是詩。',64,'全唐诗/poet.song.146000.json','["先生鍊句本無奇，信筆閑題總是詩。", "或似村歌聞野店，又如神筆降叢祠。", "大篇寫處誰能改，好句忘來亦不追。", "喚作吟哦君自誤，是儂襄郢縱談時。"]'),
('5759626c-5342-4df0-9683-c5daef81288b','次韻王少清索崔柬之詩卷','項安世','宋','宋诗','song-poetry','','[]','自古崔盧族望榮，至今王謝好家聲。',64,'全唐诗/poet.song.146000.json','["自古崔盧族望榮，至今王謝好家聲。", "子孫一一過人遠，文字篇篇翻水成。", "異縣相逢俱似舊，新詩傳示總能清。", "憑將惡語同收取，杜集他年著我名。"]'),
('698d28d7-7d0a-4890-a1c5-6fef645fb086','二日至襄陽詩卷爲偷兒持去','項安世','宋','宋诗','song-poetry','','[]','華黍詩亡更自珍，銀盃羽化未須嗔。',64,'全唐诗/poet.song.146000.json','["華黍詩亡更自珍，銀盃羽化未須嗔。", "不然雷電將天上，或者浮沉自水濱。", "鄭老本無氈可守，虎頭政恐畫能神。", "苦心只道無人愛，何物偷兒却可人。"]'),
('a7dcae7b-a795-4062-b2ce-b0f3d620ffd4','臘盡僅得微雪','項安世','宋','宋诗','song-poetry','','[]','窮冬一雪繫農心，籲佛祈仙望已深。',64,'全唐诗/poet.song.146000.json','["窮冬一雪繫農心，籲佛祈仙望已深。", "逾月亢晴生暑瘴，連朝霏霧作春陰。", "夜窗且喜風兼雨，曉瓦纔看粉共銀。", "可是江妃慳笑粲，都能無意管呻吟。"]'),
('eec94436-5452-47b8-be8d-fa1f85e57f69','十五夜雪','項安世','宋','宋诗','song-poetry','','[]','幸自封姨不敢嗔，放教月姊伴遊人。',64,'全唐诗/poet.song.146000.json','["幸自封姨不敢嗔，放教月姊伴遊人。", "不知滕六來何許，忽與天官競此辰。", "蓮焰撲殘惟種李，金波捲盡只鋪銀。", "玉皇應是憐堯父，不做元宵已四春。"]'),
('b0583cfb-609e-4d74-99e9-891c4a807763','次韻和胡仲方正月二十五日雪','項安世','宋','宋诗','song-poetry','','[]','減却濠溝厚却城，散如絲忽聚如京。',64,'全唐诗/poet.song.146000.json','["減却濠溝厚却城，散如絲忽聚如京。", "夜兼風勢千江立，曉借林花萬象榮。", "恃我柴門高卧穩，敵君竹閣醉吟清。", "長歌慷慨摇冰柱，至樂銜心未易名。"]'),
('68ee4046-958a-4675-947f-0134b01ede0e','對雪呈判府周丞相','項安世','宋','宋诗','song-poetry','','[]','燮調曾轉九重天，偃息何難十國連。',64,'全唐诗/poet.song.146000.json','["燮調曾轉九重天，偃息何難十國連。", "坐遣朝雲將朔雪，一清瘴雨與蠻烟。", "豐年預見寬心曲，儉俗能忘念目前。", "更想朝來窮巷裏，閉門高卧有遺賢。"]'),
('747ffb8d-c5ec-4692-b903-9cbdbb03234c','一日姑蘇懷古','項安世','宋','宋诗','song-poetry','','[]','披山臨水結層城，髣髴當年霸主情。',64,'全唐诗/poet.song.146000.json','["披山臨水結層城，髣髴當年霸主情。", "魚滿松江船似櫛，田連震澤稻如京。", "巍巍二老辭周籙，碌碌諸孫競晉盟。", "可但館娃能敗國，阿員三世只談兵。"]'),
('093b328b-8d4b-4c01-9da4-c846b255c98c','次前韻謝王主簿二首  其一','項安世','宋','宋诗','song-poetry','','[]','夷甫風姿滿坐傾，濬沖電目照人明。',64,'全唐诗/poet.song.146000.json','["夷甫風姿滿坐傾，濬沖電目照人明。", "更拈秋水長天句，來映清霜十月晴。", "援筆而成禰處士，摇毫不盡崔廷評。", "若容跛鱉追高步，勿卹驅塵小作程。"]'),
('88f96f0a-3bf7-41d5-93c8-f4bafadbafee','次前韻謝王主簿二首  其二','項安世','宋','宋诗','song-poetry','','[]','南州高士到湘州，山鬼湘娥暮暮愁。',64,'全唐诗/poet.song.146000.json','["南州高士到湘州，山鬼湘娥暮暮愁。", "行世頭顱渾欲老，駕天胸次未經酬。", "搜殘風月三千界，吟破江湖九十洲。", "誰報玉皇香案道，早將關放石渠休。"]'),
('8ba56fc9-95ff-454c-97e9-bd60069bd681','次韻張直閣雪詩余亦有詩方遣送而未達','項安世','宋','宋诗','song-poetry','','[]','信口粗吟信手書，蒼黄未到隠君廬。',64,'全唐诗/poet.song.146000.json','["信口粗吟信手書，蒼黄未到隠君廬。", "伻來已有詩相逼，我亦誰令子亦如。", "寫出崩騰來浩蕩，看成飛舞带紆餘。", "老夫頼有兒時獪，因索先償得少徐。"]'),
('828defa0-2ba7-4399-ac39-10fb98320348','再次韻謝張直閣惠雪詩','項安世','宋','宋诗','song-poetry','','[]','案頭擁被映殘書，溪上何人訪敝廬。',64,'全唐诗/poet.song.146000.json','["案頭擁被映殘書，溪上何人訪敝廬。", "鳳沼詩仙王二十，兔園賦客馬相如。", "玉龍百萬推敲裏，月界三千鍛鍊餘。", "合侍金輿和黄竹，一官何事尚徐徐。"]'),
('26d7e55a-c016-41ed-a6ff-d18a34a5a457','三次韻咏雪','項安世','宋','宋诗','song-poetry','','[]','初驚簌簌響蟲書，稍覺霏霏入草廬。',64,'全唐诗/poet.song.146000.json','["初驚簌簌響蟲書，稍覺霏霏入草廬。", "直是謝娘工說似，未騰歐叟不言如。", "相投最惜衣裾片，戀別尤憐瓦縫餘。", "誰見道山新霽後，嫩寒微峭日光徐。"]'),
('f9f481e1-fe03-4e8c-8e23-3d1e2e020877','四次韻李校書雪中臨唐人陰符經','項安世','宋','宋诗','song-poetry','','[]','乘興能臨褚令書，無人知是戴公廬。',64,'全唐诗/poet.song.146000.json','["乘興能臨褚令書，無人知是戴公廬。", "映窗寒雪天相借，嗜古高情我不如。", "貞觀風流淪沒後，凌烟名字斷殘餘。", "李侯用意青雲外，肯與時人較疾徐。"]'),
('4f5088e7-0100-4440-bfed-aae468777d63','車駕還內大雪','項安世','宋','宋诗','song-poetry','','[]','萬乘回轅入未央，六花迎駕舞康莊。',64,'全唐诗/poet.song.146000.json','["萬乘回轅入未央，六花迎駕舞康莊。", "都人失喜瞻天仗，旱俗相呼候歲穰。", "百局橋山方暴露，兩宮長信正凄凉。", "去年群玉題詩處，獨倚欄桿淚幾行。"]'),
('1e125d4e-1082-4e5c-9d8b-25a90197f1c1','遊白鹿洞書院','項安世','宋','宋诗','song-poetry','','[]','晦翁一別遂千秋，跨鹿乘雲何處遊。',64,'全唐诗/poet.song.146000.json','["晦翁一別遂千秋，跨鹿乘雲何處遊。", "人隨流水去不返，名與好山空自留。", "峯巒戢戢田園浄，藤刺深深磴道幽。", "寶匣塵生弦索斷，遺音重撫淚雙流。"]'),
('0dae4c34-b596-4496-b706-7870ad89e826','賦李季章大著書樓','項安世','宋','宋诗','song-poetry','','[]','不識書樓夢已登，幽人應在最高層。',64,'全唐诗/poet.song.146000.json','["不識書樓夢已登，幽人應在最高層。", "網羅歆向群言目，搜攪談遷萬古膺。", "河漢西流清露重，玉霄東望紫烟凝。", "夜深誰見憑欄處，天作長編月作燈。"]'),
('ce73041e-af7c-429c-9dbb-bbc02a2d7b4a','大風中登長橋','項安世','宋','宋诗','song-poetry','','[]','又拖筇杖過垂虹，粉柱丹梁五十洪。',64,'全唐诗/poet.song.146000.json','["又拖筇杖過垂虹，粉柱丹梁五十洪。", "雲氣深深籠薄日，波聲浩浩鼓長風。", "客船破膽經塘石，漁艇輕生逐釣筒。", "欲訪三高無處問，悠悠千古見冥鴻。"]'),
('d038fc34-1e46-4b43-8dd2-a6cf76ebe382','愛秋','項安世','宋','宋诗','song-poetry','','[]','生憎詞客并詩客，只解悲秋不愛秋。',64,'全唐诗/poet.song.146000.json','["生憎詞客并詩客，只解悲秋不愛秋。", "玉作花肌嬌不柰，金妝寶靨笑無休。", "桂香夜夜薰羅袖，蕣彩朝朝艷醉眸。", "脫盡畫橋千尺柳，舞腰如束更風流。"]'),
('418e169c-9d94-4c5d-a024-29fbf2dc8a94','送楊主簿  其一','項安世','宋','宋诗','song-poetry','','[]','誠齋四海一先生，詩滿江湖以字行。',64,'全唐诗/poet.song.146000.json','["誠齋四海一先生，詩滿江湖以字行。", "正法親傳誰得鉢，異聞獨立子趨庭。", "未能暇日詢三得，枉作經年共一城。", "眼底不知離別苦，前途相望似晨星。"]'),
('cbe3c18c-90f3-4e28-a193-e4e61c3ec77e','送楊主簿  其二','項安世','宋','宋诗','song-poetry','','[]','書生歲晚亦無餘，朝作新詩暮看書。',64,'全唐诗/poet.song.146000.json','["書生歲晚亦無餘，朝作新詩暮看書。", "書爲送人知免矣，詩仍隨子獨何歟。", "欄憑罨畫山光曉，船刺湘羅日影初。", "可是愛忙偏覓句，箇中無計得逃渠。"]'),
('86d205ea-8a91-4150-8bc8-fac50a92fef0','西坡','項安世','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','西坡仙去漪嵐在，重到堂中廿二年。',64,'全唐诗/poet.song.146000.json','["西坡仙去漪嵐在，重到堂中廿二年。", "依舊廬山當左闔，新添濠水注前川。", "渾無障礙千峰處，長有澄鮮萬頃天。", "但得此心如此地，不妨朝暮與周旋。"]'),
('00764d9c-5972-4de9-ab6a-9dcc8624a3b1','寄南唐吳監嶽兼白鹿書院','項安世','宋','宋诗','song-poetry','','[]','誅茅一畝竹三椽，繞舍畦蔬滿屋荃。',64,'全唐诗/poet.song.146000.json','["誅茅一畝竹三椽，繞舍畦蔬滿屋荃。", "擲廩峰前新廟令，勘書臺上老儒仙。", "西山草木歸吟藁，東匯烟雲入甕天。", "合與平菴管風月，便稱行守莫稱權。"]'),
('f652999d-c617-402c-9f04-d435dc60f723','路傍有因梅竹以編籬者','項安世','宋','宋诗','song-poetry','','[]','已生野外更籬根，仍與蚩氓補斷垣。',64,'全唐诗/poet.song.146000.json','["已生野外更籬根，仍與蚩氓補斷垣。", "博士低頭乘虜障，王姬掩面嫁烏孫。", "風枝雨葉無生意，粉面朱脣有淚痕。", "說與調羹吹律事，老農那信腐儒言。"]'),
('5c156304-3d24-4d39-be33-a8d3ff96aca2','二十一日柘龍橋道中','項安世','宋','宋诗','song-poetry','','[]','早禾登架晚禾青，雨後官塘處處平。',64,'全唐诗/poet.song.146000.json','["早禾登架晚禾青，雨後官塘處處平。", "山馬未明行木彴，水牛亭午卧深坑。", "人家總在林間住，生計惟憑隴上耕。", "青嶂夾田田夾澗，翠圍屏裏萬竽笙。"]'),
('c2b41f15-aeb2-4253-948d-d4da725dcdfd','直洲再贈江道士','項安世','宋','宋诗','song-poetry','','[]','玉臺山裏未能歸，滿世間人總可疑。',64,'全唐诗/poet.song.146000.json','["玉臺山裏未能歸，滿世間人總可疑。", "道士但行安穩處，先生應蔑刺譏詞。", "重來曉日芳洲上，却憶經年痛飲時。", "未必蓬山陳少監，今朝閒暇得相思。"]'),
('7de1fbc6-1a60-484e-9bc9-7338b3cb7c3b','次韻路德章石頭城弔古','項安世','宋','宋诗','song-poetry','','[]','竹間寒日浄暉暉，竹外空岡草木衰。',64,'全唐诗/poet.song.146000.json','["竹間寒日浄暉暉，竹外空岡草木衰。", "東晉舊城惟月在，南唐凉殿有風知。", "人來野寺尋遺跡，僧指蒼烟說故時。", "試問春花秋葉句，何如玉樹後庭詩。"]'),
('a9a23a0c-f977-4510-8abf-0f3e38ed730b','次韻送劉左史去國','項安世','宋','宋诗','song-poetry','','[]','手把東溪處士書，欹眠湖上小僧廬。',64,'全唐诗/poet.song.146000.json','["手把東溪處士書，欹眠湖上小僧廬。", "生憎人作侍臣看，自喜身今客子如。", "去國祗堪千古重，看囊那得一錢餘。", "二年兩過劉郎洑，應爲家林又少除。"]'),
('3a8df7f0-31ed-4c62-ad55-69878bce041a','進和御製聞喜宴詩','項安世','宋','宋诗','song-poetry','','[]','璧輝河綵絢宸章，鼎飪需雲盛國光。',64,'全唐诗/poet.song.146000.json','["璧輝河綵絢宸章，鼎飪需雲盛國光。", "自昔祖宗崇禮遇，至今英俊入言揚。", "明良舊詠回千古，槀飫新書侈萬方。", "神禹克艱心未已，更思忠節贊時康。"]'),
('3036561c-e173-47d4-8b9a-17e7047d2883','嚴州建德道中','項安世','宋','宋诗','song-poetry','','[]','步步青山擁碧溪，村村麥隴入桑畦。',64,'全唐诗/poet.song.146000.json','["步步青山擁碧溪，村村麥隴入桑畦。", "路將好景匆匆過，轎避柔柯故故低。", "風餌雨紈香有思，带羅簪玉浄無泥。", "如今始悟嚴夫子，不把漁竿換介圭。"]'),
('65bc46b5-fc54-42ae-bba8-b1132be376bf','曲湘灣','項安世','宋','宋诗','song-poetry','','[]','兩崖左右蜜房穿，一水中間蟻線旋。',64,'全唐诗/poet.song.146000.json','["兩崖左右蜜房穿，一水中間蟻線旋。", "蹙起浪渦知有石，蕩開雲影倒窺天。", "當洪沒沒青螺暗，過潄霏霏白琲圓。", "我欲濯纓渠濯足，一生輸與釣魚船。"]'),
('37f80e8e-03cb-4b6b-a298-79acfe825934','社木灣','項安世','宋','宋诗','song-poetry','','[]','胡床却坐對澄江，一點無風鏡面光。',64,'全唐诗/poet.song.146000.json','["胡床却坐對澄江，一點無風鏡面光。", "帆過生綃多少幅，書成斜雁兩三行。", "白沙翠竹却却凈，古岸新堤曲曲長。", "喚作漁郎無一事，烟中艇子許匆忙。"]'),
('0c9338ea-c0a6-4ebf-b5d1-acd2e6eb3ba3','過故宜城  其一','項安世','宋','宋诗','song-poetry','','[]','跋馬南城弔楚王，寂寥遷國歲年長。',64,'全唐诗/poet.song.146000.json','["跋馬南城弔楚王，寂寥遷國歲年長。", "故宮白道埋春草，小市青旗掛夕陽。", "時有野鷄吞墮珥，更無遺像鎮祠堂。", "祗應平路橋邊水，曾照當時後苑妝。"]'),
('2451b227-2909-475e-8730-581e166f3ca5','過故宜城  其二','項安世','宋','宋诗','song-poetry','','[]','我行熊繹故王都，十里南牆俯赤湖。',64,'全唐诗/poet.song.146000.json','["我行熊繹故王都，十里南牆俯赤湖。", "想見當時寧有晉，那知此地更逃吳。", "宮門自昔通城北，墓碣多年立路隅。", "欲仗青煙詢白鳥，背人飛去不容呼。"]'),
('7f789e54-f0f6-4433-ba91-1bb66616a8e6','都下次韻謝松陽沈術人二首  其一','項安世','宋','宋诗','song-poetry','','[]','向來定遠太平平，自殿銀袍五百英。',64,'全唐诗/poet.song.146000.json','["向來定遠太平平，自殿銀袍五百英。", "觜距不堪誇試席，齒牙無復近鄉評。", "重探虎穴顔何厚，忽見稽山眼暫明。", "頼有東陽老居士，相逢一笑又詩成。"]'),
('b00aa42b-9dd1-4f8b-ab40-d75b7efcb47c','都下次韻謝松陽沈術人二首  其二','項安世','宋','宋诗','song-poetry','','[]','下簾讀易沈君平，老向人間識世英。',64,'全唐诗/poet.song.146000.json','["下簾讀易沈君平，老向人間識世英。", "戲把年齡聊復問，從來富貴不須評。", "聯翩詩筆粗豪甚，矍鑠精神顧盼明。", "我欲求田古松邑，君言此計幾時成。"]'),
('2091b619-d62d-41dc-a5cb-4cf1cbb36171','酬紹興梁監酒','項安世','宋','宋诗','song-poetry','','[]','伯鸞長嘯出東都，來卜龍邱二畝居。',64,'全唐诗/poet.song.146000.json','["伯鸞長嘯出東都，來卜龍邱二畝居。", "千歲仍昆作英語，五噫文采尚周餘。", "胸中萬卷未得力，堂下一言誰識渠。", "我亦微官方冷甚，恨無燕玉可相噓。"]'),
('ecc2076c-3149-4e41-ac05-35bb3a62896c','病中謝客','項安世','宋','宋诗','song-poetry','','[]','方丈山中太史公，二年湖海困飄蓬。',64,'全唐诗/poet.song.146000.json','["方丈山中太史公，二年湖海困飄蓬。", "黄天蕩裏逢驚浪，百里荒前阻逆風。", "已到鄉閭猶夢魘，每聞車馬便心忪。", "客來但道先生病，自教譍門兩禿童。"]'),
('1059213e-7804-4ca8-bd71-a83f0138b770','九月呈運使盧檢院','項安世','宋','宋诗','song-poetry','','[]','法官蕆事三靈格，山國休工萬寶成。',64,'全唐诗/poet.song.146000.json','["法官蕆事三靈格，山國休工萬寶成。", "虜使此時心暫展，麗譙高處眼增明。", "搴帷正在煎萸俗，綴席何妨伴菊傾。", "此會明年公莫問，賜來應有一枝榮。"]'),
('b8c71259-a4fc-4a3b-a85d-c186dba97e04','月臺','項安世','宋','宋诗','song-poetry','','[]','小築南臺倚北亭，一方荆玉可雲屏。',64,'全唐诗/poet.song.146000.json','["小築南臺倚北亭，一方荆玉可雲屏。", "峽中暮雨嘗疎月，秋後天河始見星。", "初與羿妃爲此會，自開夔子幾千齡。", "我雖不飲心先醉，坐汲寒光當淥醹。"]'),
('7f1c6ebe-82f8-4772-a81b-f3c2eaf129b3','書懷','項安世','宋','宋诗','song-poetry','','[]','君如快馬捷先鳴，上便追風不計程。',64,'全唐诗/poet.song.146000.json','["君如快馬捷先鳴，上便追風不計程。", "楊監西江推格律，陸郎東海服才情。", "栽培花木心無事，彈壓湖山句有聲。", "如許清名剛不惜，苦來蠻角建愁城。"]'),
('86a7c34f-a747-4b42-82d8-c3c934925e89','寒食夜對月','項安世','宋','宋诗','song-poetry','','[]','朱公自有五湖天，介子何須九縣田。',64,'全唐诗/poet.song.146000.json','["朱公自有五湖天，介子何須九縣田。", "無限東風原上淚，盡輸西子月中舩。", "梨花自怯嫦娥白，鞦影終隨永夜偏。", "江海歸來無賜火，幸分光彩到愁邊。"]'),
('3dc1cbfa-368e-4b4a-9315-b677fdd779c3','十六夜州宅觀月','項安世','宋','宋诗','song-poetry','','[]','青天碧海桂光流，已是人間萬古愁。',64,'全唐诗/poet.song.146000.json','["青天碧海桂光流，已是人間萬古愁。", "野闊江深那向楚，霜深露冷更逢秋。", "此時此地俱清絕，無酒無詩得索休。", "太守尚嫌高興少，捲雲飛雨架層樓。"]'),
('8f82f8d3-cf3b-4826-8879-4b9c827c409d','正月十四夜月色奇甚','項安世','宋','宋诗','song-poetry','','[]','去年風雨暗元宵，今歲懸知月色饒。',64,'全唐诗/poet.song.146000.json','["去年風雨暗元宵，今歲懸知月色饒。", "突兀一燈離海嶠，蒼茫萬點赴星橋。", "足聲殷地仍車馬，人語喧天更鼓簫。", "定是封夷畏娥婺，斷無輕吹一絲摇。"]'),
('05d1d5bd-4581-4b3b-9161-6fcf32644375','五更至城下','項安世','宋','宋诗','song-poetry','','[]','身閑最怕俗間忙，夜短仍妨睡思長。',64,'全唐诗/poet.song.146000.json','["身閑最怕俗間忙，夜短仍妨睡思長。", "戍柝傳更催曲枕，領輿將夢踏黄塘。", "濕雲裹月江天白，小雨蒸春草樹香。", "却到城門聽畫角，倚空樓堞正蒼蒼。"]'),
('af4eab4d-62b8-4026-bfe4-ae2f4d4eb519','送李大著赴闕','項安世','宋','宋诗','song-poetry','','[]','玉觀金橋無限詩，楚臣漢女不勝悲。',64,'全唐诗/poet.song.146000.json','["玉觀金橋無限詩，楚臣漢女不勝悲。", "如今蕩蕩平平矣，却合融融洩洩之。", "八陛加恩須大冊，三朝修史待宏規。", "回頭莫忘巴陵酒，病渴多年少一卮。"]'),
('54da9000-4857-4c37-a936-9888e1e36869','送章升之料院自魚關還闕  其一','項安世','宋','宋诗','song-poetry','','[]','憶侍先皇二紫宸，殿頭親見鎖廳人。',64,'全唐诗/poet.song.146000.json','["憶侍先皇二紫宸，殿頭親見鎖廳人。", "畫簾宮燭程書了，黄牒青袍拜賜頻。", "萬使回朝天亦老，十年旅食夢如新。", "當時學士今頭白，却送郎君作近臣。"]'),
('3ca52d25-c317-4009-a5fc-184e51999e5e','送章升之料院自魚關還闕  其二','項安世','宋','宋诗','song-poetry','','[]','此別迢迢更莫言，向來一別已茫然。',64,'全唐诗/poet.song.146000.json','["此別迢迢更莫言，向來一別已茫然。", "自從內使蘭亭歲，直到東坡赤壁年。", "吳下故人如見問，楚中狂士不須憐。", "欲知病後食何藥，三百篇和上下篇。"]'),
('fb0001fa-8ed9-4516-87a7-71bf2b1e9dbb','徽州赴羅主管飯','項安世','宋','宋诗','song-poetry','','[]','去年話別春風前，今年相見菊花邊。',64,'全唐诗/poet.song.146000.json','["去年話別春風前，今年相見菊花邊。", "忽然來說二年夢，偶爾亦是三生緣。", "弟兄金玉吾所敬，肌膚冰雪人可憐。", "四海難逢一樽酒，逸群那更有吳髯。"]'),
('e2223678-f648-440d-ace4-4591686844d1','宋帥招李大著陳提刑同飯','項安世','宋','宋诗','song-poetry','','[]','龍蟠鳳舉玉霄傍，肯爲南公下石梁。',64,'全唐诗/poet.song.146000.json','["龍蟠鳳舉玉霄傍，肯爲南公下石梁。", "人識子文新政事，家傳宋玉舊文章。", "斷無橫吏驚龐俗，時有書生近燕堂。", "二客風流俱令上，獨慚歌市接輿狂。"]'),
('e0227aa1-9679-4b24-94e0-f6ea8f8804f4','夜坐懷都城','項安世','宋','宋诗','song-poetry','','[]','霏霏寒露濕檣竿，耿耿明星動玉灣。',64,'全唐诗/poet.song.146000.json','["霏霏寒露濕檣竿，耿耿明星動玉灣。", "夜久暗塵無一點，心閑遠念忽相關。", "天街月色中秋近，海岸濤頭數日間。", "正是錢塘好時節，只愁風雨自闌珊。"]'),
('57b14598-20ce-4719-bcb5-d361d47c8f7a','中秋月','項安世','宋','宋诗','song-poetry','','[]','素娥行處與誰同，玉斧修成幾許功。',64,'全唐诗/poet.song.146000.json','["素娥行處與誰同，玉斧修成幾許功。", "空裏若安丹桂木，雲中應有白銀宮。", "蟾行萬里惟三足，兔滿千山望一雄。", "海闊天寬無處問，看渠朝暮自西東。"]'),
('e9e0b18f-7c5e-4f8c-be79-963107a6c8c6','寄題四川總餉陳郎中籌邊堂  其一','項安世','宋','宋诗','song-poetry','','[]','四寸紅牙一幄籌，萬山牛馬去如流。',64,'全唐诗/poet.song.146000.json','["四寸紅牙一幄籌，萬山牛馬去如流。", "天西日落長安近，塞外雲開滴博收。", "草奏隃麋宮墨重，談兵鷄舌寶香浮。", "都將湖海元龍氣，壓倒文饒百尺樓。"]'),
('9b6cfe66-6c47-4aa9-97d1-8b4bc3f89c79','寄題四川總餉陳郎中籌邊堂  其二','項安世','宋','宋诗','song-poetry','','[]','四萬黄金六出奇，家藏犬豹虎龍機。',64,'全唐诗/poet.song.146000.json','["四萬黄金六出奇，家藏犬豹虎龍機。", "古傳財賞軍能壯，今見樵蘇士不饑。", "借得留侯千里箸，掃平冒頓五方圍。", "歸朝不肯談前事，問穀和錢却道非。"]'),
('c43f9f42-6d58-438b-971e-08f01854fa81','辱井','項安世','宋','宋诗','song-poetry','','[]','寺前蔬圃是臺城，寺後寒泉入柳營。',64,'全唐诗/poet.song.146000.json','["寺前蔬圃是臺城，寺後寒泉入柳營。", "玉甃多年無舊物，銀瓶終日有哀聲。", "游童走卒爭嗤點，弱水貪泉共姓名。", "不似冶城三尺土，鍾山回首讓崢嶸。"]'),
('f8011f84-481a-435f-9c55-0b1142370f8e','紀山寺觀梁宣明二帝陵','項安世','宋','宋诗','song-poetry','','[]','高祖當年起雍荆，山川千古尚鍾情。',64,'全唐诗/poet.song.146000.json','["高祖當年起雍荆，山川千古尚鍾情。", "林中佛寺君王冢，湖上仙宮太子塋。", "已見世誠宵斫柱，又聞阿銑曉揚旌。", "生兒若似江陵上，肯負渠家老騎兵。"]'),
('576f84c7-0631-4285-9298-eafe0864b90a','武陵道中元日自歎','項安世','宋','宋诗','song-poetry','','[]','流光冉冉道無聞，短髮蕭蕭雪見侵。',64,'全唐诗/poet.song.146000.json','["流光冉冉道無聞，短髮蕭蕭雪見侵。", "衰矣久無天下志，行乎聊慰老人心。", "功名隨世吾何感，道德康時力未任。", "安得萬牛呼古柏，武夷山下白雲深。"]'),
('1f1e4723-472c-40d9-9526-4853c5e8e3fa','送董煟歸鄱陽','項安世','宋','宋诗','song-poetry','','[]','沙隨程子九州聞，獨擁經綸謝世紛。',64,'全唐诗/poet.song.146000.json','["沙隨程子九州聞，獨擁經綸謝世紛。", "傳業只今惟董祀，愛人於古似鄱君。", "活民鴻寶方書備，壽國靈樞脈絡紛。", "欲服上醫何物是，他時種杏滿青雲。"]'),
('1f35c881-b746-48d4-a4d8-9abc03f3d727','習家池舊臨官路今路改而東池半入驛吏引自桑林中往觀因記所見','項安世','宋','宋诗','song-poetry','','[]','步入荒林問習家，江吞古岸入平沙。',64,'全唐诗/poet.song.146000.json','["步入荒林問習家，江吞古岸入平沙。", "枯池舊歲猶生藕，病柳新年尚著芽。", "草上醉人眠未醒，桑間遊女笑相遮。", "東風倦客生情性，佇立殘陽看落花。"]'),
('60d71f2b-a40e-440d-873e-1f35047d041f','次韻張部門湖上二首  其一','項安世','宋','宋诗','song-poetry','','["\u897f\u6e56"]','已作西湖爛漫游，北山蘭若更深幽。',64,'全唐诗/poet.song.146000.json','["已作西湖爛漫游，北山蘭若更深幽。", "驊騮蹀躞青林下，舴艋夷猶古渡頭。", "花滿楊坡桃不語，聲喧陰壑水爭投。", "可憐不共林宗泛，只有新詩許載酬。"]'),
('6883fbf1-2e50-4550-b545-5d87681d4577','次韻張部門湖上二首  其二','項安世','宋','宋诗','song-poetry','','[]','詩興春來似水翻，更添孤艇入雲間。',64,'全唐诗/poet.song.146000.json','["詩興春來似水翻，更添孤艇入雲間。", "中心白閣蘇堤路，兩岸南屏西竺山。", "一日晴明輸子往，半年風雨被渠慳。", "欹眠窈窕沖融裏，月白烟青未忍還。"]'),
('cd9ccdd1-d977-4005-85d0-e9713b22272e','春日湖上','項安世','宋','宋诗','song-poetry','','[]','一春官府倦樊籠，飛墮浮嵐紫翠中。',64,'全唐诗/poet.song.146000.json','["一春官府倦樊籠，飛墮浮嵐紫翠中。", "雲外憑欄臨過鳥，石間披閘看奔洪。", "東風茭蕩關心綠，落日桃谿盡意紅。", "更踏蘇堤湖面去，玉霄光裏跨晴虹。"]'),
('90a5b2b2-3be6-4e58-bde0-647840b4fcf9','次韻楊僉判潜室中竹枝','項安世','宋','宋诗','song-poetry','','[]','嬾龍入戶養慷枝，罷聽風雷却聽詩。',64,'全唐诗/poet.song.146000.json','["嬾龍入戶養慷枝，罷聽風雷却聽詩。", "頭角不爭雲雨會，精神如畏雪霜欺。", "莫教畫手流傳去，生怕時人取次知。", "此腹可憐終不負，琅玕朝暮爲君披。"]'),
('4a260ae4-2776-4629-b16f-b93b9a337931','次韻程堯仲風雨詩  其一','項安世','宋','宋诗','song-poetry','','[]','春來長是雨相禁，春事能消幾日陰。',64,'全唐诗/poet.song.146000.json','["春來長是雨相禁，春事能消幾日陰。", "一夜小桃紅削迹，明朝芳草綠驚心。", "牆溝㶁㶁忙如箭，簷瓦瀟瀟怨似吟。", "前日東亭看花處，不知尊在與沙沈。"]'),
('a2691e10-c15a-4234-b40e-488866f845b9','次韻程堯仲風雨詩  其二','項安世','宋','宋诗','song-poetry','','[]','浩浩陰風徹屋號，霏霏寒雨一天毛。',64,'全唐诗/poet.song.146000.json','["浩浩陰風徹屋號，霏霏寒雨一天毛。", "撼醒花柳經年眼，潤透郊原百尺膏。", "鼓舞孰知神物妙，沾濡方表化工勞。", "游人只見春能好，香滿園林綠滿壕。"]'),
('0303b4ad-51a6-4848-afa2-5f2a274efd8f','同舍置酒孫園招熊莘老','項安世','宋','宋诗','song-poetry','','[]','千年故國陽春地，今日王孫尚姓熊。',64,'全唐诗/poet.song.146000.json','["千年故國陽春地，今日王孫尚姓熊。", "坐上堂堂皆此客，雲間衮衮看諸公。", "題詩小苑春風裏，把酒夕陽烟雨中。", "莫恨來遲桃李過，綠襴衫色正葱葱。"]'),
('f26dcdda-0ec6-4d94-b48b-4cb71e265821','黄潭道中十一月暫往武陵營救伯兄之急','項安世','宋','宋诗','song-poetry','','[]','籃輿欲上不堪羞，古陌初窮未是愁。',64,'全唐诗/poet.song.146000.json','["籃輿欲上不堪羞，古陌初窮未是愁。", "客子天寒依道路，書生歲晚學伊優。", "烟中綠樹時招手，風裏黄蘆只點頭。", "短日鮮鮮還有意，爲人朝暮暖駝裘。"]'),
('322f8f05-add8-49a0-87bb-e13d03991f64','和胡黎州賀得郡韻','項安世','宋','宋诗','song-poetry','','[]','波間來往願莘其，林下歸飛樂鸒斯。',64,'全唐诗/poet.song.146000.json','["波間來往願莘其，林下歸飛樂鸒斯。", "羅致軍門雖有禮，捉將官裏便無詩。", "齊瓜有日君方往，舜牧無人我亦咨。", "西望雪山三百驛，何因杯酒得同持。"]'),
('316a819f-f6fc-4cf4-8811-1d99fafedf39','偶作','項安世','宋','宋诗','song-poetry','','[]','舍前江路接征廛，舍後湖光浄渺然。',64,'全唐诗/poet.song.146000.json','["舍前江路接征廛，舍後湖光浄渺然。", "不許紅塵穿港入，獨携黄妳過橋眠。", "禽魚上下詩三百，風雨陰晴易二篇。", "定有真人汎蓮葉，夜深吹杖聽芸編。"]'),
('237a48c4-144b-42b8-b43c-316855747a60','沙溪','項安世','宋','宋诗','song-poetry','','[]','沙溪東畔小沙溪，鑿石臨流喚客題。',64,'全唐诗/poet.song.146000.json','["沙溪東畔小沙溪，鑿石臨流喚客題。", "水欲環洲流故曲，山來擁市勢全低。", "車聲軋軋機中緯，榔響丁丁陣上鼙。", "出處不齊均有役，兩輪天上亦東西。"]'),
('7b133b0f-6aa7-427d-8047-254043f6416d','詠拋毬','項安世','宋','宋诗','song-poetry','','[]','綵旗丹柱倚春風，寒日清明罷繡工。',64,'全唐诗/poet.song.146000.json','["綵旗丹柱倚春風，寒日清明罷繡工。", "千仞驪珠翻錦带，五紋蛛網麗晴空。", "百年日月跳丸裏，一擲功名唾手中。", "漠北將軍貪蹋踘，豈知兵法在吳宮。"]'),
('5667c63c-77bb-483c-bea8-dbb0702cdec3','次韻王主簿同考試','項安世','宋','宋诗','song-poetry','','[]','文陣樅樅劔戟叢，喚回習氣老臧宮。',64,'全唐诗/poet.song.146000.json','["文陣樅樅劔戟叢，喚回習氣老臧宮。", "分明天上三題草，消盡人間一世雄。", "聖處門庭開蕩蕩，春來風景樂融融。", "何年一解隋唐梏，展放諸生闕里中。"]'),
('b9326577-ef32-4b98-8e9c-359d293fff7d','富陽道中','項安世','宋','宋诗','song-poetry','','[]','此生湖海慣漂浮，黄鶴垂虹已倦游。',64,'全唐诗/poet.song.146000.json','["此生湖海慣漂浮，黄鶴垂虹已倦游。", "七載雲門穿布襪，今年嚴瀨著羊裘。", "戴溪亭外天台路，揚子江頭灧澦舟。", "欲跨祁連窺瀚海，只今誰是冠軍侯。"]'),
('6a613da2-b890-480b-b8d5-af4b8277851f','江山見新知閬州李著作舟至','項安世','宋','宋诗','song-poetry','','[]','小立江風見蜀船，繡旗朱幔鼓聲喧。',64,'全唐诗/poet.song.146000.json','["小立江風見蜀船，繡旗朱幔鼓聲喧。", "問言何郡客新到，知是故人吾欲顛。", "芸裏簡書真昨夢，菊邊卮酒是前緣。", "還家快與兒曹說，明日鄰翁貸子錢。"]'),
('f11e9c1f-f083-463f-a7de-114d9071d742','有感','項安世','宋','宋诗','song-poetry','','[]','幾許心期百未償，更將疏髮對蒼茫。',64,'全唐诗/poet.song.146000.json','["幾許心期百未償，更將疏髮對蒼茫。", "江聲直上鯨波去，山色回看虎踞長。", "亂後碧蕪荒楚甸，雲間孤塔見維揚。", "承平舊事無人說，閑倚欄干送夕陽。"]'),
('ca4858e8-ea6f-4c6f-9e44-08e2aec9799a','桃花菊','項安世','宋','宋诗','song-poetry','','[]','花神得與換新妝，不著仙家金縷裳。',64,'全唐诗/poet.song.146000.json','["花神得與換新妝，不著仙家金縷裳。", "也學時人尚紅粉，依前風味带黄香。", "微醺有意隨風舞，獨立無言任雨荒。", "喚作桃紅元未稱，桃花那解傲秋霜。"]'),
('7fbf1e4d-d8cf-4b3c-b101-e8ca77b3f91f','同劉監丞步觀長干寺後諸園','項安世','宋','宋诗','song-poetry','','[]','游人塞道不容車，千古金陵少婦居。',64,'全唐诗/poet.song.146000.json','["游人塞道不容車，千古金陵少婦居。", "朱雀大桁春雨後，烏衣深巷曉風初。", "紅紅白白花無數，下下高高意有餘。", "此景只應閑客管，癭黎輕蓋日徐徐。"]'),
('242773a2-e56e-4aa4-a5b5-5335ab4a6a6f','次韻高安撫雄楚樓餞別','項安世','宋','宋诗','song-poetry','','[]','醉擘烏絲寫玉欄，坐分鸞𦞦膾龍肝。',64,'全唐诗/poet.song.146000.json','["醉擘烏絲寫玉欄，坐分鸞𦞦膾龍肝。", "已知全楚風流在，更覺將軍禮數寬。", "一日樓成供燕餞，明朝岸轉憶高寒。", "幅巾藜杖他年事，準擬歸來得重看。"]'),
('17af383b-6a8a-4f4a-828f-318a8c5734db','阻風岳州回寄曹漢陽','項安世','宋','宋诗','song-poetry','','[]','病裏牽船去趙沱，醉中題字寄曹皤。',64,'全唐诗/poet.song.146000.json','["病裏牽船去趙沱，醉中題字寄曹皤。", "卧聽別語心難遣，起看家山路不多。", "晴日上江卿大好，北風吹浪汝云何。", "早知七日桃花峽，且可千鍾竹葉波。"]'),
('da37fc25-d316-4088-af82-45a86371e332','又次韻吳少保游雄楚樓及渚宮','項安世','宋','宋诗','song-poetry','','[]','紅旗繡額上城頭，菱葉荷花下小舟。',64,'全唐诗/poet.song.146000.json','["紅旗繡額上城頭，菱葉荷花下小舟。", "遵渚夷猶蕩佳月，倚天突兀對高秋。", "坡公句裏東南水，杜老詩中西北樓。", "點化山川一刀匕，風流從此說吾州。"]'),
('85e4b4dd-c914-4e6b-854c-9e80288066ca','還過渚宮  其一','項安世','宋','宋诗','song-poetry','','[]','一興一廢古今同，熊繹當年起霸功。',64,'全唐诗/poet.song.146000.json','["一興一廢古今同，熊繹當年起霸功。", "沿漢泝江開國步，牧臯規偃建王宮。", "重來舊日嬉遊處，猶覺如今氣象雄。", "想見得臣并鬭穀，治兵謀國震山東。"]'),
('04df82b0-827b-4cc3-8e68-6798fa5cc421','還過渚宮  其二','項安世','宋','宋诗','song-poetry','','[]','下得腰輿倚瘦藜，閑將病骨照清陂。',64,'全唐诗/poet.song.146000.json','["下得腰輿倚瘦藜，閑將病骨照清陂。", "三王故苑風流處，二月游人爛漫時。", "此日鬢邊應笑我，過來胸次却關誰。", "一年兩度西城去，獨自宮園賦小詩。"]'),
('df74ca6c-42ae-4f14-a546-fb08b32952d5','次韻和張安撫九日龍山賦','項安世','宋','宋诗','song-poetry','','[]','使君千騎踏清秋，乞與他年說勝游。',64,'全唐诗/poet.song.146000.json','["使君千騎踏清秋，乞與他年說勝游。", "自有名山無此客，痛湔遺臭爲吾州。", "野人已畢三時務，老子聊寬一日愁。", "猶有平生憂國意，不堪摇落對江流。"]'),
('bb9cb87b-1c7f-4b8d-8db5-098380d57230','明山湖阻風','項安世','宋','宋诗','song-poetry','','[]','咫尺明山在目中，咿啞三月傍蘆叢。',64,'全唐诗/poet.song.146000.json','["咫尺明山在目中，咿啞三月傍蘆叢。", "神豬繫久號無力，火隊炊頻飯欲空。", "半世宦途仍舊職，一生學海未新功。", "舟人慍見官人笑，萬事從來慣逆風。"]'),
('6fcd248b-917c-4927-adba-7a101e11c7a1','十日發祁陽  其一','項安世','宋','宋诗','song-poetry','','[]','自矜重九苦吟處，寫出浯溪真畫圖。',64,'全唐诗/poet.song.146000.json','["自矜重九苦吟處，寫出浯溪真畫圖。", "安排秀句待石鼓，指點江神迎綵艫。", "小雨已休朝復作，寒流忽漲夜仍枯。", "篷聲瑟瑟灘聲滑，應伴先生著句無。"]'),
('42e5fc74-8c71-426b-8009-fe6a5def6a47','十日發祁陽  其二','項安世','宋','宋诗','song-poetry','','[]','蟠螭結蚓走長坡，百尺蒼煙出女蘿。',64,'全唐诗/poet.song.146000.json','["蟠螭結蚓走長坡，百尺蒼煙出女蘿。", "削柿徵膏憐俗薄，和泥封痏謝官多。", "輝輝野日晞寒髮，索索剛風起細哦。", "幸自本無饑渴慮，不知何事此婆娑。"]'),
('c9d11350-94ca-4b69-9a3c-3751542e874d','至齋詩爲劉知錄作','項安世','宋','宋诗','song-poetry','','[]','酒邊琴外蕣華明，栗里幽人遠念生。',64,'全唐诗/poet.song.146000.json','["酒邊琴外蕣華明，栗里幽人遠念生。", "一寸光陰知有限，百年心事恐無成。", "追隨春服攀高駕，指點雩童問去程。", "簣土未升泉有達，高深那得便忘情。"]'),
('a013bce9-ea3c-4913-aac4-06bccc4d21ae','試學士院聞大駕過重華宮','項安世','宋','宋诗','song-poetry','','[]','君王鳳輦過龍樓，清曉都門積雨收。',64,'全唐诗/poet.song.146000.json','["君王鳳輦過龍樓，清曉都門積雨收。", "淚落三朝餘父老，春生簇仗萬貔貅。", "群公就日丹衷罄，索虜聞風逆膽羞。", "湖海小臣心未已，更陳千慮向鼇頭。"]'),
('e8fb640e-db21-4f58-8147-6cd7d47e18eb','四月二十八日輪對遇雨','項安世','宋','宋诗','song-poetry','','[]','攢梆疊鼓遞相催，西府東班次第來。',64,'全唐诗/poet.song.146000.json','["攢梆疊鼓遞相催，西府東班次第來。", "雨入北門千步濕，天臨後殿九重開。", "嘗時只在中廷拜，此日容穿左序回。", "叨近威顔陳悃愊，愧無崇論補涓埃。"]'),
('689c329f-69d6-48ef-8680-98f8cb1cbd4d','次韻王大著大享宿齋','項安世','宋','宋诗','song-poetry','','[]','淺學胡然敢望回，英躔幸甚得追陪。',64,'全唐诗/poet.song.146000.json','["淺學胡然敢望回，英躔幸甚得追陪。", "談鋒羨子雨無極，詩境愧予田盡萊。", "叢桂晚香牽獨夢，小梅春思惱清才。", "丁寧閣老須勤賦，早晚西扉詠砌苔。"]'),
('abcdd18c-6fb0-44af-a7b1-d4a8238742f9','至竹客嶺却寄金山聞老','項安世','宋','宋诗','song-poetry','','[]','二十五年丁令威，二十五日鬢成絲。',64,'全唐诗/poet.song.146000.json','["二十五年丁令威，二十五日鬢成絲。", "塵埃滿面脚欲破，酒肉熏心舌盡癡。", "雨出郭門聊一洗，日從源口便相隨。", "振衣直上千峯頂，却寄金山長老詩。"]'),
('2e0c7988-7773-481f-9f2f-ca0fb528202f','爲狄氏題','項安世','宋','宋诗','song-poetry','','[]','漭蒼洲邊縛葦亭，百年朝暮看雲生。',64,'全唐诗/poet.song.146000.json','["漭蒼洲邊縛葦亭，百年朝暮看雲生。", "月光破處藕花舞，雨意來時蒲葉鳴。", "歸艇欲迷宵路重，捲簾忽散曉風清。", "已同蒼狗俱無意，豈有江鷗更用盟。"]'),
('70a1adab-f749-4aea-9e16-cb9b1978f694','過如春堂觀趙德麟詩帖因次趙成卿韻','項安世','宋','宋诗','song-poetry','','[]','阿麟文采近西京，付與而公翰墨名。',64,'全唐诗/poet.song.146000.json','["阿麟文采近西京，付與而公翰墨名。", "今日如春堂上看，當年遺帖子孫榮。", "元豐曲裏承平話，小杜詩中戰伐情。", "濟上舊遊成一夢，王孫端復可憐生。"]'),
('7decfacf-fac4-46f7-886a-101dde40f8c1','鄭檢法久病將起以詩速之','項安世','宋','宋诗','song-poetry','','[]','詩人貪睡費朝衙，卧看香奩暈碧鴉。',64,'全唐诗/poet.song.146000.json','["詩人貪睡費朝衙，卧看香奩暈碧鴉。", "已向中秋阻丹桂，莫教重九負黄花。", "曈曈初日關農事，冉冉閑情近物華。", "已辦作糕尋故事，速來同醉落烏紗。"]'),
('4193c4e9-e192-4804-aef1-d09480028aeb','送吳襄陽換承宣使歸奉朝請二首  其一','項安世','宋','宋诗','song-poetry','','[]','去年荆府參謀去，今歲襄州太守歸。',64,'全唐诗/poet.song.146000.json','["去年荆府參謀去，今歲襄州太守歸。", "捐我漢南江北却，從今樂事賞心稀。", "南風日日菰蒲長，秋水年年鱖鯽肥。", "已斷此生湖𭲟裏，鱗鴻無用到柴扉。"]'),
('0a8cea18-8bde-4743-a4f0-f837582bbdaf','送吳襄陽換承宣使歸奉朝請二首  其二','項安世','宋','宋诗','song-poetry','','[]','三朝橐珥真王子，萬卷詩書大布衣。',64,'全唐诗/poet.song.146000.json','["三朝橐珥真王子，萬卷詩書大布衣。", "我尚不知身是貴，人於何見昨爲非。", "東朝特地成西序，放去分明是召歸。", "時覲重華談物表，君臣相對兩忘機。"]'),
('f2296e89-d5b2-41de-98d8-4ec893e9e166','雪堂','項安世','宋','宋诗','song-poetry','','[]','又到黄州舊雪堂，雪堂文字斷人腸。',64,'全唐诗/poet.song.146000.json','["又到黄州舊雪堂，雪堂文字斷人腸。", "紫烟有路連桐柏，清浪何年看洛陽。", "北望神州皆晉土，誰爲黨字豈蒼王。", "先王讀論空流血，浩浩乾坤此話長。"]'),
('1325ef1b-045e-442e-9ee9-ab722aa3d7d1','病起和柳州劉司法贈詩韻','項安世','宋','宋诗','song-poetry','','[]','平生僞學媿心休，此病何年可得瘳。',64,'全唐诗/poet.song.146000.json','["平生僞學媿心休，此病何年可得瘳。", "杜渴惟應卧江漢，齊痁何感罪姑尤。", "久之法掾師韓子，更向龍城問柳侯。", "能辨茯神驅瘧鬼，吾衰從此不須憂。"]'),
('fc611a05-c994-411e-b822-d4e217f383e7','再和病起韻答曹仲明','項安世','宋','宋诗','song-poetry','','[]','愛我空城美疢休，未蒙鍼砭若爲瘳。',64,'全唐诗/poet.song.146000.json','["愛我空城美疢休，未蒙鍼砭若爲瘳。", "齒疎髮脫真無用，語澀行遲見寡尤。", "稍善知醫似高子，敢云稱病學留侯。", "徑煩曹植波瀾句，一爲元微破隠憂。"]'),
('ccda5660-15e8-406e-9389-ff4cae4e4829','自過漢水菜花彌望不絕土人以其子爲油','項安世','宋','宋诗','song-poetry','','[]','漢南漢北滿平田，三月黄花也可憐。',64,'全唐诗/poet.song.146000.json','["漢南漢北滿平田，三月黄花也可憐。", "惟有書生知此味，可無詩句到渠邊。", "油燈夜讀書千卷，虀臼晨供飲十年。", "今日相看總流落，洛陽櫻笋正爭先。"]'),
('0069e956-f167-40d6-9613-fa22dc4da766','用韻送任以道入四川總領幕府二首  其一','項安世','宋','宋诗','song-poetry','','[]','銅梁天漢一軺新，紅芰清波去及辰。',64,'全唐诗/poet.song.146000.json','["銅梁天漢一軺新，紅芰清波去及辰。", "顧我索居誰爲友，與君難別豈關親。", "飛書上隴催庚癸，閉息匡床候子寅。", "出處雖殊心事一，濂溪風月舞雩春。"]'),
('8660f8f3-b5bc-4af1-8dfe-cceeb7b6e9c6','用韻送任以道入四川總領幕府二首  其二','項安世','宋','宋诗','song-poetry','','[]','軟紅塵裏不爭新，蠹簡香中却競辰。',64,'全唐诗/poet.song.146000.json','["軟紅塵裏不爭新，蠹簡香中却競辰。", "鄴架孔堂深貯腹，鮑篇陳檄妙看親。", "芻糧軋軋虛旁午，歲月悠悠老秩寅。", "曷日陰山行漢馬，大揮椽筆布王春。"]'),
('3af63222-e0e9-4b18-b604-f1154c1500cf','和王子一用韻告別','項安世','宋','宋诗','song-poetry','','[]','積吹摩空海有鯤，驚雷出地竹生孫。',64,'全唐诗/poet.song.146000.json','["積吹摩空海有鯤，驚雷出地竹生孫。", "娑羅木吐層層艷，窣堵波開面面閽。", "小貼金花聽疾足，淡書灰墨看高鶱。", "街槐影裏宮袍出，回首無忘匯澤門。"]'),
('9eccb642-d8fa-4d5c-b524-88c373ecb0b8','野山茶紅白二種','項安世','宋','宋诗','song-poetry','','[]','樟原嶺下野山茶，半是紅花半白花。',64,'全唐诗/poet.song.146000.json','["樟原嶺下野山茶，半是紅花半白花。", "雨裏向人俱有淚，花中隠士自成家。", "依稀薝蔔稍頭雪，彷彿棠梨臉畔霞。", "恐是山君雙侍女，不應臨路久咨嗟。"]'),
('54fe5fa9-3251-4871-95da-605833991853','夜坐納凉','項安世','宋','宋诗','song-poetry','','[]','黑雲湧起星月暗，急雨欲來天地凉。',64,'全唐诗/poet.song.146000.json','["黑雲湧起星月暗，急雨欲來天地凉。", "精神颯爽動秋思，襟袖飄蕭吹晚香。", "石峯巉青菖蒲細，盆沼漲綠鳬茈長。", "此中何處得三伏，更聽露井鳴銀床。"]'),
('70ccd1ad-085d-4b64-b810-2a31825ced93','陳氏四芝圖','項安世','宋','宋诗','song-poetry','','[]','當時一念繼元昆，誰附飛章告九閽。',64,'全唐诗/poet.song.146000.json','["當時一念繼元昆，誰附飛章告九閽。", "天聽直無多遠近，地靈頓有許便蕃。", "擬牋此事呈諸老，盍引斯人侍至尊。", "弭旱功夫消幾許，草茅猶足動乾坤。"]'),
('08153254-1d18-429f-aeef-b9090c1de22e','守歲  其一','項安世','宋','宋诗','song-poetry','','[]','人情憐舊復憐新，擾擾通宵雜笑嚬。',64,'全唐诗/poet.song.146000.json','["人情憐舊復憐新，擾擾通宵雜笑嚬。", "炷蠟煎膏留漏箭，買椒沽酒辦厨珍。", "一聲竹裏千家曉，百和香中九陌春。", "莫道病夫無節序，明朝清鏡滿梳銀。"]'),
('01f368bd-36aa-4705-8b3b-e5fbee1b39ca','守歲  其二','項安世','宋','宋诗','song-poetry','','[]','大家投轄駐年先，共判今宵一醉長。',64,'全唐诗/poet.song.146000.json','["大家投轄駐年先，共判今宵一醉長。", "不管栖禽驚列炬，且傾浮蟻盡餘觴。", "茶馗已作當關面，花柳誰知惜別腸。", "看取平生雙鬢髮，也隨新歲著新霜。"]'),
('eb27a68b-0416-4048-9b7a-9d19c6345180','重到東齋二首','項安世','宋','宋诗','song-poetry','','[]','人生底事非前定，我與東齋似有緣。',64,'全唐诗/poet.song.146000.json','["人生底事非前定，我與東齋似有緣。", "別去風光只如昨，重來花木已經年。", "曾將問答趨參席，愧把才名據鄭氈。", "却憶西堂舊詩友，幾番風雨對床眠。"]'),
('a11eee3d-39f7-49bb-ab06-2691f7fccabf','次韻沈若院見贈','項安世','宋','宋诗','song-poetry','','[]','三載鳴絃宓不齊，姓名飛動玉宸知。',64,'全唐诗/poet.song.146000.json','["三載鳴絃宓不齊，姓名飛動玉宸知。", "從來蘭省絲綸署，夢入梔林草木詩。", "我亦放言聊爾耳，君真施手事于斯。", "爲寮况是張公子，錦筆淋浪日對持。"]'),
('f24dd4b9-6b01-45a1-a750-e5b6352d6295','秋日陪使君飲章華臺','項安世','宋','宋诗','song-poetry','','[]','堂堂雲夢接天開，蓽路規模亦壯哉。',64,'全唐诗/poet.song.146000.json','["堂堂雲夢接天開，蓽路規模亦壯哉。", "自是邊城多古意，那堪秋日更荒臺。", "諸侯聚散羣鷄宿，百代興亡一雁來。", "一舉使君三大白，奈何胸次鬰崔嵬。"]'),
('18eeac3d-0dec-4723-ad6c-8273c4c319b9','還過郢城','項安世','宋','宋诗','song-poetry','','[]','頭白初行郢水邊，故城千載尚依然。',64,'全唐诗/poet.song.146000.json','["頭白初行郢水邊，故城千載尚依然。", "豈無戍卒持鉦鼓，應有居人沸管弦。", "今日桑麻成沃野，幾家茅竹散平川。", "停車欲問當時事，紅日翩翩下翠烟。"]'),
('be4ff6f6-45d3-443b-9980-b6f07d6d2fc4','六日寄鎮江馬侍郎大同','項安世','宋','宋诗','song-poetry','','[]','十四年前楚水傍，碧油幢下拜輝光。',64,'全唐诗/poet.song.146000.json','["十四年前楚水傍，碧油幢下拜輝光。", "鮒魚躑躅遵行潦，龍馬騰凌出大荒。", "珥筆南宮扶日月，橫戈北府控昇陽。", "冷官只有酸寒分，又把藜燈照蘗黄。"]'),
('ee977338-4282-424b-a601-a2ce68c62a60','道山風雨','項安世','宋','宋诗','song-poetry','','[]','年華澹灧滿皇州，時節凄凉限勝遊。',64,'全唐诗/poet.song.146000.json','["年華澹灧滿皇州，時節凄凉限勝遊。", "雨後石渠新水長，風前芸閣晚香愁。", "不堪萬點梅花老，强倚千絲柳带柔。", "又是長安一百五，春陰漠漠未能休。"]'),
('4e050b18-aa79-4d82-b62e-e819aac197b0','題王醇甫秀才海隠齋','項安世','宋','宋诗','song-poetry','','[]','萬人如海最堪藏，何必南山有豹章。',64,'全唐诗/poet.song.146000.json','["萬人如海最堪藏，何必南山有豹章。", "避世金門師曼倩，變名桐瀨笑嚴光。", "睡龍淵底珠潜色，抵鵲山頭玉混芒。", "不比尋常溝瀆裏，蛙跳雀浴便張皇。"]'),
('a73772e5-59ae-427f-864a-67a5be19da8d','久齋詩爲南康趙司戶作','項安世','宋','宋诗','song-poetry','','[]','歲寒始見松將柳，道遠方分驥若駑。',64,'全唐诗/poet.song.146000.json','["歲寒始見松將柳，道遠方分驥若駑。", "鑿井爲山新意氣，斷幹穿石老工夫。", "重湖水作葡萄漲，五老雲成錦繡鋪。", "萬古千秋模不盡，幾家文集幾家圖。"]'),
('9e00a546-cb9f-47eb-8c6d-a2c75ec1a0ba','遊齊山','項安世','宋','宋诗','song-poetry','','[]','半生作夢身初到，此日遊山興可知。',64,'全唐诗/poet.song.146000.json','["半生作夢身初到，此日遊山興可知。", "小蓋曲穿楊柳岸，平輿斜掠槿花籬。", "層軒俯瞰人寰狹，陰洞幽尋古路危。", "滿寺留題誰最警，南唐人寫晚唐詩。"]'),
('e8a0071b-898e-485f-b8b3-8d695198f813','謝姜夔秀才示詩卷從千巖蕭東甫學詩','項安世','宋','宋诗','song-poetry','','[]','千巖一派落都城，承露金盤爾許清。',64,'全唐诗/poet.song.146000.json','["千巖一派落都城，承露金盤爾許清。", "古體黄陳家格律，短章溫李氏才情。", "等閑又得詩人處，咫尺相過故將營。", "想見紅塵烏帽底，幾多懷玉未知名。"]'),
('bb65740d-c73d-4c0c-8af1-460bf096b0d4','監利許知縣見示詩卷','項安世','宋','宋诗','song-poetry','','[]','哦君五十四篇詩，燃盡青藜杖一枝。',64,'全唐诗/poet.song.146000.json','["哦君五十四篇詩，燃盡青藜杖一枝。", "長韻屈平經裏思，短章介甫集中辭。", "只因雲夢曾遊耳，便把江山盡得之。", "割我錦機君已甚，不須更遣世人知。"]'),
('ca6a108c-d1a8-4670-a033-d89175c0a480','謝王草場示詩卷','項安世','宋','宋诗','song-poetry','','[]','王郎老句合超羣，曾是東萊語夜分。',64,'全唐诗/poet.song.146000.json','["王郎老句合超羣，曾是東萊語夜分。", "多向斷崖生絕景，或于晴野度輕雲。", "舊吟古意無人解，新住荒園免世紛。", "特地籃輿穿北郭，已聞藜杖過前村。"]'),
('cf0e9a74-dec4-4760-8632-2a0a347c5ed6','送陳正己赴調','項安世','宋','宋诗','song-poetry','','[]','一寸丹心百念更，滿簪華髮萬人驚。',64,'全唐诗/poet.song.146000.json','["一寸丹心百念更，滿簪華髮萬人驚。", "閑拋歲月供書冊，長把饑寒爲友生。", "此事不輕身出處，諸公可念政和平。", "昔藏名字依沅水，今逐帆檣覲漢京。"]'),
('e448bdf0-27b6-4216-995a-861d6b3ae344','送任三舅赴調','項安世','宋','宋诗','song-poetry','','[]','火雲燒浪峽中歸，朔雪橫江又語離。',64,'全唐诗/poet.song.146000.json','["火雲燒浪峽中歸，朔雪橫江又語離。", "一世由來迎送裏，多才好去盛明時。", "人知與我爲兄弟，或欲從君問鬢髭。", "爲說掌中亡玉樹，中年懷抱總堪知。"]'),
('60b1ef09-3a57-4fe1-bd03-c1537a87f6f0','次韻新瀘南張安撫送行','項安世','宋','宋诗','song-poetry','','[]','滄湖居士楚江臯，勸我嘉州竹葉醪。',64,'全唐诗/poet.song.146000.json','["滄湖居士楚江臯，勸我嘉州竹葉醪。", "侍立郎君清玉雪，贈行詩句妙風騷。", "懷人眷眷辭多苦，接物卑卑道更高。", "自聽津亭三日語，掃除湖海一生豪。"]'),
('6747c8c7-a99f-452b-b198-ca85356e912f','雪後出西偏門迓鄭安撫','項安世','宋','宋诗','song-poetry','','[]','四郊殘雪未成泥，十里籃輿雜馬蹄。',64,'全唐诗/poet.song.146000.json','["四郊殘雪未成泥，十里籃輿雜馬蹄。", "道上行人梭樣織，日邊雲氣剪相齊。", "山圍鏡野成環玦，東折冰河散璧珪。", "獨立跨河橋上望，共誰同說馬公堤。"]'),
('a7b4bca7-262d-47d7-ac48-8060319b2e2a','次韻奉東溪劉居士','項安世','宋','宋诗','song-poetry','','[]','雪領飄蕭電目明，老于塵裏詎沾塵。',64,'全唐诗/poet.song.146000.json','["雪領飄蕭電目明，老于塵裏詎沾塵。", "惠連已解傳吾句，元亮何妨得此身。", "詩卷酒盃爲事業，藥囊丹鼎自君臣。", "幅巾短褐長安市，誰識東溪直釣人。"]'),
('5851d82d-665b-4ca0-9aa4-c782d66bb628','送吳察院赴江西運使','項安世','宋','宋诗','song-poetry','','[]','春風同上杏園韉，夜雨江湖十九年。',64,'全唐诗/poet.song.146000.json','["春風同上杏園韉，夜雨江湖十九年。", "冊府歸來頭併雪，鼎湖仙去淚盈川。", "喜君冠豸裨新政，容我祛蟬校舊編。", "忽見繡衣南浦去，亦思小艇白鷗邊。"]'),
('80f07e08-8267-4db6-a65d-40c1b4f2af2a','次韻鄭檢法休日律詩','項安世','宋','宋诗','song-poetry','','[]','一閑早已被閑魔，忙日求閑更幾何。',64,'全唐诗/poet.song.146000.json','["一閑早已被閑魔，忙日求閑更幾何。", "稍向靜中觀物化，未妨聖處策勳多。", "官曹似我方成冷，詩句如君可得過。", "小待州橋好風雪，碎敲吟𩍐逐清歌。"]'),
('0a4a05f8-560e-4f15-a6f8-8322e7d31f26','次韻潘都幹喜楊中庫歸督其和詩','項安世','宋','宋诗','song-poetry','','[]','鳴鶑三嘆友聲詩，底事聞壎未應箎。',64,'全唐诗/poet.song.146000.json','["鳴鶑三嘆友聲詩，底事聞壎未應箎。", "嗟我金蘭多寡彼，賁然風月喜來思。", "將軍老去猶橫槊，壯士前行莫退綏。", "只恐監軍門下客，未容戎幕舉三麾。"]'),
('597b8bff-bff2-42aa-b7f4-bb10efc0e2b6','再次韻贈潘楊二君二首  其一','項安世','宋','宋诗','song-poetry','','[]','今代潘郎老作詩，友聲相應速如箎。',64,'全唐诗/poet.song.146000.json','["今代潘郎老作詩，友聲相應速如箎。", "燃萁短句寧論步，聯鼎長吟不待思。", "武事解歌三箭定，文容堪頌萬邦綏。", "從公更覓中和什，慚愧無因把蜀麾。"]'),
('5935ee00-13c0-44e0-9371-993b6f4fe7d4','再次韻贈潘楊二君二首  其二','項安世','宋','宋诗','song-poetry','','[]','楊子高才作小詩，似裁推管製纖箎。',64,'全唐诗/poet.song.146000.json','["楊子高才作小詩，似裁推管製纖箎。", "亂流不怕公無渡，絕險寧愁我所思。", "百鎰黄金裝馬首，五文繡段繫車綏。", "橫行海內無堅陣，目短曹劉不足麾。"]'),
('96498eec-dbb9-415e-9b18-59dbfc9b7448','又用韻酬贈潘楊二首  其一','項安世','宋','宋诗','song-poetry','','[]','物物當前總是詩，遇絲成瑟竹成箎。',64,'全唐诗/poet.song.146000.json','["物物當前總是詩，遇絲成瑟竹成箎。", "止呼大義周王澤，蔽以無邪孔氏思。", "屈賈詞悲變弁凱，齊梁格靡陷崔綏。", "欲回溫厚千年教，須仗詩翁爲一麾。"]'),
('67627f04-9994-4ccc-8182-22f17ec5b00d','又用韻酬贈潘楊二首  其二','項安世','宋','宋诗','song-poetry','','[]','四海誠齋獨霸詩，世無仲氏敢言箎。',64,'全唐诗/poet.song.146000.json','["四海誠齋獨霸詩，世無仲氏敢言箎。", "周公費誓傳禽父，宣聖中庸授子思。", "鍾子期家應善聽，郵無卹後定能綏。", "真傳更在吟哦外，大節如山不授麾。"]'),
('97ede0df-b688-48d1-8094-ab5c608879f5','再次韻謝潘都幹','項安世','宋','宋诗','song-poetry','','[]','壯士從軍不廢詩，何妨笳鼓間簫箎。',64,'全唐诗/poet.song.146000.json','["壯士從軍不廢詩，何妨笳鼓間簫箎。", "秋城夜觀無公事，月脅天心有詠思。", "歲稔公私方暇樂，時平福履正來綏。", "金陵風月三千首，共看君侯羽扇麾。"]'),
('af5d9683-6299-43fa-833d-7a0b5fff9282','次韻趙僉判投贈','項安世','宋','宋诗','song-poetry','','[]','三復新篇吻爲乾，載賡餘韻甲生顔。',64,'全唐诗/poet.song.146000.json','["三復新篇吻爲乾，載賡餘韻甲生顔。", "今無愈湜陪長吉，古有嚴徐伴小山。", "秀出猗蘭仙李外，思留春草桂枝閒。", "從來只有詩人苦，可笑王孫不自閑。"]'),
('1f426241-f960-4d6f-9205-c4876e456573','再次韻趙僉判投贈','項安世','宋','宋诗','song-poetry','','[]','天街何日雨雲乾，夢想王孫白玉顔。',64,'全唐诗/poet.song.146000.json','["天街何日雨雲乾，夢想王孫白玉顔。", "一日能從晦巖子，十年不負會稽山。", "吟詩可但師唐白，服禮終期類漢間。", "萬事總當如廕戶，己私除盡即心閑。"]'),
('bc5db942-05c4-4469-ad74-ecbea5cf1a25','次韻黄縣尉祁陽遇全州試官同歸','項安世','宋','宋诗','song-poetry','','[]','粉字朱牌簇縣津，綠蓑青笠洗行塵。',64,'全唐诗/poet.song.146000.json','["粉字朱牌簇縣津，綠蓑青笠洗行塵。", "一時客路同歸棹，半是年家及里人。", "秦代徵君巖上石，吳時霸主澗中神。", "休將短髮供離恨，早卜寬鄉作酒隣。"]'),
('b987ba45-02a1-4fb7-b5c7-e4d47679794a','次韻寄謝楊制機','項安世','宋','宋诗','song-poetry','','[]','把卷愴然不自勝，古來離合豈人能。',64,'全唐诗/poet.song.146000.json','["把卷愴然不自勝，古來離合豈人能。", "未應鬻髢尤窮髮，暫喜餐蔬得枕肱。", "身逐南雲親色養，夢尋巴瘴隔心朋。", "囊中貝母煩分惠，獨學仍愁舊病增。"]'),
('4ffa7dc8-d729-4e15-af62-0d7eee88c0c5','休日過劉寺','項安世','宋','宋诗','song-poetry','','[]','綠髮蕭蕭變白頭，二年京洛不堪愁。',64,'全唐诗/poet.song.146000.json','["綠髮蕭蕭變白頭，二年京洛不堪愁。", "雨天賜沐逢新霽，烟寺分茶得舊遊。", "古蔓巧當陰洞掛，驚泉逆上畫簷流。", "曲欄干外山如染，最是橋亭合小留。"]'),
('ae4fb80b-e196-4d43-af8c-833ec987918d','再次前韻唁南湖放鶑燕','項安世','宋','宋诗','song-poetry','','[]','誰向南湖賦白頭，西風團扇有新愁。',64,'全唐诗/poet.song.146000.json','["誰向南湖賦白頭，西風團扇有新愁。", "歸巢海燕無多日，出谷暖鶑何處遊。", "文杏梁邊泥尚濕，綠楊堤畔水長流。", "有情莫掃園中路，舞影歌塵處處留。"]'),
('f3361d1b-59a6-461f-bdc3-71920e205c10','次韻贈東湖周子問','項安世','宋','宋诗','song-poetry','','[]','玉鏁凌空不可攀，卧聽車馬日三竿。',64,'全唐诗/poet.song.146000.json','["玉鏁凌空不可攀，卧聽車馬日三竿。", "以湖拜命官名散，把酒封君國號歡。", "父祖詩家三世將，弟兄文陣兩秦難。", "年豐母健無餘事，長作人間謝客蘭。"]'),
('ed666198-aaf5-434d-8c82-62c4a6c8d49c','再次前韻答高秀才言詩','項安世','宋','宋诗','song-poetry','','[]','萬仞崢嶸赤手攀，但能進步莫憂竿。',64,'全唐诗/poet.song.146000.json','["萬仞崢嶸赤手攀，但能進步莫憂竿。", "一生便作苦吟去，萬事何如得句歡。", "鼓氣易衰憐我退，市聲方午似君難。", "丈夫不用分畦畛，臭味從今蕙與蘭。"]'),
('d4431366-8b9a-48d2-ac58-60e2315080aa','次韻張祕書春日憶莊賢良','項安世','宋','宋诗','song-poetry','','[]','卿家客子幾當歸，問訊頻煩守舍兒。',64,'全唐诗/poet.song.146000.json','["卿家客子幾當歸，問訊頻煩守舍兒。", "篋裏蠹魚穿故帙，壁間漏雨濕殘碑。", "夢魂欲往春迷路，心事相望月到題。", "樵斧丁丁上雲谷，有齋何用慰斯饑。"]'),
('6d755181-aa6e-440f-8f82-7c7e0c779b00','次老沈秀才韻','項安世','宋','宋诗','song-poetry','','[]','千駟不數齊封君，西山餓夫萬古名。',64,'全唐诗/poet.song.146000.json','["千駟不數齊封君，西山餓夫萬古名。", "勢利須臾覆手雨，邱壑耐久無心兵。", "有田二頃多種秫，栽蘭九畹當餐英。", "他年會有佳客過，東老向來如此清。"]'),
('091634e0-cc62-4275-9beb-78cc0be6fdb2','次韻答吳阜之投贈','項安世','宋','宋诗','song-poetry','','[]','沈沈寒甃綆千尋，澹澹疎絃瑟五音。',64,'全唐诗/poet.song.146000.json','["沈沈寒甃綆千尋，澹澹疎絃瑟五音。", "讀罷自今三太息，個中應有一生心。", "君真骨相超凡馬，我已情懷學展禽。", "肯爲明時當許事，科場文字未須深。"]'),
('3ab869ce-65e0-4961-8eb7-5f0ba91ad609','十九日至都門次鞏仲至立春日見寄韻','項安世','宋','宋诗','song-poetry','','[]','客子沙頭飲餞時，美人溪上正題詩。',64,'全唐诗/poet.song.146000.json','["客子沙頭飲餞時，美人溪上正題詩。", "栗齋寒盡相思早，竹閣春閑拜賜遲。", "別後著書逾汗馬，閑中讀易見靈龜。", "何由洗硯居兄左，快斧麾天看一斯。"]'),
('18907e5c-a158-4499-8565-cefbfdab4d97','次韻張部門','項安世','宋','宋诗','song-poetry','','[]','管領孤梅近小窗，推排茗椀當壺漿。',64,'全唐诗/poet.song.146000.json','["管領孤梅近小窗，推排茗椀當壺漿。", "且然入局無公事，除却申臺有印章。", "飯已抄經臨小楷，興餘揮句落斜行。", "不堪平日詩千首，剛被人求米萬箱。"]'),
('ccf722ec-0684-4732-ae00-da602cba3f88','九日喜陳一之提刑至龍山','項安世','宋','宋诗','song-poetry','','[]','聞道西征使者來，滿城風雨菊花開。',64,'全唐诗/poet.song.146000.json','["聞道西征使者來，滿城風雨菊花開。", "喚回烏帽千年夢，驚倒龍山百尺臺。", "病叟舊痾初去體，元戎新醖恰浮醅。", "籬邊更有休官令，人事天機亦異哉。"]'),
('b8666d2e-60c4-409a-8c15-1201462d3e97','續聞李季章提刑舟到用前韻迎之','項安世','宋','宋诗','song-poetry','','[]','今日何居忽鼎來，眉心黄氣十分開。',64,'全唐诗/poet.song.146000.json','["今日何居忽鼎來，眉心黄氣十分開。", "青簾穩下東三峽，繡斧相逢兩外臺。", "抱病拾遺脩破帽，罷官陶令覓殘醅。", "未知千古龍山下，有此重陽盛事哉。"]'),
('366752a3-9bfd-4d94-92e3-9514f9e1a594','和陳正己九日公安道中韻','項安世','宋','宋诗','song-poetry','','[]','何處山無九日花，故人相遇即爲家。',64,'全唐诗/poet.song.146000.json','["何處山無九日花，故人相遇即爲家。", "君方去著風前帽，我已寒如露後葭。", "久閉柴門陶歲月，晚憑兒子送生涯。", "眼看一樹堂堂去，雙鬢那能不早華。"]'),
('ea43a929-57b2-491b-9437-5130e6fdc901','次韻王少清重陽','項安世','宋','宋诗','song-poetry','','[]','旋收積雨放秋陽，天亦慇懃慰酒腸。',64,'全唐诗/poet.song.146000.json','["旋收積雨放秋陽，天亦慇懃慰酒腸。", "籬下看花元自逸，公前露首固非狂。", "芙渠幕底鄉心動，竹葉杯中古意長。", "每到佳時懷舊隠，羨君猶爾愧吾忘。"]'),
('6be0adf9-6a40-494c-a962-485cf097a558','次韻承甫兄重陽','項安世','宋','宋诗','song-poetry','','[]','露入楓林葉未黄，風將花信到南陽。',64,'全唐诗/poet.song.146000.json','["露入楓林葉未黄，風將花信到南陽。", "一年好處詠九日，四海幾人雕寸腸。", "偶爾至今成故事，亦須隨分繫萸囊。", "陶生孟祖當時意，可但區區爲一觴。"]'),
('4936269b-7427-46a0-b03e-dc698ecc1bb5','涪陵令李坤幼隨母冒姓今復姓王','項安世','宋','宋诗','song-poetry','','[]','孝子平生三釜悲，故人解后一寒疑。',64,'全唐诗/poet.song.146000.json','["孝子平生三釜悲，故人解后一寒疑。", "亦知自講陶朱事，不同戲題臣向詩。", "舊日夫人稱李衛，如今弟子即羲之。", "姓同名獨吾何憾，厚德真堪慰所思。"]'),
('63336c74-a54d-4331-b8e9-7b61d44dace7','次韻送新潜江滕令  其一','項安世','宋','宋诗','song-poetry','','[]','髯滕筆力萬鈞强，少日詩聲遠擅場。',64,'全唐诗/poet.song.146000.json','["髯滕筆力萬鈞强，少日詩聲遠擅場。", "身著青衫頭半白，腰懸銅印綬仍黄。", "魚來俞市鮮無數，酒滿龍淵樂詎央。", "若許爲氓仁政裏，一廛烟水受漁郎。"]'),
('222615e2-508c-42a5-8a76-c4d0593c0161','次韻送新潜江滕令  其二','項安世','宋','宋诗','song-poetry','','[]','縣南堤破戶全逃，縣北堤存尚可苗。',64,'全唐诗/poet.song.146000.json','["縣南堤破戶全逃，縣北堤存尚可苗。", "春野縱耕無吠犬，秋場一笑足迎貓。", "解牛巨手烹鬵水，戲彩深情化哺梟。", "時喚雲洲論小篆，少於韓蔡老於潮。"]'),
('f7f1d8db-c17b-4d49-892d-c8587acfe5b3','送任壽朋赴襄陽令  其一','項安世','宋','宋诗','song-poetry','','[]','際天南北麳麰盛，夾漢東西巘崿長。',64,'全唐诗/poet.song.146000.json','["際天南北麳麰盛，夾漢東西巘崿長。", "爲客曾誇心膽壯，送君今嘆鬢毛蒼。", "五官置屬蓮成蕩，七校屯兵柳作行。", "中有書生騎瘦馬，自弦焦木種甘棠。"]'),
('0c954dd3-fba6-4182-99e5-8caab2b51bb2','送任壽朋赴襄陽令  其二','項安世','宋','宋诗','song-poetry','','[]','潭心山頂碑何在，鳳翥龍翔夢亦非。',64,'全唐诗/poet.song.146000.json','["潭心山頂碑何在，鳳翥龍翔夢亦非。", "野鍤狼烟參井畝，城開鴈翅入江圻。", "蟠胸蠹帙千年富，手到鷄鋒一吷微。", "應待經行阡陌徧，喚登文石問兵機。"]'),
('088cf94b-dd90-4bda-bb78-65c7abb4816e','重過鄂州','項安世','宋','宋诗','song-poetry','','[]','南柯夢散不知年，東海騎鯨作醉仙。',64,'全唐诗/poet.song.146000.json','["南柯夢散不知年，東海騎鯨作醉仙。", "我自偶經前赤壁，誰言曾倚舊青氈。", "轅門甲馬三更發，古寺鐘魚一夏眠。", "慚愧白棠花下叟，當時芻狗尚流傳。"]'),
('365d4a78-8587-4521-928c-39a0640e089c','晴日迓江西帥徐子宣','項安世','宋','宋诗','song-poetry','','[]','漢殿東頭玉琯回，吳城西上錦帆開。',64,'全唐诗/poet.song.146000.json','["漢殿東頭玉琯回，吳城西上錦帆開。", "一天紫霧風吹散，千丈紅光日射來。", "翼軫衡廬生喜氣，江湖淮海絕纖埃。", "凄凉只有山前客，何日臨津理去桅。"]'),
('08826547-b337-466e-8beb-c0d36d63a50b','和宋帥出示所送李大著詩  其一','項安世','宋','宋诗','song-poetry','','[]','掖垣清夜十年愁，夢遶西南處處州。',64,'全唐诗/poet.song.146000.json','["掖垣清夜十年愁，夢遶西南處處州。", "忽向江陵逢太白，同嘲楚國看倡優。", "梅花賦就行人遠，白雪歌殘兩槳流。", "日暮江空魂欲斷，更題九辯說悲秋。"]'),
('4ca7bb7b-da17-441d-acf1-1d386c28457a','和宋帥出示所送李大著詩  其二','項安世','宋','宋诗','song-poetry','','[]','樓前人送四前旌，樓上詩添七字成。',64,'全唐诗/poet.song.146000.json','["樓前人送四前旌，樓上詩添七字成。", "蔽芾風中皆德意，黍苗雅裏盡仁聲。", "請回南國條枚筆，歸主中朝禮樂盟。", "天下舉安吾始樂，時哉王道正和平。"]'),
('6fd8ef70-3b38-4ceb-8407-3022c59fec52','和宋帥出示所送李大著詩  其三','項安世','宋','宋诗','song-poetry','','[]','病中三復舍人篇，可但才工與調妍。',64,'全唐诗/poet.song.146000.json','["病中三復舍人篇，可但才工與調妍。", "心在雩壇沂水上，思通歸鳥岫雲邊。", "自將鐵石爲傳授，不與風騷較襲沿。", "聽者座中誰最喜，丹邱道士舞如顛。"]'),
('d82759a9-f469-4ed9-9584-54fd71314cf5','次韻答劉正將','項安世','宋','宋诗','song-poetry','','[]','落魄劉郎住藕池，湖南湖北竹枝詞。',64,'全唐诗/poet.song.146000.json','["落魄劉郎住藕池，湖南湖北竹枝詞。", "風流故有諸孫句，絕妙都如幼婦碑。", "玉斗歌成微醉後，銀河曲就淺寒時。", "文章自倚兼餘體，不分人來只看詩。"]'),
('96ddb2bf-434c-425b-b223-c7285222bc7a','次前韻答徐監門','項安世','宋','宋诗','song-poetry','','[]','依環倣磬作園池，戛玉鏗金出好詞。',64,'全唐诗/poet.song.146000.json','["依環倣磬作園池，戛玉鏗金出好詞。", "世擅文章從魏氏，家傳仁義見韓碑。", "抱關碌碌卑飛日，去國遲遲獨往時。", "相值兩窮方有味，短牋朝暮送新詩。"]'),
('3e13c96d-8f83-4033-9621-cffc3e788e38','次韻答蜀人薛仲章','項安世','宋','宋诗','song-poetry','','[]','只憐久病劉公幹，不羨多騶鄧仲華。',64,'全唐诗/poet.song.146000.json','["只憐久病劉公幹，不羨多騶鄧仲華。", "解寄長年新句法，頗思前夜好燈花。", "自離窗外千秋雪，長看天西一色霞。", "想見疎桐凉月下，幽鴻無伴立寒沙。"]'),
('dfad4f87-b6aa-4cc0-8aae-f81a19c883a1','讀杜賢良文卷','項安世','宋','宋诗','song-poetry','','[]','舉公售淺戒深鈎，學士談根諱末流。',64,'全唐诗/poet.song.146000.json','["舉公售淺戒深鈎，學士談根諱末流。", "萬古斯文真一髮，百年逢子散千愁。", "氣雄聲正師韓集，格重詞妍似柳侯。", "天遣孤窮應有意，未追彖繫莫輕休。"]'),
('d312a756-286e-4bd8-9208-f8eedecb77df','同年董知縣席上','項安世','宋','宋诗','song-poetry','','[]','十五年前玉頰紅，長安道上氣如虹。',64,'全唐诗/poet.song.146000.json','["十五年前玉頰紅，長安道上氣如虹。", "集英廊迥含霄露，後市樓高納海風。", "解后一涯俱潦倒，摩挲雙鬢各蓬鬆。", "酒邊更用分疎在，明日相看總是翁。"]'),
('dda31117-186f-489d-9b3c-416bc2eff91a','送羅機宜秩滿東歸三首  其一','項安世','宋','宋诗','song-poetry','','[]','不愛征西入幕賓，只圖抽得最閑身。',64,'全唐诗/poet.song.146000.json','["不愛征西入幕賓，只圖抽得最閑身。", "畧無崖岸胸懷白，洞見中邊德行淳。", "但用至誠裨府主，不將高論詫時人。", "如今獻納須公可，若是朱雲却未仁。"]'),
('08eca3ac-9ec7-4c80-abc4-718f94392462','送羅機宜秩滿東歸三首  其二','項安世','宋','宋诗','song-poetry','','[]','風髯飛動儼長身，縹渺襟期不受塵。',64,'全唐诗/poet.song.146000.json','["風髯飛動儼長身，縹渺襟期不受塵。", "豈是恝然忘應物，亦知蕞爾漫勞人。", "若非事業驚當世，也合文章作近臣。", "此外世間無處著，却須汗漫跨麒麟。"]'),
('2eb2d393-8561-4a52-bce9-81e04f998e7f','送羅機宜秩滿東歸三首  其三','項安世','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十年爲客古南都，不謂斯行得範模。',64,'全唐诗/poet.song.146000.json','["十年爲客古南都，不謂斯行得範模。", "我自閲人惟見此，公言有弟更勝吾。", "金堤碧瓦新遊覽，綠竹紅薇舊醉呼。", "短別未應勞夢寐，定來騎馬看西湖。"]'),
('de99f3ee-6248-4374-9b39-ff9e44af3cab','送樓國正罷荆幕東歸','項安世','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','一江秋水散芙蕖，笑買扁舟下五湖。',64,'全唐诗/poet.song.146000.json','["一江秋水散芙蕖，笑買扁舟下五湖。", "北學自憐非楚産，東歸安得與公俱。", "同年進士今丞相，六館諸生舊講徒。", "朱橘白魚留不住，洞庭橙熟有新鱸。"]'),
('24141850-9f89-459d-899d-cedd8fa926ba','贈韓術士','項安世','宋','宋诗','song-poetry','','[]','睡過春星十二番，牙疏髮脫久知難。',64,'全唐诗/poet.song.146000.json','["睡過春星十二番，牙疏髮脫久知難。", "捉將官裏兵良苦，放入山間枕乍安。", "舉世知君能安式，不愁無客問彈冠。", "毋多奪我枚回渚，厚笠輕蓑老竹竿。"]'),
('78e8cf5d-8df7-4083-85d2-838d39c804e1','送潜江令徐盈','項安世','宋','宋诗','song-poetry','','[]','漢江西畔蜀江東，中有荆王古縣公。',64,'全唐诗/poet.song.146000.json','["漢江西畔蜀江東，中有荆王古縣公。", "蒍艾獵來民見德，穀於菟去士傳忠。", "肝腸可奈平生苦，機杼胡庸抵死窮。", "君寵親恩俱望報，直須平易與天通。"]'),
('a4ad7cb5-c34b-498b-839e-5402f807974a','和韻答都昌胡令論詩','項安世','宋','宋诗','song-poetry','','[]','竹屋蘆門映短牆，夜深宜月曉宜霜。',64,'全唐诗/poet.song.146000.json','["竹屋蘆門映短牆，夜深宜月曉宜霜。", "青山顧我如相識，白水粘天似故鄉。", "光景萬端皆好句，肝腸百鍊見真剛。", "今君正與民同樂，安得清愁滿腹裝。"]'),
('184db04a-d1c6-4152-8ca1-b2c3c0b6f87a','夾得胡仲芳詩次韻','項安世','宋','宋诗','song-poetry','','[]','天遣清明作小寒，人從赤壁上青山。',64,'全唐诗/poet.song.146000.json','["天遣清明作小寒，人從赤壁上青山。", "頗宜書更形骸外，頼有詩猶意氣間。", "一日水程無幾住，百篇火急莫令慳。", "杖藜徑入漁樵去，從此因君得往還。"]'),
('26f52801-35f7-4b3a-b57c-ad5c86972afa','劉都翰送伊川山谷二像','項安世','宋','宋诗','song-poetry','','[]','十年道學誠明處，四海詩篇雅頌餘。',64,'全唐诗/poet.song.146000.json','["十年道學誠明處，四海詩篇雅頌餘。", "元祐向來基宥密，涪江相逐伴樵漁。", "坐中蒼白誰安立，身後丹青獨久如。", "再拜兩公何所見，衣巾端肯過吾廬。"]'),
('41667490-a1ee-478d-9b55-e3bf17322d42','和陳信民用韻以高撫州之命相招','項安世','宋','宋诗','song-poetry','','[]','入無錐瓦出無閭，笑殺康山老寄居。',64,'全唐诗/poet.song.146000.json','["入無錐瓦出無閭，笑殺康山老寄居。", "客裏光陰何以度，閑中親舊頓然疎。", "武岡文學來投卷，臨汝君侯肯致書。", "早晚一犂親受地，時於笠底望行車。"]'),
('b149dcb2-6c9e-47eb-9a96-835b0237e2f7','次韻鄉人賀歸','項安世','宋','宋诗','song-poetry','','[]','早知芳樹不如歸，底用青天接翅飛。',64,'全唐诗/poet.song.146000.json','["早知芳樹不如歸，底用青天接翅飛。", "但了寢門安與否，更關城廓是和非。", "預愁計日當還次，安得窮年只掩扉。", "羨殺能詩西閣老，一菴依舊鬢毛稀。"]'),
('9857ef9f-a181-4653-af83-689433667f04','張晉用晦自西和州來歸','項安世','宋','宋诗','song-poetry','','[]','江海張公亦壯哉，雪蛆生處守邊來。',64,'全唐诗/poet.song.146000.json','["江海張公亦壯哉，雪蛆生處守邊來。", "緜裘六月冰如鐵，土焙三更冷似灰。", "棧踏曾雲歸蜀道，船欺急淖下瞿堆。", "沙頭病士眠初熟，又見征人萬里回。"]'),
('6207137c-439b-458c-8267-08634beef10d','過無錫寄沈知縣','項安世','宋','宋诗','song-poetry','','[]','同時月殿氣如虹，各自天涯影似蓬。',64,'全唐诗/poet.song.146000.json','["同時月殿氣如虹，各自天涯影似蓬。", "半世弟兄纔一識，二年州縣忽重逢。", "湘山飽聽靈妃瑟，錫水新彈單父桐。", "剩有江湖不歸話，回船相就却從容。"]'),
('cdea71f6-4995-491e-a4e6-2dfa1fe40412','過秀寄麋祕書','項安世','宋','宋诗','song-poetry','','["\u897f\u6e56"]','圓嶠仙人厭久如，戲求同穎作周書。',64,'全唐诗/poet.song.146000.json','["圓嶠仙人厭久如，戲求同穎作周書。", "半生聞誼親無路，一日同僚分有餘。", "西子湖邊春載酒，征官亭上夜分裾。", "秋來懷抱知多少，總是歸程細細攄。"]'),
('dc45948e-4060-4a17-b912-c1123b736e03','成都二月十五日補試院呈同官','項安世','宋','宋诗','song-poetry','','[]','向來耆舊日爭輝，太息西來萬事非。',64,'全唐诗/poet.song.146000.json','["向來耆舊日爭輝，太息西來萬事非。", "一笑烘堂吾豈敢，百年憂世淚仍揮。", "洋洋大國風流在，奄奄諸生氣息微。", "欲挽岷江注東海，吾衰無力只思歸。"]'),
('6a9f67ea-8dc5-46c3-95cb-2e499bf0d2fd','三次劉寺韻賦張以道新居與約齋夾湖相望  其一','項安世','宋','宋诗','song-poetry','','[]','寒綠新軒對馬頭，陂南陂北□銷愁。',64,'全唐诗/poet.song.146000.json','["寒綠新軒對馬頭，陂南陂北□銷愁。", "合添漁艇兩三隻，時與約齋來往遊。", "欹枕孤鴻煙雨漲，鈎簾宿鷺曉光流。", "何時祭竈呼鄰里，我欲題詩素壁留。"]'),
('fda42ada-40e8-4aa2-91c5-b18e81c0d04f','三次劉寺韻賦張以道新居與約齋夾湖相望  其二','項安世','宋','宋诗','song-poetry','','[]','碧柳黄蘆冷映門，荒陂寒水浄涵村。',64,'全唐诗/poet.song.146000.json','["碧柳黄蘆冷映門，荒陂寒水浄涵村。", "深深留殿朝常閉，肅肅行營夜不喧。", "景似邱園宜避俗，事非風月總忘言。", "平生故有閑吟分，何物堪酬造化恩。"]'),
('3be98223-9490-4464-80a1-55a829e0d6f0','再用絲字韻謝張留守垂訪新居','項安世','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','畫出城都客子詩，元戎真赴野人期。',64,'全唐诗/poet.song.146000.json','["畫出城都客子詩，元戎真赴野人期。", "白沙翠竹新晴罷，紅旆青油小隊移。", "聖世散材甘永棄，師門曲木未全遺。", "驚魄已作逃絃鴈，只願長江理釣絲。"]'),
('3fd36d41-638e-4b9b-ad7b-e023043729d9','再送陳沅江','項安世','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','三年食茆厭冰廳，一日栽桃遶带城。',64,'全唐诗/poet.song.146000.json','["三年食茆厭冰廳，一日栽桃遶带城。", "水入洞庭天正闊，山連黔徼地偏清。", "醉歌屈子醒時賦，琴和湘娥瑟外聲。", "若到江濱逢九肋，爲言稀有是輕生。"]'),
('280a311f-7bf1-480c-bc34-7896e7af2ccf','三送陳沅江','項安世','宋','宋诗','song-poetry','','[]','苦死相留不療饑，再三相送只添詩。',64,'全唐诗/poet.song.146000.json','["苦死相留不療饑，再三相送只添詩。", "金蘭去我方嫌速，襦袴催公莫恨遲。", "碧海聲名無右者，玉霄歧路合東之。", "未應白髮清溪上，長傍孤篷理釣絲。"]'),
('78f8c210-0f2f-46ae-95e1-9a4d6aa573db','再得崇道觀寄王左史','項安世','宋','宋诗','song-poetry','','[]','藥鼎無時手自煎，萬囊長在枕頭邊。',64,'全唐诗/poet.song.146000.json','["藥鼎無時手自煎，萬囊長在枕頭邊。", "罪今脫矣從頭白，病已安之用涕漣。", "始悟舊詩成卦影，只消崇道了天年。", "故人讀罷知余喜，遥舉真珠百斛泉。"]'),
('4ddfe442-d8e0-4314-b381-abfc514f3cbd','答劉知縣詠雪','項安世','宋','宋诗','song-poetry','','[]','一夜雲潢剪素娥，平明門外柰詩何。',64,'全唐诗/poet.song.146000.json','["一夜雲潢剪素娥，平明門外柰詩何。", "灞橋鄭五方如許，冰柱劉叉更患多。", "衆版並題吾豈敢，扁舟乘興子能過。", "不嫌茅舍無氈否，共續長安慷慨歌。"]'),
('c0c6fbf6-b836-4c89-ae8d-507768144c4f','次韻周子問詠雪','項安世','宋','宋诗','song-poetry','','[]','掃罷殘冰又辱臨，喚回前雪與爭新。',64,'全唐诗/poet.song.146000.json','["掃罷殘冰又辱臨，喚回前雪與爭新。", "禁持酒力難爲聖，倚頼詩腸即有神。", "朝氣顛狂從自舞，夜聲騷屑會相親。", "白蘋滿眼長安夢，三月楊花覆錦茵。"]'),
('bf7ace94-1229-442e-861f-9eb439eec024','贈葉少敏','項安世','宋','宋诗','song-poetry','','[]','絳蠟高然玉粟花，眉間喜色見宜家。',64,'全唐诗/poet.song.146000.json','["絳蠟高然玉粟花，眉間喜色見宜家。", "銀河已報橋成鵲，寶鏡遥知鬢畫鴉。", "柳外月圓人漸好，洞中桃出路非賒。", "從今莫作悲秋賦，直自安仁鬢未華。"]'),
('95a91fec-39b3-4239-8d6b-2a3ec8912726','贈黄愉','項安世','宋','宋诗','song-poetry','','[]','三命盤中水火煎，五星局上計羅纏。',64,'全唐诗/poet.song.146000.json','["三命盤中水火煎，五星局上計羅纏。", "天公賦與元如此，歷叟欺諛謂不然。", "一紙向人明似鏡，平生惟爾直如弦。", "更持居士鹿門去，欲獻何人覓酒錢。"]'),
('0b4f8ec8-caec-4792-8a64-fbb40fbba0cb','次韻范有交秀才投贈二首  其一','項安世','宋','宋诗','song-poetry','','[]','頭顱看即已如斯，狡獪何能尚昔時。',64,'全唐诗/poet.song.146000.json','["頭顱看即已如斯，狡獪何能尚昔時。", "物自有情非我也，筆因隨意偶書之。", "不知風壑焉由籟，但見春林忽自枝。", "老去詩名多減盡，詠沂門戶欲容窺。"]'),
('aefb5d73-f117-4c23-a5d3-3887da6b2654','次韻范有交秀才投贈二首  其二','項安世','宋','宋诗','song-poetry','','[]','旴江范子亦奇哉，謁入寒廳眼爲開。',64,'全唐诗/poet.song.146000.json','["旴江范子亦奇哉，謁入寒廳眼爲開。", "少日論心弋陽老，新年行脚艮齋回。", "君方赤手騎生馬，我已冥心學死灰。", "空復項斯門地在，箇中無處覓詩才。"]'),
('065e7c55-f0bd-4698-8669-dcda4f54e691','次韻高秀才重九二首  其一','項安世','宋','宋诗','song-poetry','','[]','未待經霜拆嫩黄，已思斜日醉高陽。',64,'全唐诗/poet.song.146000.json','["未待經霜拆嫩黄，已思斜日醉高陽。", "鬢毛擬共冠巾約，詩句先含萸菊香。", "小雨微雲愁令節，批風借月倚新章。", "應門莫報催租吏，酒債如今也未償。"]'),
('8722a3dc-0ed0-45e1-8513-6b68c3450c72','次韻高秀才重九二首  其二','項安世','宋','宋诗','song-poetry','','[]','茱萸未插鬢先黄，兄弟西陵更岳陽。',64,'全唐诗/poet.song.146000.json','["茱萸未插鬢先黄，兄弟西陵更岳陽。", "鴻鴈來時俱是淚，菊花知汝爲誰香。", "臺因抱病難重上，詩爲催租已斷章。", "新樣小槽官釀熟，輸君直把九秋償。"]'),
('e1e14a2e-c9e4-4f24-9b25-841ecee6f858','送海陵孫縣丞三首  其一','項安世','宋','宋诗','song-poetry','','[]','壯年往贊海陵公，切莫哦詩歎負儂。',64,'全唐诗/poet.song.146000.json','["壯年往贊海陵公，切莫哦詩歎負儂。", "妻子父兄皆上祿，民人社稷盡天工。", "稅存産去須勤割，陂壞田荒與細通。", "日暮歸來念此哲，尚應無面著慚紅。"]'),
('97ba1546-f63e-4c77-9ce1-0198975afafe','送海陵孫縣丞三首  其二','項安世','宋','宋诗','song-poetry','','[]','向來一尉萬人知，此段風流已大奇。',64,'全唐诗/poet.song.146000.json','["向來一尉萬人知，此段風流已大奇。", "資考漸將京秩近，新年能使道心移。", "但慚我乃吏民上，勿謂官今選調卑。", "持此尊前供笑樂，勝如天上拜恩私。"]'),
('55a6e3a8-bca6-4e94-8c9f-186d9a667804','送海陵孫縣丞三首  其三','項安世','宋','宋诗','song-poetry','','[]','新安老子放窮山，星婺仙人古柏間。',64,'全唐诗/poet.song.146000.json','["新安老子放窮山，星婺仙人古柏間。", "今日吾儕隨利祿，高風千里斷躋攀。", "天寒日短雙輪去，海闊波深萬艇還。", "上徹浮圖須自力，有爲何地不曾顔。"]'),
('d100e6ae-c6a4-4cf3-9989-7a7d4c61e54f','次韻和謝江陵楊縣丞投贈四首  其一','項安世','宋','宋诗','song-poetry','','[]','柴門密掩但如孫，白榻高懸偶似陳。',64,'全唐诗/poet.song.146000.json','["柴門密掩但如孫，白榻高懸偶似陳。", "皮骨久將梅共瘦，鬢毛難與柳爭新。", "却思二十三年上，曾醉千巖萬壑濱。", "蘋月蓼風如昨日，堯天依舊滿懷春。"]'),
('7d9eef2e-a660-4221-92d6-a031163c7b64','次韻和謝江陵楊縣丞投贈四首  其二','項安世','宋','宋诗','song-poetry','','[]','徑苔鋪翠葉堆黄，生怕人來便踏傷。',64,'全唐诗/poet.song.146000.json','["徑苔鋪翠葉堆黄，生怕人來便踏傷。", "病久養成心性懶，閑多衍得歲年長。", "己拚故我忘俱盡，忽話當年喜欲狂。", "蓮蕩稻田相對起，鏡湖南北好風光。"]'),
('5d1e28e1-80a7-4185-9763-6d80742ebf51','次韻和謝江陵楊縣丞投贈四首  其三','項安世','宋','宋诗','song-poetry','','[]','與君齊宦五雲東，與我齊生一歲中。',64,'全唐诗/poet.song.146000.json','["與君齊宦五雲東，與我齊生一歲中。", "今日天涯須共笑，半生頭鬢畧相同。", "觀中香火無官守，庭下吟哦少事功。", "未必苕溪閑似此，買船歸去莫匆匆。"]'),
('a9117974-64a7-4566-a4b0-4e7ad8cf86d6','次韻和謝江陵楊縣丞投贈四首  其四','項安世','宋','宋诗','song-poetry','','[]','買臣五十貴何疑，衣錦懷章亦未遲。',64,'全唐诗/poet.song.146000.json','["買臣五十貴何疑，衣錦懷章亦未遲。", "苕霅有情依輦轂，簪纓無數足親知。", "只消笑向長安得，何用歌穿郢市爲。", "江漢沮漳吾老矣，藥囊如櫛氣如絲。"]'),
('0c71dda3-9631-4eba-8363-605bc624e4b5','又次韻羅商卿七夕雷雨','項安世','宋','宋诗','song-poetry','','[]','早秋初夜暗凉生，門巷歡呼見物情。',64,'全唐诗/poet.song.146000.json','["早秋初夜暗凉生，門巷歡呼見物情。", "時節自令兒女愛，年華潜遣鬢毛驚。", "一聲霹靂開銀漢，萬丈雲濤下太清。", "析木津頭傾見底，鵲橋從此不須營。"]'),
('a49832c2-3f6b-43a1-8554-4477f32cd9ba','送任梅叔赴州教授','項安世','宋','宋诗','song-poetry','','[]','楚船西上蜀東圻，茆滑芹香水半圍。',64,'全唐诗/poet.song.146000.json','["楚船西上蜀東圻，茆滑芹香水半圍。", "養就鯤鯩觀海運，哺成鸞鵠教天飛。", "化行石照銅梁外，人指蓬山藏室歸。", "喚起少年時習夢，小窗寒日鬢毛稀。"]'),
('58d9f9b8-c726-4c8e-82ce-e6f62bf1bbe6','直州次韻丁教授送行二首  其一','項安世','宋','宋诗','song-poetry','','[]','誰喚新霜破曉扉，江神知我向庭闈。',64,'全唐诗/poet.song.146000.json','["誰喚新霜破曉扉，江神知我向庭闈。", "直州千古送人處，一棹橫江從此歸。", "簾額北風情索索，轎窗東日薄暉暉。", "樹頭鵲子能傳喜，欲去回頭更整衣。"]'),
('1127002e-ab13-4563-bda0-2d963d1a1fef','直州次韻丁教授送行二首  其二','項安世','宋','宋诗','song-poetry','','[]','送行第一要君詩，一路看詩慰所思。',64,'全唐诗/poet.song.146000.json','["送行第一要君詩，一路看詩慰所思。", "可吏可儒仍可將，吾兄吾友亦吾師。", "暫移馬舫仿亭榭，小簇螺盤話別離。", "指點方壺門外柳，歸來須及欲黄時。"]'),
('7e115170-c55a-4827-86ce-674ca1d2bf41','送漢陽軍鞏教授','項安世','宋','宋诗','song-poetry','','[]','今代清時有鞏兄，世間無處著才情。',64,'全唐诗/poet.song.146000.json','["今代清時有鞏兄，世間無處著才情。", "洗乾螺黛姿仍好，挽出鯨魚意轉平。", "千古未吟渠忽到，傍人不解我先驚。", "何如鏁著金鑾殿，玉燭新調看鳳鳴。"]'),
('e1b84b46-e7ba-4e0d-afa9-f31015532c73','送李公衡從其弟赴涪州教授','項安世','宋','宋诗','song-poetry','','[]','對床夜雨副深情，去續眉山萬古名。',64,'全唐诗/poet.song.146000.json','["對床夜雨副深情，去續眉山萬古名。", "杜宇不來無客恨，鶺鴒相喚有新聲。", "江西太史吟詩處，洛下先生載道行。", "今日重提舊公案，亦須拈問老師兄。"]'),
('ee555a17-be73-48bd-894a-e6f54d550949','用韻送倪教授千里','項安世','宋','宋诗','song-poetry','','[]','吟罷隨州路口詩，先生書劍此東之。',64,'全唐诗/poet.song.146000.json','["吟罷隨州路口詩，先生書劍此東之。", "邊城它日無斯士，病叟中年惜所知。", "出處如今方永隔，逢迎何處是前期。", "故人若問孫文寶，閉戶焚香讀坎離。"]'),
('25d3aec5-1aa1-4e74-9ea8-5c4d5cd697f6','贈黄縣尉二首  其一','項安世','宋','宋诗','song-poetry','','["\u8861\u5c71"]','震澤逢君意便傾，湘江見我眼中明。',64,'全唐诗/poet.song.146000.json','["震澤逢君意便傾，湘江見我眼中明。", "鎖闈對榻談風雨，放流雙舟話晚晴。", "南嶽歌行雲裏和，西亭今古夜深評。", "無端吹落紅塵脚，寸步相疎一萬程。"]'),
('051232b4-b060-416f-b201-aba05bd25a4d','贈黄縣尉二首  其二','項安世','宋','宋诗','song-poetry','','[]','幾日真成去道洲，如今未發已先愁。',64,'全唐诗/poet.song.146000.json','["幾日真成去道洲，如今未發已先愁。", "一城對酒猶疏闊，千里題詩底唱酬。", "鴈不到君濂字水，魚應過我直名州。", "登臨若有相思句，西北風吹送似休。"]'),
('08b57fba-7cee-4d70-980c-c5e7b9970cde','再次前韻留黄縣尉二首  其一','項安世','宋','宋诗','song-poetry','','[]','郵亭別酒也須傾，底作匆匆向永明。',64,'全唐诗/poet.song.146000.json','["郵亭別酒也須傾，底作匆匆向永明。", "蓮裏青心猶有薏，雨中紅日可無情。", "吾伊未了吾難出，子墨傳言子試評。", "回首便成千里恨，論心何惜片時程。"]'),
('de4f68a0-3d31-4b44-9d48-6150d3f2373a','再次前韻留黄縣尉二首  其二','項安世','宋','宋诗','song-poetry','','[]','天教槐輔撫藩州，人道梅仙百不愁。',64,'全唐诗/poet.song.146000.json','["天教槐輔撫藩州，人道梅仙百不愁。", "倚閣才情翻作苦，留連詩卷不成酬。", "我方設棘蒐芹水，渠自張蒲去荻洲。", "二十四瀧高浪裏，卧敲船板醉吟休。"]'),
('1f9c47c3-4427-4da0-86cd-9955d75cdd73','次韻王司理二首  其一','項安世','宋','宋诗','song-poetry','','[]','它鄉異縣歘相逢，岐國家聲聳岱崧。',64,'全唐诗/poet.song.146000.json','["它鄉異縣歘相逢，岐國家聲聳岱崧。", "仕宦一生無去國，周旋四世不言功。", "太平時節司文事，滿世交游盡至公。", "若把安榮觀後進，百年未抵一年中。"]'),
('aaafe114-5f38-4199-b011-a5452b2a0324','次韻王司理二首  其二','項安世','宋','宋诗','song-poetry','','[]','對敵何曾挫一毫，避人堪笑却成逃。',64,'全唐诗/poet.song.146000.json','["對敵何曾挫一毫，避人堪笑却成逃。", "莫思蓬戶飛三箭，且向椿闈带兩髦。", "年少枉隨流水去，老來方悟入山高。", "兒童已辦新詩句，擬釘門符換舊桃。"]'),
('dfaecb20-e0aa-477a-9677-0f8e7877e054','次韻張以道對雨','項安世','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖水足鏡新磨，竺寺雲深著色多。',64,'全唐诗/poet.song.146000.json','["西湖水足鏡新磨，竺寺雲深著色多。", "雙槳滿城舟子唱，一犂無數老農歌。", "冬溫無計邀滕六，春旱愁人似石皤。", "但得新年堪浸種，不嗔花事雨中過。"]'),
('83cb7b8c-9b14-4180-8d36-25ab9a09f912','次韻張直閣對雨','項安世','宋','宋诗','song-poetry','','[]','九重城裏作山園，隔盡紅塵一世喧。',64,'全唐诗/poet.song.146000.json','["九重城裏作山園，隔盡紅塵一世喧。", "今雨未妨連昨日，春寒聊爲破冬溫。", "客傳條令來梅圃，僮報平安向竹村。", "我在道山猶羨子，世間誰似隠君尊。"]'),
('5faf0e50-a2b6-4556-a6fb-5a6ff5c69ad8','淳熙己亥歲傅子淵勸予無弄文墨自是絕意筆研十四年矣非應用不得已不作也今年胡季隨復勸予爲之曰文不可溺也其可廢乎因作此寄傅子淵','項安世','宋','宋诗','song-poetry','','[]','兒時月露與風雲，半世詞場罷策勳。',64,'全唐诗/poet.song.146000.json','["兒時月露與風雲，半世詞場罷策勳。", "老子今年新有興，良朋嗔我久無文。", "不妨翰墨鳴斯事，聊遣篇章記所云。", "不見衡州傅文學，春來雩詠滿湘濆。"]'),
('37884ad1-5851-4446-b6bb-43eb292ab960','寄鄭薦玉','項安世','宋','宋诗','song-poetry','','[]','鄭公身與我同寒，陸子泉頭隔幾山。',64,'全唐诗/poet.song.146000.json','["鄭公身與我同寒，陸子泉頭隔幾山。", "爲客蓋頭無一瓦，何時開眼見千間。", "非干世俗人情薄，自是書生命運慳。", "三邑未隨燔肉廢，先師心事幾曾還。"]'),
('3306a5c5-9176-417e-afba-69e679925f6c','寄承甫兄','項安世','宋','宋诗','song-poetry','','[]','不見夫君歲月過，舉頭相望隔山河。',64,'全唐诗/poet.song.146000.json','["不見夫君歲月過，舉頭相望隔山河。", "人來人去書長到，江北江南情若何。", "鐵硯功名當自許，錦囊詩句不須多。", "家風正待吾曹振，莫漫尋常費琢磨。"]'),
('b85c935e-2560-419c-b0c7-c21fd90b08a8','送程寺丞知和州','項安世','宋','宋诗','song-poetry','','[]','名爲淮郡實江城，采石江心郡吏迎。',64,'全唐诗/poet.song.146000.json','["名爲淮郡實江城，采石江心郡吏迎。", "一葦橫通秋浦近，雙旌何異晝衣行。", "承平豫事疑生事，緩急圖成豈解成。", "我有豳風桑土句，聊當束帛贈先生。"]'),
('c5519d33-b4cf-4d0c-a676-93c6450504c4','送蔣舍人知利州','項安世','宋','宋诗','song-poetry','','[]','乙未臨軒賜勅頭，左班詹監右君侯。',64,'全唐诗/poet.song.146000.json','["乙未臨軒賜勅頭，左班詹監右君侯。", "兩翁今止一翁健，萬里去爲千里州。", "不向殿巖提虎士，亦應帷幄運鴻籌。", "阜陵人物今餘幾，况是當年第一流。"]'),
('1f1f123c-f2ac-48b8-bcb9-f7cd705f2785','包山送辛大卿知福州','項安世','宋','宋诗','song-poetry','','[]','樓頭尊酒送將行，樓下江潮意未平。',64,'全唐诗/poet.song.146000.json','["樓頭尊酒送將行，樓下江潮意未平。", "漠漠南天垂雨脚，陰陰長夏作秋聲。", "杜陵戀闕心應苦，楚客思君淚合傾。", "莫倚輕紅宜重碧，男兒報國在尊生。"]'),
('46f3550f-8fde-43d9-b233-4aca4b3a6847','送吳少保知鄂州','項安世','宋','宋诗','song-poetry','','[]','第三閘外看征帆，閘駃帆輕似箭奔。',64,'全唐诗/poet.song.146000.json','["第三閘外看征帆，閘駃帆輕似箭奔。", "此去直挨湖北岸，吾廬正在水邊村。", "送公便作還家想，何日真酬去國言。", "最是別來情味惡，州橋每到誤窺門。"]'),
('2a781339-7f6c-48be-afe0-dd4456173739','送著作范禮部知彭州','項安世','宋','宋诗','song-poetry','','[]','三十六峰當郡前，世間無此好山川。',64,'全唐诗/poet.song.146000.json','["三十六峰當郡前，世間無此好山川。", "辭家上馬消一日，去蜀題橋今七年。", "草奏南宮文似錦，紬書東觀筆如椽。", "批風判露名花裏，正是彭州二月天。"]'),
('17e5b404-503b-4f25-ac25-fbcfbacd44e0','寄高象州','項安世','宋','宋诗','song-poetry','','[]','聞向君王乞象州，只貪州宅有高樓。',64,'全唐诗/poet.song.146000.json','["聞向君王乞象州，只貪州宅有高樓。", "山西日薄都無瘴，海外風來早見秋。", "蟋蟀已非今角匠，鷓鴣猶是舊亭侯。", "南崖石壁寬多少，題徧新詩意未休。"]'),
('c0660aa8-c1ce-430d-80b4-e2b78757df29','送胡黎州','項安世','宋','宋诗','song-poetry','','[]','江南客子賦西征，冬月川江似砥平。',64,'全唐诗/poet.song.146000.json','["江南客子賦西征，冬月川江似砥平。", "山遣雪來迎小隊，人將春去到邊城。", "邛崍阪曲臣車直，大渡河深帝斧明。", "都護歸時身未老，萬年觴畔佩環聲。"]'),
('ced47d27-800b-4d41-985d-2f02cc3091ab','送邕州高教授二首  其一','項安世','宋','宋诗','song-poetry','','[]','聽說邕州暫駐航，有金如粟馬如羊。',64,'全唐诗/poet.song.146000.json','["聽說邕州暫駐航，有金如粟馬如羊。", "五千里地通中國，四十三州控大荒。", "武事建時文未喪，化風宣處教無方。", "朝家學校通南越，慶歷諸公未易量。"]'),
('55e82189-8271-4fff-97b5-27c1f1324e79','送邕州高教授二首  其二','項安世','宋','宋诗','song-poetry','','[]','吏部無官可注員，諸生星散落三邊。',64,'全唐诗/poet.song.146000.json','["吏部無官可注員，諸生星散落三邊。", "君行回雁前頭路，我上杜鵑無處舩。", "蜀越漫傳分日雪，西南元自接風烟。", "相思莫忘書紳句，長在輿衡與立前。"]'),
('aa402cc7-a3fd-411b-9a0a-e741f8abc07d','次韻趙僉判苦雨','項安世','宋','宋诗','song-poetry','','[]','多謝新詩起鈍頑，扣門佳夢忽驚殘。',64,'全唐诗/poet.song.146000.json','["多謝新詩起鈍頑，扣門佳夢忽驚殘。", "句中解貌秋霖苦，讀罷猶聞夜滴寒。", "誰道貴遊無世話，君今清尚更儒酸。", "向來白賀風流在，勉立修名後代看。"]'),
('8446c4c7-245f-410e-ab21-15a6326817f7','答杜仲高來書哭兄伯高及辛待制且言杜氏至仲高始預薦榜','項安世','宋','宋诗','song-poetry','','[]','康廬之麓蠡之臯，太息書來杜仲高。',64,'全唐诗/poet.song.146000.json','["康廬之麓蠡之臯，太息書來杜仲高。", "待制功名千古傑，賢良文字萬夫豪。", "淚痕頻向西風滴，場屋新隨舉子曹。", "且爲門闌闢青紫，軻親威父一生勞。"]'),
('40ba6d07-93ad-4e32-aa02-458c09cefba1','次韻楊僉判室中竹枝','項安世','宋','宋诗','song-poetry','','[]','嬾龍入戶養慵枝，罷聽風雷却聽詩。',64,'全唐诗/poet.song.146000.json','["嬾龍入戶養慵枝，罷聽風雷却聽詩。", "頭角不爭雲雨會，精神如畏雪霜欺。", "莫教畫手流傳去，生怕時人取次知。", "此腹可憐終不負，琅玕朝暮爲君披。"]'),
('faf33e27-a62f-4976-bcd0-112940161a5d','送胡仲方二首  其一','項安世','宋','宋诗','song-poetry','','[]','鄧林擢幹皆楩梓，丹穴生雛即鳳凰。',64,'全唐诗/poet.song.146000.json','["鄧林擢幹皆楩梓，丹穴生雛即鳳凰。", "年少一來無比並，老翁千歲有輝光。", "幕中潤澤江湖遠，筆下才情錦繡張。", "未必安仁須作縣，籍田新賦待文章。"]'),
('dee00eed-d03e-42b7-a43d-cfc3f0e72140','送胡仲方二首  其二','項安世','宋','宋诗','song-poetry','','[]','交情久處臨分苦，別意深時著語難。',64,'全唐诗/poet.song.146000.json','["交情久處臨分苦，別意深時著語難。", "志士自期須皓首，故人相勸只加餐。", "乾坤老大千年在，雲海扶摇一息看。", "防有能言如子者，解將佳話倚危欄。"]'),
('bd75254f-cd87-41ac-acd6-2b1994603a39','送東川成路鈐','項安世','宋','宋诗','song-poetry','','[]','壯歲專城身欲老，兒時射策眼今昏。',64,'全唐诗/poet.song.146000.json','["壯歲專城身欲老，兒時射策眼今昏。", "戰創滿面誰能管，舊事逢人且莫論。", "壁壘旌旗分一路，弟兄父子號名門。", "回瞻永阜陵前柏，莫忘當時教育恩。"]'),
('111f3f06-9145-42b6-828b-5f0bce8f2ccb','送醇甫','項安世','宋','宋诗','song-poetry','','[]','怕聽槌鼓發舩聲，桑梓葭莩兩繫情。',64,'全唐诗/poet.song.146000.json','["怕聽槌鼓發舩聲，桑梓葭莩兩繫情。", "病有千回煩訪問，貧無一事擾聰明。", "循良只爲鄉人惜，離別偏令老大驚。", "不記歸來多少歲，兒童三見令君行。"]'),
('acc0ecba-0b73-4c42-a201-c06404d26d9c','送夔帥楊校書解印還鄉二首  其一','項安世','宋','宋诗','song-poetry','','[]','高閑風度澹無營，靜密工夫久自增。',64,'全唐诗/poet.song.146000.json','["高閑風度澹無營，靜密工夫久自增。", "太息家林惟獨鶴，向來西海說三鵬。", "橋衝不動千原穫，鼛鼓無聲萬杵登。", "道在陰陽公自到，向來河洛此繩繩。"]'),
('c3326110-4aa3-41fe-8146-e2155ab70f00','送夔帥楊校書解印還鄉二首  其二','項安世','宋','宋诗','song-poetry','','[]','清秋丹鳳下蓬萊，驚倒瞿唐灧澦堆。',64,'全唐诗/poet.song.146000.json','["清秋丹鳳下蓬萊，驚倒瞿唐灧澦堆。", "監國入堂催議事，相公開館夢翹材。", "未甘直上青雲去，更欲斜飛錦水回。", "一片蘆帆楚江岸，新春蓑笠候高桅。"]'),
('8c059dd7-6764-4ecd-ad30-dd2944ca790f','故人亭','項安世','宋','宋诗','song-poetry','','[]','翠壁丹崖雲氣浮，故人亭下駐行舟。',64,'全唐诗/poet.song.146000.json','["翠壁丹崖雲氣浮，故人亭下駐行舟。", "瀟湘東去連滄海，桂嶺西來接永州。", "浦樹生烟攢舴艋，巖花覆水叫軥輈。", "讞刑省俗慙無補，目斷波間雙白鷗。"]'),
('362b5a77-6a69-4d90-860f-cbab6550cbc5','劉寺置酒遇雨次韻答王大著','項安世','宋','宋诗','song-poetry','','[]','勝絕今年第一籌，錢湖劉寺雨中遊。',64,'全唐诗/poet.song.146000.json','["勝絕今年第一籌，錢湖劉寺雨中遊。", "湯傾衢點雲隨肘，羹汎戎酥雪滿甌。", "竹塢張烟圍客住，梅簷翻水勸人留。", "只因元氣淋漓手，計會天公作此謀。"]'),
('d0e71a70-4473-42a7-a660-3e2c47a217d6','大雨','項安世','宋','宋诗','song-poetry','','[]','閑裏光陰已自娛，近添衰病更宜居。',64,'全唐诗/poet.song.146000.json','["閑裏光陰已自娛，近添衰病更宜居。", "羅禽樂甚無賓客，庭草欣然罷吏胥。", "一霎陰風催下箔，滿堂流水喚開渠。", "家童莫笑先生急，雨過先生緩有餘。"]'),
('7f702052-a5d3-4943-93a4-ae0d7340f994','老人命賦家庭雙頭牡丹','項安世','宋','宋诗','song-poetry','','[]','只與酴醾話獨醒，不隨桃李競時名。',64,'全唐诗/poet.song.146000.json','["只與酴醾話獨醒，不隨桃李競時名。", "人憐國色無花對，天與風流並蒂生。", "兩兩鶴紅思並翥，雙雙鹿紫待齊鳴。", "沖天食野方多慶，盡是仙翁手種成。"]'),
('b788c5be-03ce-4f00-a792-6222e053c208','失題','項安世','宋','宋诗','song-poetry','','[]','肇開苕霅葬斯文，從此新安族望分。',64,'全唐诗/poet.song.146000.json','["肇開苕霅葬斯文，從此新安族望分。", "牴角煙寒山烈烈，梅溪風切水沄沄。", "何人可誌林宗墓，他日應尋董相墳。", "桃李無言蹊自遠，五湖清淚濕春雲。"]'),
('86f9a899-e0be-48cb-ad15-d603a1ccc8c6','讀竹林先生墓銘','項安世','宋','宋诗','song-poetry','','[]','嵩安鄉社榻岡阡，野客銘詩嗣子鎸。',64,'全唐诗/poet.song.146000.json','["嵩安鄉社榻岡阡，野客銘詩嗣子鎸。", "花發鳥啼春覓句，草深螢度夜開編。", "竹林名字人知否，玉樹禨祥我謂然。", "十萬丈夫旁可置，六千君子後多言。"]'),
('06b7f670-05eb-417c-b2a5-c4114f0a7182','又病起送春','項安世','宋','宋诗','song-poetry','','[]','睡過珍林十日紅，起看陽艷欲成空。',64,'全唐诗/poet.song.146000.json','["睡過珍林十日紅，起看陽艷欲成空。", "有情盡付鶑和蝶，無恨堪嗔雨與風。", "原隰望中青一色，欄干凭處意無窮。", "衰翁晚悟人間事，春去春來歲歲同。"]'),
('16a6ff1e-f182-4fe9-8018-805d78ba5d3c','有感韓魯一首','項安世','宋','宋诗','song-poetry','','[]','道散斯文體尚浮，韓魯力與化工侔。',64,'全唐诗/poet.song.146000.json','["道散斯文體尚浮，韓魯力與化工侔。", "山瞻泰岱巖巖聳，河出崑崙混混流。", "長慶從官銷不得，熙寧丞相挽難留。", "滄州奏疏潮州表，猶被人拈作話頭。"]'),
('20c678a0-bd5d-4a52-ba9b-1b719229c7d3','有感','項安世','宋','宋诗','song-poetry','','[]','策策秋聲起樹枝，遥憐塞下鴈來時。',64,'全唐诗/poet.song.146000.json','["策策秋聲起樹枝，遥憐塞下鴈來時。", "寧聞中夜荒鷄舞，肯拾他人竹馬騎。", "短劍舊曾交俠客，小詩猶作將偏師。", "無情却是青銅鏡，剛照書生兩鬢絲。"]'),
('2ea597f4-b2fd-43d5-bd77-0c77b654f1de','有感七首之一','項安世','宋','宋诗','song-poetry','','[]','我與昔賢生異世，晝思夜夢兩微茫。',64,'全唐诗/poet.song.146000.json','["我與昔賢生異世，晝思夜夢兩微茫。", "棹頭墮霧入東海，被髮乘風下大荒。", "仙伯已尋丹竈地，武王亦返白雲鄉。", "惟應詩卷留天地，寶氣雖埋斗有光。"]'),
('cec75cdb-30fa-444e-ba42-023542adc819','聞城中募兵有感  其一','項安世','宋','宋诗','song-poetry','','[]','調發年多籍半空，虎符招補至閩中。',64,'全唐诗/poet.song.146000.json','["調發年多籍半空，虎符招補至閩中。", "莊農戎服來操戟，太守儒裝學拍弓。", "去日初辭鄉樹綠，到時愁見戍旗紅。", "募金莫作纏頭費，留製衣袍禦北風。"]'),
('5ac47791-cdde-466e-bc58-df4dbe0bfc0e','聞城中募兵有感  其二','項安世','宋','宋诗','song-poetry','','[]','莫在軍中日募兵，萬夫魚貫列行營。',64,'全唐诗/poet.song.146000.json','["莫在軍中日募兵，萬夫魚貫列行營。", "懸金都市招徠廣，立的轅門去取精。", "二石開弓猶恨少，雙重被鎧尚嫌輕。", "伍符□屬他人手，歷歷空能記姓名。"]'),
('8c2abaf3-f8ec-4c42-98c7-d82dcb97c1e2','代任閬州和人重午二首  其一','項安世','宋','宋诗','song-poetry','','[]','靈符高掛辟方良，寶劑旁搜納衆芳。',64,'全唐诗/poet.song.146000.json','["靈符高掛辟方良，寶劑旁搜納衆芳。", "穰穰人情隨節變，冥冥古意與□長。", "新裁白雪羅衣潤，旋剝黄金角餌香。", "尚想中流見荃棹，徘徊洲浦待巫陽。"]'),
('4dbb3164-1fb9-4a5c-9576-6f1e173383bd','代任閬州和人重午二首  其二','項安世','宋','宋诗','song-poetry','','[]','游龍蹴浪錦江高，節物驚人感二毛。',64,'全唐诗/poet.song.146000.json','["游龍蹴浪錦江高，節物驚人感二毛。", "京洛承平真富貴，江湖風物歎蕭騷。", "荃蕪有恨流千古，駑驥當年共一槽。", "聖處相期君不肯，自煎明焰泣流膏。"]'),
('ec471376-42a6-47f0-bd3d-0b40cb328b21','次韻鄉人華秀才冬至日投贈二首  其一','項安世','宋','宋诗','song-poetry','','[]','深知道長屬仁賢，甚愛陽來復舊氈。',64,'全唐诗/poet.song.146000.json','["深知道長屬仁賢，甚愛陽來復舊氈。", "鳳歷新灰浮緹室，牛星初度轉青天。", "五雲嘉氣書周典，七日靈文驗孔編。", "忽忽窮愁休悵恨，東風已到玉梅前。"]'),
('0936a805-ba04-44a7-8f5f-6c8a2fa2782f','次韻鄉人華秀才冬至日投贈二首  其二','項安世','宋','宋诗','song-poetry','','[]','異鄉初見子文章，短至仍逢日吉良。',64,'全唐诗/poet.song.146000.json','["異鄉初見子文章，短至仍逢日吉良。", "下馬入門知意重，芳華贈我愧情長。", "筆端風味誰能及，江上形容莫自傷。", "一線陽光真白璧，九衢春夢付黄粱。"]'),
('52f4005b-aba1-454e-b43d-3d2c040c8371','賀孟漕爲疫禱雨','項安世','宋','宋诗','song-poetry','','[]','綠簡朱書扣紫圜，黑烟紅電攪黄淵。',64,'全唐诗/poet.song.146000.json','["綠簡朱書扣紫圜，黑烟紅電攪黄淵。", "捲殘東漢西岷水，翻入南雲北夢田。", "病祝香燈猶未炷，疫民鍼艾已先痊。", "更欣十萬天驕子，角脫膠開不上弦。"]'),
('5908ae12-481e-4ce6-bf9f-f2945e15ae44','送張柳二生歸潭州應舉','項安世','宋','宋诗','song-poetry','','[]','丹鳳飛來紫詔香，六龍初日上扶桑。',64,'全唐诗/poet.song.146000.json','["丹鳳飛來紫詔香，六龍初日上扶桑。", "漢廷第一垂清問，潭府三元有故常。", "賦客從來推屈宋，文星依舊照衡湘。", "夜凉天宇清如洗，翼軫光中見柳張。"]'),
('1e4455d2-19a7-4e36-a2ad-a4b960db3951','上冢還過方橋','項安世','宋','宋诗','song-poetry','','[]','一番新火試新茶，又向方橋記歲華。',64,'全唐诗/poet.song.146000.json','["一番新火試新茶，又向方橋記歲華。", "草色前頭見江樹，桑林多處是人家。", "拓開白鳥天邊眼，背盡紅塵脚底沙。", "臨老不知來幾度，只看豆麥不看花。"]'),
('bf7f0ccc-79e1-4f5a-b771-0901c68b22e9','丙寅法輪寺閲前賢碑板有感','項安世','宋','宋诗','song-poetry','','[]','岣嶁峯前法輪寺，少林閣後訪碑軒。',64,'全唐诗/poet.song.146000.json','["岣嶁峯前法輪寺，少林閣後訪碑軒。", "子宣介甫清詩在，雙井毗陵白牓懸。", "文本記成當國日，退之句就貶官年。", "從來治亂無多術，只在諸人進退邊。"]'),
('e37aa8cb-52a5-4b40-b1bc-da7b3010669e','頭顱四十有感','項安世','宋','宋诗','song-poetry','','[]','學古光陰惜寸分，濟時心膽慕華勛。',64,'全唐诗/poet.song.146000.json','["學古光陰惜寸分，濟時心膽慕華勛。", "少年有意不稱意，暮景欲云何所云。", "行矣未能真不惑，歸與長恐遂無聞。", "朝來不敢看清鏡，怕有輕霜下碧雲。"]'),
('bf5d9907-cd17-4535-9f70-4e423e57dba7','次韻酬查仲文春日宴集','項安世','宋','宋诗','song-poetry','','[]','步屧隨春亦偶來，堂前雙燕莫深猜。',64,'全唐诗/poet.song.146000.json','["步屧隨春亦偶來，堂前雙燕莫深猜。", "明年我自滄浪去，無限人從紫陌回。", "寶扇臨風聽曲度，繡簾低日看花開。", "一尊幸許陪諸老，急拍深杯未用催。"]'),
('85d9fb02-0518-4200-959f-6e7c2f79e447','老母生朝','項安世','宋','宋诗','song-poetry','','[]','陶春庭院起鞦韆，賽社人家踏舞筵。',64,'全唐诗/poet.song.146000.json','["陶春庭院起鞦韆，賽社人家踏舞筵。", "生日新來逢此日，今年好去勝常年。", "舊栽桂子孫枝盛，老對萱叢孺色鮮。", "待得兒曹俱鶴髮，五紋雙髧戲尊前。"]'),
('72e1de97-509d-4789-85eb-7ef5d8a16f60','又代庠孫','項安世','宋','宋诗','song-poetry','','[]','春風建鄴花如錦，社日秦淮酒似油。',64,'全唐诗/poet.song.146000.json','["春風建鄴花如錦，社日秦淮酒似油。", "繡閣相傳住鍼綫，高堂有喜送觥籌。", "兔經三夜光長好，燕入新年語不休。", "商略重闈何許壽，八千纔是一春秋。"]'),
('1a7041d2-9500-4872-b448-938cbac3a5a3','丈人任知縣生朝','項安世','宋','宋诗','song-poetry','','[]','老梅坡底萬花黄，未問重陽且少陽。',64,'全唐诗/poet.song.146000.json','["老梅坡底萬花黄，未問重陽且少陽。", "華岳金天鍾寶器，屏星初月照琴堂。", "阿連句好珠躔聚，文度歸來玉樹香。", "千歲易逢難此會，明年湖海却相望。"]'),
('71386394-d048-4776-9e26-cf942abad1e6','大人生朝六首 安世','項安世','宋','宋诗','song-poetry','','[]','一秋六誥入于門，總是君恩與父恩。',64,'全唐诗/poet.song.146000.json','["一秋六誥入于門，總是君恩與父恩。", "拔起單貧新氏族，訓開癡騃小兒孫。", "于今教養功都就，疇昔鄉閭道愈尊。", "樂事滿懷無一欠，只消長壽看仍昆。"]'),
('2f818110-8eee-4c52-b1c3-79807075269d','大人生朝六首 宜孫','項安世','宋','宋诗','song-poetry','','[]','曉鏘環佩謁仙靈，退著班衣戲寧馨。',64,'全唐诗/poet.song.146000.json','["曉鏘環佩謁仙靈，退著班衣戲寧馨。", "帝所已開天佑節，新闈又拜老人星。", "爲臣爲子真逢運，斯萬斯千並與齡。", "聖主蘿圖長奕奕，仙翁華髮再青青。"]'),
('00ccde7e-ec65-4c18-885a-a45825a9b3d9','大人生朝六首 寅孫','項安世','宋','宋诗','song-poetry','','[]','岧嶢丹闕六龍飛，浩蕩鴻私下九圍。',64,'全唐诗/poet.song.146000.json','["岧嶢丹闕六龍飛，浩蕩鴻私下九圍。", "花結初頒紅錦帙，寶香新拜綠荷衣。", "未曾賀刺周閭里，又報升柴享禁闈。", "千歲幾番蒙帝澤，一年兩度被恩輝。"]'),
('19711a57-52ea-4e49-bdb0-6f8b9fb2fbae','大人生朝六首 容孫','項安世','宋','宋诗','song-poetry','','[]','一年好景是重陽，萸紫樨紅菊更黄。',64,'全唐诗/poet.song.146000.json','["一年好景是重陽，萸紫樨紅菊更黄。", "可但初旬堪落帽，不□二九再飛觴。", "芝書况有重重慶，桂種仍傳衮衮芳。", "歲歲年年秋色裏，玳筵紅燭醉風光。"]'),
('273bbbb8-8b5e-417f-b81d-0e6224718c09','大人生朝六首 康孫','項安世','宋','宋诗','song-poetry','','[]','隔江遥望小蓬萊，滿眼風光入壽盃。',64,'全唐诗/poet.song.146000.json','["隔江遥望小蓬萊，滿眼風光入壽盃。", "湧起濤江爲玉酒，瀉開東海作金罍。", "山龍恰爲供香獸，橋鯉真堪截錦腮。", "鴈字滿天霞正赤，染成詩軸勝於坯。"]'),
('65556271-d98b-49c4-b201-4f1dc8591d68','大人生朝六首 庠孫','項安世','宋','宋诗','song-poetry','','[]','角羈小小未多知，但識堆盤果實奇。',64,'全唐诗/poet.song.146000.json','["角羈小小未多知，但識堆盤果實奇。", "星女機邊榴粲粲，炎官繖底柿纍纍。", "綠皺紫殻如拳栗，玉液金肌似碗梨。", "願得仙翁千歲壽，長分餘顆及孫兒。"]'),
('478764d2-b883-4db3-939e-584b4dbbd11c','瑞慶節','項安世','宋','宋诗','song-poetry','','[]','引罷琳宮祝壽班，團團初日上雲間。',64,'全唐诗/poet.song.146000.json','["引罷琳宮祝壽班，團團初日上雲間。", "微風不動靴袍暖，千騎無譁錦繡環。", "一色新花迷遠近，十分和氣滿江山。", "邊城盡日聞簫鼓，豈料今朝有此閑。"]'),
('52a00aac-78ea-4970-8b1a-440bfed14be5','題周丞相壽沙亭','項安世','宋','宋诗','song-poetry','','[]','台星入軫照三湘，申畫南雲作壽鄉。',64,'全唐诗/poet.song.146000.json','["台星入軫照三湘，申畫南雲作壽鄉。", "太始以來山色在，北流無盡水聲長。", "曾開皇極頒諸福，親把鴻鈞轉八荒。", "却倚虛欄看平楚，野潢閑受濟川航。"]'),
('81aa5c26-9dd8-4806-9464-15dd691b9fc4','方太君生日  其一','項安世','宋','宋诗','song-poetry','','[]','金鴨煙青蠟炬紅，玉龜山上勸春風。',64,'全唐诗/poet.song.146000.json','["金鴨煙青蠟炬紅，玉龜山上勸春風。", "乍寒還暖花無數，似缺疑圓桂欲中。", "八十又三人所羨，雙瞳如漆壽難窮。", "七千九百十七歲，始共椿齡一半同。"]'),
('ce3ebb02-eb9a-4142-9c31-84f4ffb5734a','方太君生日  其二','項安世','宋','宋诗','song-poetry','','[]','飄飄南極上明星，浩浩東風入翠醽。',64,'全唐诗/poet.song.146000.json','["飄飄南極上明星，浩浩東風入翠醽。", "春最好時纔中半，人難學處是修齡。", "已開棠樹千枝錦，尚欠蓂花一莢青。", "更願兒孫添晚景，早收丹桂媚慈庭。"]'),
('1c36723c-8f63-42f1-855a-685439b453ba','六叔母生日  其一','項安世','宋','宋诗','song-poetry','','[]','千歲光陰二十停，一停纔向此時盈。',64,'全唐诗/poet.song.146000.json','["千歲光陰二十停，一停纔向此時盈。", "律筒又報三陽近，歷草還飛四莢輕。", "冉冉春盤行細綠，泠泠臈琖瀉空清。", "不須更煮囊中藥，息氣存神自久生。"]'),
('c2e7810c-1fee-4fe0-93b9-17e32ca1a34e','六叔母生日  其二','項安世','宋','宋诗','song-poetry','','[]','已傳春日在春前，誕日欺春又占先。',64,'全唐诗/poet.song.146000.json','["已傳春日在春前，誕日欺春又占先。", "百面玉盤檠菜縷，兩行紅燭罩沉烟。", "自從梅裏迎王母，直到荷時慶老仙。", "攔住東風頭與尾，中間和氣一千年。"]'),
('9b0f8afd-6484-4aba-99d2-211192c5892c','內子生日  其一','項安世','宋','宋诗','song-poetry','','[]','去歲親前捧壽杯，如今萬里獨西來。',64,'全唐诗/poet.song.146000.json','["去歲親前捧壽杯，如今萬里獨西來。", "遥知此日憐兒婦，應撫南枝問雪梅。", "百尺燈山初轉眼，一卮春酒欲酡腮。", "願言尊幼俱彊健，歸著斑衣伴老萊。"]'),
('95a3e8e9-8522-4756-b9ef-1bf700d4e9d1','內子生日  其二','項安世','宋','宋诗','song-poetry','','[]','東風吹草未成花，物色相看意已嘉。',64,'全唐诗/poet.song.146000.json','["東風吹草未成花，物色相看意已嘉。", "游女盡從燈夕出，家人重向壽辰誇。", "層層膝下孫枝長，衮衮天邊帝綍加。", "欲和晏公延壽曲，紅鸞紫鳳勸流霞。"]'),
('7e1e5701-53a0-4cc2-8cef-2e245e5340e7','內子生日  其三','項安世','宋','宋诗','song-poetry','','[]','人間十八最風流，更占新年第一籌。',64,'全唐诗/poet.song.146000.json','["人間十八最風流，更占新年第一籌。", "北夢南雲春漸暖，星橋火樹夜初收。", "舅姑未老椿松固，兒女成行璧玉稠。", "但得長年同飽飯，其他萬事更何求。"]'),
('3a8f4e40-3141-48f8-aad1-ffbe477862c1','內子生日  其四','項安世','宋','宋诗','song-poetry','','[]','居士新年六秩來，細君初慶綺筵開。',64,'全唐诗/poet.song.146000.json','["居士新年六秩來，細君初慶綺筵開。", "朱顔拂拂生銀勺，華髮鮮鮮上玉臺。", "女嫁男婚成次第，殃銷禍散到耆鮐。", "高堂一曲斑衣舞，我唱君隨作老萊。"]'),
('def91da4-33de-46ba-874d-c43e98ae8fe9','又中秋詩  其一','項安世','宋','宋诗','song-poetry','','[]','去年客裏念庭闈，今日尊前捧壽卮。',64,'全唐诗/poet.song.146000.json','["去年客裏念庭闈，今日尊前捧壽卮。", "樂事賞心仍有月，好天良夜可無詩。", "秋原絕粒真成旱，俚俗燒燈不負時。", "一笑難逢須自慶，幾人對酒得開眉。"]'),
('cb773b34-5558-474c-bdc1-1a9ecc752498','又中秋詩  其二','項安世','宋','宋诗','song-poetry','','[]','煙清露冷月明中，無古無今此夕同。',64,'全唐诗/poet.song.146000.json','["煙清露冷月明中，無古無今此夕同。", "大地山河歸影裏，白銀宮闕上天東。", "人情可是隨時別，酒盞真堪對影空。", "來歲相逢應更好，丹梯高處獨乘風。"]'),
('c4c8c5ef-1215-4da6-ab1d-1741fc387fef','又中秋小雨','項安世','宋','宋诗','song-poetry','','[]','天生明月照秋空，人把鮮晴候歲功。',64,'全唐诗/poet.song.146000.json','["天生明月照秋空，人把鮮晴候歲功。", "可忍浮雲來鏡裏，更堪風雨落庭中。", "旌旗踏浪驚吳俗，燈火連街見楚風。", "江海歸來心未穩，猶疑醒眼是朦朧。"]'),
('23468e2b-9395-4b5d-84b1-64e4bf361bc9','又月出次韻','項安世','宋','宋诗','song-poetry','','[]','觥船老去不能空，詩律衰來漸少功。',64,'全唐诗/poet.song.146000.json','["觥船老去不能空，詩律衰來漸少功。", "此夜輪邊誰得句，一壺花下偶成中。", "光分少皡金天露，氣挾蓐收閶闔風。", "只恐嫦娥須自悔，何如雲裏放朦朧。"]'),
('38fc2657-1560-4797-8b04-3e98653f77bc','又中秋沿檄新昌道中有懷二首','項安世','宋','宋诗','song-poetry','','[]','亂山深處過中秋，客裏今年分外愁。',64,'全唐诗/poet.song.146000.json','["亂山深處過中秋，客裏今年分外愁。", "坐想鴒原揮兔翰，遥知鶴髮念貂裘。", "一身四處爲肝膽，有月無人與獻酬。", "急喚老兵同濁酒，强排孤憤作清遊。"]'),
('6eb614fa-c04d-451a-a090-aede91f9702f','母氏立春日慶七十','項安世','宋','宋诗','song-poetry','','[]','土牛門外打春鞭，綵鳳堂前慶壽箋。',64,'全唐诗/poet.song.146000.json','["土牛門外打春鞭，綵鳳堂前慶壽箋。", "西母東公俱得歲，古稀今有見雙全。", "羣仙別演長生籍，大歷重開甲子年。", "更值圜壇鷄赦出，兩封花誥一般鮮。"]'),
('11017f07-f2fc-4bd2-917d-afdb3dcbcfce','六叔母生朝','項安世','宋','宋诗','song-poetry','','[]','香梅細柳競芳辰，預報新年兩日春。',64,'全唐诗/poet.song.146000.json','["香梅細柳競芳辰，預報新年兩日春。", "未得犀盤傳菜縷，且看玉盞泛松仁。", "東風衮衮添孫竹，南極雙雙照壽椿。", "正是門闌多喜日，乘龍嬌客翠袍新。"]'),
('67593ec1-5cda-40d4-92e0-94a159092a16','又代作','項安世','宋','宋诗','song-poetry','','[]','絳帷犀鎮繡簾低，翠竹龍香錦帕齊。',64,'全唐诗/poet.song.146000.json','["絳帷犀鎮繡簾低，翠竹龍香錦帕齊。", "百柂瓊艘傾竹醖，千年眉壽輯萱閨。", "堂東已見床堆笏，庭下行看玉滿畦。", "歲晚逢春知有意，天教齯齒受新褆。"]'),
('6fee8dc4-5e96-41d3-93f5-82f2b2b6fee2','妻兄任以道生朝','項安世','宋','宋诗','song-poetry','','[]','月律從渠大小旬，先生隨意作生辰。',64,'全唐诗/poet.song.146000.json','["月律從渠大小旬，先生隨意作生辰。", "以謙自養何嫌晦，與復俱來特地新。", "千歲日將宮綫數，五方雲作壽香陳。", "葭灰寂寞今無頼，擬向黄鍾託此身。"]'),
('ac8a5aa5-bdf3-404b-bad5-cfef1aeda344','四伯父生朝三首  其一','項安世','宋','宋诗','song-poetry','','[]','花到酴釄芍藥時，人如仙桂大椿詩。',64,'全唐诗/poet.song.146000.json','["花到酴釄芍藥時，人如仙桂大椿詩。", "一年春事鶑初懶，千歲光陰鶴未遲。", "鬢雪多於南極老，臉朱濃似舞雩兒。", "醺醺曲水餘酲在，又酌流霞勸壽卮。"]'),
('ccc2a020-ee6a-4bbd-af24-c07a784fb709','四伯父生朝三首  其二','項安世','宋','宋诗','song-poetry','','[]','夜闌脩竹罷傳觴，清曉詵詵輯燕堂。',64,'全唐诗/poet.song.146000.json','["夜闌脩竹罷傳觴，清曉詵詵輯燕堂。", "浴冠舞童春服盛，秀眉齯齒頌聲長。", "博山細吐晴霏潤，大斗高斟臈味香。", "華髮他年多勝事，鳳綸重疊拜恩光。"]'),
('29db19ea-09b0-4f86-bc00-2faa3dc39af6','四伯父生朝三首  其三','項安世','宋','宋诗','song-poetry','','[]','農郊有喜萬人知，三日甘霖綠野肥。',64,'全唐诗/poet.song.146000.json','["農郊有喜萬人知，三日甘霖綠野肥。", "動地歡聲連穀旦，降神喜頌入春圍。", "雲充畫棟排金鴨，花滿前行立綵衣。", "七十今年須預慶，明年群玉正天飛。"]'),
('fd792b55-95ae-4938-820e-8357bf451fd0','十七弟生朝','項安世','宋','宋诗','song-poetry','','[]','至日陽生萬事新，阿連於此慶生辰。',64,'全唐诗/poet.song.146000.json','["至日陽生萬事新，阿連於此慶生辰。", "一天雲物皆和氣，滿市人家作賀賓。", "壽算暗隨宮綫長，科名行逐地雷伸。", "病夫已學陳根退，只願庭前玉樹春。"]'),
('42b23934-6d2a-4b54-ab2c-ef8e8a8abd77','六叔父生朝三首  其一','項安世','宋','宋诗','song-poetry','','[]','拂拂南薰入燕堂，獸爐清潤酒尊凉。',64,'全唐诗/poet.song.146000.json','["拂拂南薰入燕堂，獸爐清潤酒尊凉。", "筵開湯餠麥初熟，綵結茶花絲正香。", "翠竹有孫添夏笋，紅榴能笑發春妝。", "都將造物無窮景，來與仙翁獻壽觴。"]'),
('ac7edf43-d434-4c4c-9ed4-a23b309c7ff5','六叔父生朝三首  其二','項安世','宋','宋诗','song-poetry','','[]','夷惠之間得趣多，天教彌月占清和。',64,'全唐诗/poet.song.146000.json','["夷惠之間得趣多，天教彌月占清和。", "門當午市心如水，髮插秋霜臉自酡。", "雨洗竹香侵瑞鴨，風翻荷潤入杯螺。", "欲知壽算長多少，樓外西江萬里波。"]'),
('7fc769bd-05ac-4c64-8047-b1bb8e505a33','六叔父生朝三首  其三','項安世','宋','宋诗','song-poetry','','[]','百摺榴花照畫筵，八千椿歷記遐年。',64,'全唐诗/poet.song.146000.json','["百摺榴花照畫筵，八千椿歷記遐年。", "東公西母朱顔老，玉女金童綵服鮮。", "梅雨漲添春色酒，麥秋黄起壽爐烟。", "銅壺未下三更水，猶是清和四月天。"]'),
('68243978-e405-4bec-92e4-eb4e13f81101','伯父生朝','項安世','宋','宋诗','song-poetry','','[]','前宵穀雨放茶旗，昨日重三轉酒池。',64,'全唐诗/poet.song.146000.json','["前宵穀雨放茶旗，昨日重三轉酒池。", "綵杖插花明兔碗，紅牙調曲勸鸞卮。", "煌煌朱臉烘華髮，奕奕清睛耿秀眉。", "南極壽星祗此是，不須高向畫圖窺。"]'),
('b549c5fd-ec61-4556-a271-9f47690d8e7a','壽邱安撫二首  其一','項安世','宋','宋诗','song-poetry','','[]','湖上高荷五月凉，雲間三五桂華香。',64,'全唐诗/poet.song.146000.json','["湖上高荷五月凉，雲間三五桂華香。", "蒲葵影裏民無暑，飛鏡光中吏有霜。", "日近天申纔半浹，陽居大夏恰中央。", "定扶真主開炎運，雪恥歸來報上皇。"]'),
('7e81850b-a78d-4ef7-a234-a516fa5fcd4d','壽邱安撫二首  其二','項安世','宋','宋诗','song-poetry','','[]','當年詔使再來時，物色依人喜可知。',64,'全唐诗/poet.song.146000.json','["當年詔使再來時，物色依人喜可知。", "萱麝半黄宜壽母，籜龍新綠見孫枝。", "清香畫戟沈沈處，永日薰風細細吹。", "閣上南山青不盡，一杯相屬壽無期。"]'),
('e00ea5cc-77d3-47f2-ba2a-02d8b0b940c0','用韻壽鄭子仁二首  其一','項安世','宋','宋诗','song-poetry','','[]','千載吾家得鄭君，至今情義藹於春。',64,'全唐诗/poet.song.146000.json','["千載吾家得鄭君，至今情義藹於春。", "向人心事緇衣武，伴我躬耕谷口真。", "父老尚談宣幕事，世科元是探花人。", "朱庭玉色渾相似，曾向冰綃識壽神。"]'),
('bc1abd23-9ffa-46a5-8749-cfcc03ad4a34','用韻壽鄭子仁二首  其二','項安世','宋','宋诗','song-poetry','','[]','殿閣風來六莢新，勾芒猶是管餘春。',64,'全唐诗/poet.song.146000.json','["殿閣風來六莢新，勾芒猶是管餘春。", "明朝斗外星初轉，今日樽前夏未真。", "九十日都成此會，八千年更屬何人。", "併將駘蕩清和德，鍾作崧高駿極神。"]'),
('d26a3547-685c-4095-a5bc-b9ce739cb431','次韻爲樂黔州內子壽','項安世','宋','宋诗','song-poetry','','[]','四牧車前翟茀施，六珈光裏振榆揮。',64,'全唐诗/poet.song.146000.json','["四牧車前翟茀施，六珈光裏振榆揮。", "侯宮燕喜千年壽，天詔鸞封咫尺威。", "西閣雨晴山靡靡，東湖雲澹水微微。", "春風無限長生意，客子何妨緩緩歸。"]'),
('176438e5-c95c-4f5c-bace-9b871dda9554','鄭子仁生朝','項安世','宋','宋诗','song-poetry','','[]','萬紫千紅變綠時，高門廣路繡弧垂。',64,'全唐诗/poet.song.146000.json','["萬紫千紅變綠時，高門廣路繡弧垂。", "梅梢暗結和羹實，蠶簇初抽演綍絲。", "首占夏時天已許，名喧春牓世方知。", "家傳鼎甲尋常事，不比寒儒漫浪期。"]'),
('88f3c72c-1d2a-41b9-9a2f-3bef7da747c0','送鄭子仁往岳陽兼以爲壽','項安世','宋','宋诗','song-poetry','','[]','曉發津陽向岳陽，梅風吹纜麥天凉。',64,'全唐诗/poet.song.146000.json','["曉發津陽向岳陽，梅風吹纜麥天凉。", "家人細數生朝近，壽算應同水驛長。", "行處葡萄迎棹綠，宿時楊柳近船黄。", "千花不敢留顔色，只許藍袍一樣芳。"]'),
('68290b44-073b-4db0-aad1-8575097ac21e','壽王尚書二首  其一','項安世','宋','宋诗','song-poetry','','[]','前年革履下星辰，那料如今更有春。',64,'全唐诗/poet.song.146000.json','["前年革履下星辰，那料如今更有春。", "幾爲拜雩成俯膝，可辭持酒勞燋脣。", "田家有喜新收麥，老子無何忽念蓴。", "欲去强留天意切，玉堂清夜出絲綸。"]'),
('62d27403-30ca-4213-b663-d835463851d3','壽王尚書二首  其二','項安世','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','去年曾賦泰山高，祇識君侯一味豪。',64,'全唐诗/poet.song.146000.json','["去年曾賦泰山高，祇識君侯一味豪。", "稍稍近能窺霧豹，堂堂元不掛秋毫。", "直將空洞容君輩，從使參軍似馬曹。", "此世此途荆棘久，借公餘勇爲除薅。"]'),
('a69b5195-5798-4cb0-bd36-53bb8171ffde','壽母生朝','項安世','宋','宋诗','song-poetry','','[]','油河會散恰盈旬，春水痕生又浹辰。',64,'全唐诗/poet.song.146000.json','["油河會散恰盈旬，春水痕生又浹辰。", "堂上畫圖星欲動，夜來銀燭火猶新。", "江汀花草香風滿，兒女孫曾樂事頻。", "海燕長隨生日到，是渠三島十洲人。"]'),
('e381e3d3-6acc-4b5b-9fac-3a35ef0854a2','內子生朝','項安世','宋','宋诗','song-poetry','','[]','壽杯同舉壽闈中，此樂人人羨此翁。',64,'全唐诗/poet.song.146000.json','["壽杯同舉壽闈中，此樂人人羨此翁。", "滿目芝蘭如謝傅，齊眉賓主似梁鴻。", "萬枝燈過游塵息，三莢蓂飛淑氣通。", "正是春來好時節，柳梢微綠小桃紅。"]'),
('201bef9b-b597-41e1-8476-db654e83fff1','寅子生朝寄以蜀果','項安世','宋','宋诗','song-poetry','','[]','老來夫婦喜如顛，遥舉生朝白玉船。',64,'全唐诗/poet.song.146000.json','["老來夫婦喜如顛，遥舉生朝白玉船。", "多作時文充上賦，深持僞學繼家傳。", "九年伏枕吾何恨，五子通經汝更專。", "嘉實送將知有意，且須成熟味方全。"]'),
('95add5bf-2556-43bb-8b53-bfdbecd45e86','承甫兄生朝','項安世','宋','宋诗','song-poetry','','[]','鶴雲絲雨弄春柔，鳳蠟龍薰淑氣浮。',64,'全唐诗/poet.song.146000.json','["鶴雲絲雨弄春柔，鳳蠟龍薰淑氣浮。", "頌柏盃盤連月尾，夢蘭時節占年頭。", "吹開郗桂千花上，歛退堯蓂一莢留。", "好箇龍飛新榜首，萬人齊指最風流。"]'),
('cbab10f5-df7e-4097-8fc1-8631cf3dcf70','又代作','項安世','宋','宋诗','song-poetry','','[]','新年輪遍列星名，却到龍頭第一星。',64,'全唐诗/poet.song.146000.json','["新年輪遍列星名，却到龍頭第一星。", "夢澤東風吹麗曲，錦江春浪漲芳醽。", "月鸞雲鳳揮才藻，日鶴天龜與壽齡。", "此會明年應更好，長安花裏醉還醒。"]'),
('0de7f6bb-4785-41f7-a2e3-bb43a60c1f32','壽司馬夫人二首  其一','項安世','宋','宋诗','song-poetry','','[]','起居大國太夫人，玉带金魚兩相門。',64,'全唐诗/poet.song.146000.json','["起居大國太夫人，玉带金魚兩相門。", "歲有萬千宜壽母，人生七十見重孫。", "古來此事猶稀有，帝所如今亦預恩。", "應是前宵度河漢，獨乘飛馭下崑崙。"]'),
('5c1caf91-79d0-49c3-8494-c37f26a17883','壽司馬夫人二首  其二','項安世','宋','宋诗','song-poetry','','[]','秋風庭院忽生春，請說庭前祝壽人。',64,'全唐诗/poet.song.146000.json','["秋風庭院忽生春，請說庭前祝壽人。", "卿月已昇仙掌露，郎星初見宰官身。", "九霞醖就金尊滿，四世孫看玉砌新。", "待得蓬萊更清淺，人間誰復數靈椿。"]'),
('0dc82cb1-77aa-4bc3-90f3-19e5130800f2','挽利路章運詩二首  其一','項安世','宋','宋诗','song-poetry','','[]','疇昔吾鄉主簿君，今年丹旐過江潯。',64,'全唐诗/poet.song.146000.json','["疇昔吾鄉主簿君，今年丹旐過江潯。", "老僧尚記辭葅笋，舊吏猶聞却顧金。", "玉節朱輪行萬里，清冰寒露炯初心。", "南風軋軋鳴歸樐，似相蒿城薤管音。"]'),
('d7e8a87c-1d8b-4ea5-b6ac-cb4a4e66037d','挽利路章運詩二首  其二','項安世','宋','宋诗','song-poetry','','[]','寶屏峰上兩先生，照見廉貪立懦情。',64,'全唐诗/poet.song.146000.json','["寶屏峰上兩先生，照見廉貪立懦情。", "八百萬錢同弃屣，四麾一節但空籝。", "掃除身世朝和暮，分付兒孫白與清。", "持此橫山原畔去，少師秦國有餘榮。"]'),
('11cddff7-b76f-4338-b0d1-4effa2528253','黄均州挽詞  其一','項安世','宋','宋诗','song-poetry','','[]','孤童崛起世希有，二子成名人所難。',64,'全唐诗/poet.song.146000.json','["孤童崛起世希有，二子成名人所難。", "終始兩無堪恨處，東西常大所居官。", "諸方老宿俱參遍，蓋世功名忽夢殘。", "愛我平生呼畏友，負公無路送行棺。"]'),
('487a7957-3393-40f8-b7aa-a3b3489f9920','黄均州挽詞  其二','項安世','宋','宋诗','song-poetry','','[]','乾道淳熙首尾年，相從江漢麗譙邊。',64,'全唐诗/poet.song.146000.json','["乾道淳熙首尾年，相從江漢麗譙邊。", "主方壯歲才衝斗，客亦兒時氣刺天。", "故舊彫零真老矣，城門重到輒潸然。", "最憐襄郢徘徊日，爲我經旬治畫船。"]'),
('7f5eccc5-4c19-46b2-a6a7-8885c4526bb6','次韻李校書雨中至四聖觀三絕句  其一','項安世','宋','宋诗','song-poetry','','[]','今日真仙宅，當年處士家。',24,'全唐诗/poet.song.146000.json','["今日真仙宅，當年處士家。", "江梅疎影盡，無數海棠花。"]'),
('aad8f4c4-df25-45fd-9bb5-f3b35498d54e','次韻李校書雨中至四聖觀三絕句  其二','項安世','宋','宋诗','song-poetry','','[]','花片洒行廊，苔痕上赭牆。',24,'全唐诗/poet.song.146000.json','["花片洒行廊，苔痕上赭牆。", "阜陵游幸處，花草亦悲凉。"]'),
('00f645a2-7dd3-4e4d-bda4-22a12689cbfe','次韻李校書雨中至四聖觀三絕句  其三','項安世','宋','宋诗','song-poetry','','[]','積雨全迷路，皇天不做春。',24,'全唐诗/poet.song.146000.json','["積雨全迷路，皇天不做春。", "提壺休勸客，城外有饑人。"]'),
('285bf6dd-8548-4064-8838-abec32014506','白鹿洞書堂','項安世','宋','宋诗','song-poetry','','[]','山人居白鹿，書洞有遺跡。',24,'全唐诗/poet.song.146000.json','["山人居白鹿，書洞有遺跡。", "爲世作星鳳，真堪慰泉石。"]'),
('227b2e65-b19c-41bb-b73f-0e8e79a344f4','李中主書堂','項安世','宋','宋诗','song-poetry','','[]','楞伽有公擇，娣弟如班宗。',24,'全唐诗/poet.song.146000.json','["楞伽有公擇，娣弟如班宗。", "宜州黄宅相，餘韻更舂容。"]'),
('3595089e-3303-4367-9a4b-4e3b0b38056b','歐陽拾遺讀書堂  其一','項安世','宋','宋诗','song-poetry','','[]','嗟余嗜前訓，蚤歲得明模。',24,'全唐诗/poet.song.146000.json','["嗟余嗜前訓，蚤歲得明模。", "中年困離索，舊學日荒蕪。"]'),
('ea15d3de-6a06-4fb9-b801-0d0e54c1c748','歐陽拾遺讀書堂  其二','項安世','宋','宋诗','song-poetry','','[]','茲行覽得失，撫己動兢愧。',24,'全唐诗/poet.song.146000.json','["茲行覽得失，撫己動兢愧。", "暮景尚可鞭，毋使寸陰棄。"]'),
('26adf4e6-fa25-4174-a808-278a2c20f4e5','失題','項安世','宋','宋诗','song-poetry','','[]','日暮歌碧雲，天寒思脩竹。',24,'全唐诗/poet.song.146000.json','["日暮歌碧雲，天寒思脩竹。", "佳人不可見，景入山更綠。"]'),
('ce7b7f1e-6a66-4889-a2b0-d845e34caecd','憶田間事','項安世','宋','宋诗','song-poetry','','[]','小蓋行障日，枯筇立倚風。',24,'全唐诗/poet.song.146000.json','["小蓋行障日，枯筇立倚風。", "入田催種稻，行圃看澆葱。"]'),
('5cdf99ee-8ca2-41d3-ab78-934fffd6049b','水宿','項安世','宋','宋诗','song-poetry','','[]','水納乾坤凈，窗通左右凉。',24,'全唐诗/poet.song.146000.json','["水納乾坤凈，窗通左右凉。", "船門如引索，直面看波光。"]'),
('43820bac-9063-4eed-8d53-19aa42c452ec','鐵笛亭','項安世','宋','宋诗','song-poetry','','[]','夜嘯千崖裂，朝吟萬象蘇。',24,'全唐诗/poet.song.146000.json','["夜嘯千崖裂，朝吟萬象蘇。", "山人大自在，無淚捋君鬚。"]'),
('d04a73a9-92ba-4d64-b18f-09330048b9ba','仁智堂','項安世','宋','宋诗','song-poetry','','[]','堂前九折溪，堂後百仞屏。',24,'全唐诗/poet.song.146000.json','["堂前九折溪，堂後百仞屏。", "客來問仁智，相與坐中庭。"]'),
('b3ca1919-407c-4274-93bd-43dc0b34614a','隠求齋','項安世','宋','宋诗','song-poetry','','[]','種桑不撩寒，蒔粟長苦饑。',24,'全唐诗/poet.song.146000.json','["種桑不撩寒，蒔粟長苦饑。", "饑寒從古有，但使願無違。"]'),
('3cfabe13-c83f-4f5f-9d63-f750b2a02344','觀善齋','項安世','宋','宋诗','song-poetry','','[]','切切松上風，齒齒泉下石。',24,'全唐诗/poet.song.146000.json','["切切松上風，齒齒泉下石。", "零露曉沾衣，童山夜升液。"]'),
('83b99302-406d-4448-a670-cb6b20d4fa0c','張文獻公讀書堂','項安世','宋','宋诗','song-poetry','','[]','謫仙讀書處，零落依長松。',24,'全唐诗/poet.song.146000.json','["謫仙讀書處，零落依長松。", "世人皆欲殺，頭白想飄蓬。"]'),
('7eab9fb7-43af-479c-8210-985c1f40dc27','記夢','項安世','宋','宋诗','song-poetry','','[]','共客談風雅，花邊或水邊。',24,'全唐诗/poet.song.146000.json','["共客談風雅，花邊或水邊。", "胸中無一事，夢裏亦欣然。"]'),
('16261009-b24a-40d9-a92a-7a54c1dd6ce6','茶竈','項安世','宋','宋诗','song-poetry','','[]','灧澦亦有堆，黄河豈無柱。',24,'全唐诗/poet.song.146000.json','["灧澦亦有堆，黄河豈無柱。", "借問覆舟人，何如喫茶處。"]'),
('7532d3fe-aedf-49bc-9477-cbcf105c6fb0','有感','項安世','宋','宋诗','song-poetry','','[]','船頭一摇槳，船尾萬波隨。',24,'全唐诗/poet.song.146000.json','["船頭一摇槳，船尾萬波隨。", "聞道山中樂，無人盡日維。"]'),
('4d73d52a-a4f6-4506-8626-36e10cd41860','觀潮','項安世','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','張王偏宜月，雄豪更得秋。',24,'全唐诗/poet.song.146000.json','["張王偏宜月，雄豪更得秋。", "岸頭渾破膽，浪裏有行舟。"]'),
('21b3cc18-60d5-4133-b8b1-d6eb1b18ce1e','聽雨','項安世','宋','宋诗','song-poetry','','[]','幸自蓬窗好，儂家企脚眠。',24,'全唐诗/poet.song.146000.json','["幸自蓬窗好，儂家企脚眠。", "雨聲無頼得，相喚著愁邊。"]'),
('6a04cf70-6c27-4c81-8325-9ba976ae0818','觀穫','項安世','宋','宋诗','song-poetry','','[]','晚艇村村載，秋原處處收。',24,'全唐诗/poet.song.146000.json','["晚艇村村載，秋原處處收。", "年來尤愛此，一熟緩千憂。"]'),
('348f71c7-b6d0-4fb1-b62c-fc276d835736','思歸二絕句  其一','項安世','宋','宋诗','song-poetry','','[]','永日消金鴨，暄風汎寶鸞。',24,'全唐诗/poet.song.146000.json','["永日消金鴨，暄風汎寶鸞。", "自從歸意動，無復夢魂安。"]'),
('5a10e514-2dd8-49bf-b5b4-fd7f394c91b6','思歸二絕句  其二','項安世','宋','宋诗','song-poetry','','[]','艾葉翻翻白，榴花疊疊紅。',24,'全唐诗/poet.song.146000.json','["艾葉翻翻白，榴花疊疊紅。", "年華驚客枕，心事逐郵筒。"]'),
('e0fb0368-4093-45c3-9ad5-241dcee35071','二十二日山行','項安世','宋','宋诗','song-poetry','','[]','秋日更山行，朝朝入畫屏。',24,'全唐诗/poet.song.146000.json','["秋日更山行，朝朝入畫屏。", "雨看如水墨，晴喚似丹青。"]'),
('a4a6c128-960e-4314-8fe3-a479e9fc4bd5','釣磯','項安世','宋','宋诗','song-poetry','','[]','水深石可竈，水淺石可磯。',24,'全唐诗/poet.song.146000.json','["水深石可竈，水淺石可磯。", "多謝山中石，與翁不相違。"]'),
('10f59132-e99e-48be-8f1f-b31a54501816','次韻潘都幹菊花六首  其一','項安世','宋','宋诗','song-poetry','','[]','花草春時迹遠，風霜急處心夷。',28,'全唐诗/poet.song.146000.json','["花草春時迹遠，風霜急處心夷。", "生怕枕幃收去，粉香脂氣薰肌。"]'),
('60199e1f-1d2a-43b0-9d6e-89e8dcc16e16','次韻潘都幹菊花六首  其二','項安世','宋','宋诗','song-poetry','','[]','長恨獨醒無頼，和英餐向馮夷。',28,'全唐诗/poet.song.146000.json','["長恨獨醒無頼，和英餐向馮夷。", "我自浮沈酒裏，鵝黄薰透香肌。"]'),
('c22bc37a-74df-4baf-90b9-ab4dc5d3cdda','次韻潘都幹菊花六首  其三','項安世','宋','宋诗','song-poetry','','[]','霜神亦有丰韻，未可尋常等夷。',28,'全唐诗/poet.song.146000.json','["霜神亦有丰韻，未可尋常等夷。", "赤盡江頭楓葉，却能徧護花肌。"]'),
('f6d1f544-b50d-448b-89d6-b55221a6ab3c','次韻潘都幹菊花六首  其四','項安世','宋','宋诗','song-poetry','','[]','食杞何須慕陸，采薇未用誇夷。',28,'全唐诗/poet.song.146000.json','["食杞何須慕陸，采薇未用誇夷。", "別有寒潭秋蘂，能留鶴髮松肌。"]'),
('eb251998-e221-4390-b989-aa0a9561e0da','次韻潘都幹菊花六首  其五','項安世','宋','宋诗','song-poetry','','[]','暖風和日花時，不共人爭醜夷。',28,'全唐诗/poet.song.146000.json','["暖風和日花時，不共人爭醜夷。", "自愛霜深月冷，纍纍金粟生肌。"]'),
('a18bed0e-0001-4477-b3fc-a2de3793eb70','次韻潘都幹菊花六首  其六','項安世','宋','宋诗','song-poetry','','[]','斷無羅綺追隨，政要兒曹鄙夷。',28,'全唐诗/poet.song.146000.json','["斷無羅綺追隨，政要兒曹鄙夷。", "千古一人知己，重陽無酒溫肌。"]'),
('05c05871-e236-4bce-9898-f4f0ee80f9d4','再次韻菊花譜系四首  其一','項安世','宋','宋诗','song-poetry','','[]','人道花生絕域，此花或系西夷。',28,'全唐诗/poet.song.146000.json','["人道花生絕域，此花或系西夷。", "薝蔔林中妙馥，金光明裏真肌。"]'),
('c9d4b1b9-722f-4189-b019-1f5dd60fdef5','再次韻菊花譜系四首  其二','項安世','宋','宋诗','song-poetry','','[]','若使荆公作譜，却須派出東夷。',28,'全唐诗/poet.song.146000.json','["若使荆公作譜，却須派出東夷。", "補落伽山傳種，閻浮檀水成肌。"]'),
('9a71bf38-fdc9-49ae-b5c3-65a3e1e7ecdf','再次韻菊花譜系四首  其三','項安世','宋','宋诗','song-poetry','','[]','欲喚群仙指定，衣裝似學希夷。',28,'全唐诗/poet.song.146000.json','["欲喚群仙指定，衣裝似學希夷。", "金母爲塗嬌暈，黄姑與鍊仙肌。"]'),
('5437c9a0-1db9-48d7-ba2a-d812874604f0','再次韻菊花譜系四首  其四','項安世','宋','宋诗','song-poetry','','[]','我欲詢之元亮，但言前路威夷。',28,'全唐诗/poet.song.146000.json','["我欲詢之元亮，但言前路威夷。", "且約黄花共醉，門前塵土侵肌。"]'),
('8186f99b-273e-49c8-beb7-2f8b34a94630','用韻送夔帥何侍郎以待制奉祠東歸  其一','項安世','宋','宋诗','song-poetry','','[]','瀼水橫通江水，巴山直下巫山。',28,'全唐诗/poet.song.146000.json','["瀼水橫通江水，巴山直下巫山。", "山水光中坐嘯，猶嫌不似鷗閒。"]'),
('e0a9f7e0-4ee9-468a-9969-92350117f81a','用韻送夔帥何侍郎以待制奉祠東歸  其二','項安世','宋','宋诗','song-poetry','','[]','薌火周王壽考，松階舜目聰明。',28,'全唐诗/poet.song.146000.json','["薌火周王壽考，松階舜目聰明。", "願足不求餘地，夢回何處生兵。"]'),
('2cf9d18e-94d7-45d9-9dd8-4de64bddb8ef','用韻送夔帥何侍郎以待制奉祠東歸  其三','項安世','宋','宋诗','song-poetry','','[]','種竹看成耆舊，栽花養就雲來。',28,'全唐诗/poet.song.146000.json','["種竹看成耆舊，栽花養就雲來。", "偶被東屯喚出，却遭浮白呼回。"]'),
('2d2eb4d9-71c2-46f7-bea0-9d8f3d61621e','用韻送夔帥何侍郎以待制奉祠東歸  其四','項安世','宋','宋诗','song-poetry','','[]','萬念頭頭灰冷，三田日日春妍。',28,'全唐诗/poet.song.146000.json','["萬念頭頭灰冷，三田日日春妍。", "曉起珠巖漱瀑，夜深玉海升烟。"]'),
('3d6a41ed-6242-4c98-beec-5fd7ffc37198','用韻送夔帥何侍郎以待制奉祠東歸  其五','項安世','宋','宋诗','song-poetry','','[]','晉國心存綠野，萊公夢著橫舟。',28,'全唐诗/poet.song.146000.json','["晉國心存綠野，萊公夢著橫舟。", "可奈紫宸墀下，春風催嘂班頭。"]'),
('0196d679-1102-4f42-bfae-2c68ae9b9a87','三日游澹巖火星巖朝陽巖','項安世','宋','宋诗','song-poetry','','[]','一日三巖可了，半生兩脚初來。',28,'全唐诗/poet.song.146000.json','["一日三巖可了，半生兩脚初來。", "不怕天公雨澀，青鞋飛上崔嵬。"]'),
('5462c5bd-77ad-48bb-b26f-9bda261cf3be','次韻和王少清春遊','項安世','宋','宋诗','song-poetry','','[]','自笑年來多病，一春辜負嬉遊。',28,'全唐诗/poet.song.146000.json','["自笑年來多病，一春辜負嬉遊。", "造物故禁雙眼，東風爲惜纏頭。"]'),
('aae49564-bda3-4a7b-9844-8f03503981ac','寄羅機宜竟陵督捕六首  其一','項安世','宋','宋诗','song-poetry','','[]','颭颭旌旗出郭，轟轟雷電奔空。',28,'全唐诗/poet.song.146000.json','["颭颭旌旗出郭，轟轟雷電奔空。", "一夜楚江風雨，千岩萬壑流通。"]'),
('2b2038ed-8c46-4657-9a31-da4504c54ef2','寄羅機宜竟陵督捕六首  其二','項安世','宋','宋诗','song-poetry','','[]','共是天家赤子，可憐地上游魂。',28,'全唐诗/poet.song.146000.json','["共是天家赤子，可憐地上游魂。", "去草固嫌滋蔓，遏流須藉澄冰。"]'),
('71f0d045-d080-4695-b93a-e03ad3df3c2b','寄羅機宜竟陵督捕六首  其三','項安世','宋','宋诗','song-poetry','','[]','萬仞山根螻蟻，千車轍底螳蜋。',28,'全唐诗/poet.song.146000.json','["萬仞山根螻蟻，千車轍底螳蜋。", "不怕麷蕡嬰刃，只憂玉石焚岡。"]'),
('a55b4f9e-8bf0-4a14-adb5-0bc153c0ef4a','寄羅機宜竟陵督捕六首  其四','項安世','宋','宋诗','song-poetry','','[]','只合笑談油幕，亦煩親擁琱戈。',28,'全唐诗/poet.song.146000.json','["只合笑談油幕，亦煩親擁琱戈。", "小試異時頗牧，要觀方畧如何。"]'),
('9f50efda-5368-4041-ad31-feee4d37161a','寄羅機宜竟陵督捕六首  其五','項安世','宋','宋诗','song-poetry','','[]','好把從軍樂事，新詩細入郵筒。',28,'全唐诗/poet.song.146000.json','["好把從軍樂事，新詩細入郵筒。", "我亦平生湖海，日來頗困頭風。"]'),
('a41df7be-bf31-47e3-aae9-8daea51630bb','寄羅機宜竟陵督捕六首  其六','項安世','宋','宋诗','song-poetry','','[]','已賦陽臺行雨，還看夢澤連雲。',28,'全唐诗/poet.song.146000.json','["已賦陽臺行雨，還看夢澤連雲。", "爲問當時平土，如今多少耕耘。"]'),
('e767f55e-673d-4d5d-b055-238e4c78a2f7','偶得二首  其一','項安世','宋','宋诗','song-poetry','','[]','水邊楊柳禿𧤺沙，路上寒梅噤未花。',32,'全唐诗/poet.song.146000.json','["水邊楊柳禿𧤺沙，路上寒梅噤未花。", "欲識乾坤生物意，桑根麥子已含芽。"]'),
('a4fc9201-9474-4e54-9356-89d65b622e88','偶得二首  其二','項安世','宋','宋诗','song-poetry','','[]','雪中春到梅花覺，冰底水行人未知。',32,'全唐诗/poet.song.146000.json','["雪中春到梅花覺，冰底水行人未知。", "珍重天公好消息，通今通古更何疑。"]'),
('3db53882-b569-4520-9ad0-342c0779ebea','和趙司戶尋梅桐原菴  其一','項安世','宋','宋诗','song-poetry','','[]','王孫寶馬七香車，不似吟鞭跨蹇馿。',32,'全唐诗/poet.song.146000.json','["王孫寶馬七香車，不似吟鞭跨蹇馿。", "少待綠陰青子下，與君扶杖轉鳴渠。"]'),
('ffb77eb4-9f9f-4055-9171-934179cd2db6','和趙司戶尋梅桐原菴  其二','項安世','宋','宋诗','song-poetry','','[]','桐原花下不容車，茅壓疎簷竹繞閭。',32,'全唐诗/poet.song.146000.json','["桐原花下不容車，茅壓疎簷竹繞閭。", "可慣傳呼青影裏，人聲浩浩屋渠渠。"]'),
('4793941a-33c9-474a-a8bf-151e65914515','東齋','項安世','宋','宋诗','song-poetry','','[]','桃花不解言前事，菊蕊還須記舊人。',32,'全唐诗/poet.song.146000.json','["桃花不解言前事，菊蕊還須記舊人。", "惟有軒前舊移竹，向人憔悴似相嗔。"]'),
('cca764b3-0221-4e5f-a932-405918141fef','松陽南巖夜歸','項安世','宋','宋诗','song-poetry','','[]','走下南巖踏黑歸，蒼林擁逕白光微。',32,'全唐诗/poet.song.146000.json','["走下南巖踏黑歸，蒼林擁逕白光微。", "馬湖橋上消摇甚，飛度前村露滿衣。"]'),
('9b1d4900-7bde-4ead-9591-a121d4a74f8c','二十四日看山','項安世','宋','宋诗','song-poetry','','[]','日日憑輿看遠山，不知行處是峯巒。',32,'全唐诗/poet.song.146000.json','["日日憑輿看遠山，不知行處是峯巒。", "他山亦有癡人看，却向儂家行處看。"]'),
('38d09400-2fa4-4977-ba93-8651affc6b42','釣臺  其一','項安世','宋','宋诗','song-poetry','','[]','數仞山頭一小亭，只消此地過平生。',32,'全唐诗/poet.song.146000.json','["數仞山頭一小亭，只消此地過平生。", "崎嶇狹世纔伸脚，已被劉郎賣作名。"]'),
('c796f454-bb05-4100-b7c7-cafa26c4724c','釣臺  其二','項安世','宋','宋诗','song-poetry','','[]','君房足下竟成諛，只是韓歆已破除。',32,'全唐诗/poet.song.146000.json','["君房足下竟成諛，只是韓歆已破除。", "豈有江湖釣竿手，爲君臺閣奉文書。"]'),
('89e1b768-eb25-4384-9626-36747ed4f6e4','秋懷  其一','項安世','宋','宋诗','song-poetry','','[]','有營何日得無悲，無欲無時不自宜。',32,'全唐诗/poet.song.146000.json','["有營何日得無悲，無欲無時不自宜。", "竹影一窗泉一曲，山齋非是愛吟詩。"]'),
('3faf106a-e028-4539-9946-a8cf90694879','秋懷  其二','項安世','宋','宋诗','song-poetry','','[]','秋水迢迢詩思清，秋陽杲杲道心明。',32,'全唐诗/poet.song.146000.json','["秋水迢迢詩思清，秋陽杲杲道心明。", "誰人得似秋光巧，畫出山齋杖屨行。"]'),
('8a124c09-e61e-4af6-b1ca-55a36957ee10','中秋無月','項安世','宋','宋诗','song-poetry','','[]','青天碧海路悠悠，兔老蟾饑亦倦遊。',32,'全唐诗/poet.song.146000.json','["青天碧海路悠悠，兔老蟾饑亦倦遊。", "鎖定玉樓雲不卷，兩街燈火作中秋。"]'),
('ea3a24ae-afd3-4555-9ddf-ea69224b2bc4','脫葉','項安世','宋','宋诗','song-poetry','','[]','綠陰時節葉急飛，投分青蕪更不疑。',32,'全唐诗/poet.song.146000.json','["綠陰時節葉急飛，投分青蕪更不疑。", "橫被蛛絲禁得住，舞風一片獨多時。"]'),
('a16920b9-d62b-4509-83da-015f5066f8dd','富陽道中二首  其一','項安世','宋','宋诗','song-poetry','','[]','雲破天開雪欲晴，櫓聲爭出滿江鳴。',32,'全唐诗/poet.song.146000.json','["雲破天開雪欲晴，櫓聲爭出滿江鳴。", "牽繩直上高崖去，想見瞿塘百丈行。"]'),
('6a18c078-4e16-44fd-9797-1ed86f7eaf31','富陽道中二首  其二','項安世','宋','宋诗','song-poetry','','[]','一带江流兩岸山，玉花珠髻滿雲鬟。',32,'全唐诗/poet.song.146000.json','["一带江流兩岸山，玉花珠髻滿雲鬟。", "一聲鳴櫓俱回首，小杜舟中醉眼看。"]');
